const book: BibleBook = {
  id: 'joshua',
  name: 'Josué',
  englishName: 'Joshua',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'Now after the death of Moses the servant of Yahweh, Yahweh spoke to Joshua the son of Nun, Moses’ servant, saying,', pt: 'Depois da morte de Moisés, servo do Senhor, falou o Senhor a Josué, filho de Num, servidor de Moisés, dizendo:' },
      { v: 2, en: '“Moses my servant is dead. Now therefore arise, go across this Jordan, you, and all these people, to the land which I am giving to them, even to the children of Israel.', pt: 'Moisés, meu servo, é morto; levanta-te pois agora, passa este Jordão, tu e todo este povo, para a terra que eu dou aos filhos de Israel.' },
      { v: 3, en: 'I have given you every place that the sole of your foot will tread on, as I told Moses.', pt: 'Todo lugar que pisar a planta do vosso pé, vo-lo dei, como eu disse a Moisés.' },
      { v: 4, en: 'From the wilderness, and this Lebanon, even to the great river, the river Euphrates, all the land of the Hittites, and to the great sea toward the going down of the sun, shall be your border.', pt: 'Desde o deserto e este Líbano, até o grande rio, o rio Eufrates, toda a terra dos heteus, e até o grande mar para o poente do sol, será o vosso termo.' },
      { v: 5, en: 'No man will be able to stand before you all the days of your life. As I was with Moses, so I will be with you. I will not fail you nor forsake you.', pt: 'Ninguém te poderá resistir todos os dias da tua vida. Como fui com Moisés, assim serei contigo; não te deixarei, nem te desampararei.' },
      { v: 6, en: '“Be strong and courageous; for you shall cause this people to inherit the land which I swore to their fathers to give them.', pt: 'Esforça-te, e tem bom ânimo, porque tu farás a este povo herdar a terra que jurei a seus pais lhes daria.' },
      { v: 7, en: 'Only be strong and very courageous. Be careful to observe to do according to all the law, which Moses my servant commanded you. Don’t turn from it to the right hand or to the left, that you may have good success wherever you go.', pt: 'Tão-somente esforça-te e tem mui bom ânimo, cuidando de fazer conforme toda a lei que meu servo Moisés te ordenou; não te desvies dela, nem para a direita nem para a esquerda, a fim de que sejas bem sucedido por onde quer que andares.' },
      { v: 8, en: 'This book of the law shall not depart from your mouth, but you shall meditate on it day and night, that you may observe to do according to all that is written in it; for then you shall make your way prosperous, and then you shall have good success.', pt: 'Não se aparte da tua boca o livro desta lei, antes medita nele dia e noite, para que tenhas cuidado de fazer conforme tudo quanto nele está escrito; porque então farás prosperar o teu caminho, e serás bem sucedido.' },
      { v: 9, en: 'Haven’t I commanded you? Be strong and courageous. Don’t be afraid. Don’t be dismayed, for Yahweh your God is with you wherever you go.”', pt: 'Não to mandei eu? Esforça-te, e tem bom ânimo; não te atemorizes, nem te espantes; porque o Senhor teu Deus está contigo, por onde quer que andares.' },
      { v: 10, en: 'Then Joshua commanded the officers of the people, saying,', pt: 'Então Josué deu esta ordem aos oficiais do povo:' },
      { v: 11, en: '“Pass through the middle of the camp, and command the people, saying, ‘Prepare food; for within three days you are to pass over this Jordan, to go in to possess the land, which Yahweh your God gives you to possess it.’”', pt: 'Passai pelo meio do arraial, e ordenai ao povo, dizendo: Provede-vos de mantimentos, porque dentro de três dias haveis de atravessar este Jordão, a fim de que entreis para tomar posse da terra que o Senhor vosso Deus vos dá para a possuirdes.' },
      { v: 12, en: 'Joshua spoke to the Reubenites, and to the Gadites, and to the half-tribe of Manasseh, saying,', pt: 'E disse Josué aos rubenitas, aos gaditas, e à meia tribo de Manassés:' },
      { v: 13, en: '“Remember the word which Moses the servant of Yahweh commanded you, saying, ‘Yahweh your God gives you rest, and will give you this land.', pt: 'Lembrai-vos da palavra que vos mandou Moisés, servo do Senhor, dizendo: O Senhor vosso Deus vos dá descanso, e vos dá esta terra.' },
      { v: 14, en: 'Your wives, your little ones, and your livestock, shall live in the land which Moses gave you beyond the Jordan; but you shall pass over before your brothers armed, all the mighty men of valor, and shall help them', pt: 'Vossas mulheres, vossos pequeninos e vosso gado fiquem na terra que Moisés vos deu desta banda do Jordão; porém vós, todos os homens valorosos, passareis armados adiante de vossos irmãos e os ajudareis;' },
      { v: 15, en: 'until Yahweh has given your brothers rest, as he has given you, and they have also possessed the land which Yahweh your God gives them. Then you shall return to the land of your possession, and possess it, which Moses the servant of Yahweh gave you beyond the Jordan toward the sunrise.’”', pt: 'até que o Senhor tenha dado descanso: a vossos irmãos, assim como vo-lo deu a vós, e eles também tenham possuído a terra que o Senhor vosso Deus lhes dá; então tornareis para a terra da vossa herança, e a possuireis, terra que Moisés, servo do Senhor, vos deu além do Jordão, para o nascente do sol.' },
      { v: 16, en: 'They answered Joshua, saying, “All that you have commanded us we will do, and wherever you send us we will go.', pt: 'Então responderam a Josué, dizendo: Tudo quanto nos ordenaste faremos, e aonde quer que nos enviares iremos.' },
      { v: 17, en: 'Just as we listened to Moses in all things, so will we listen to you. Only may Yahweh your God be with you, as he was with Moses.', pt: 'Como em tudo ouvimos a Moisés, assim te ouviremos a ti; tão-somente seja o Senhor teu Deus contigo, como foi com Moisés.' },
      { v: 18, en: 'Whoever rebels against your commandment, and doesn’t listen to your words in all that you command him shall himself be put to death. Only be strong and courageous.”', pt: 'Quem quer que se rebelar contra as tuas ordens, e não ouvir as tuas palavras em tudo quanto lhe mandares, será morto. Tão-somente esforça-te, e tem bom ânimo.' },
    ],
    2: [
      { v: 1, en: 'Joshua the son of Nun secretly sent two men out of Shittim as spies, saying, “Go, view the land, including Jericho.” They went and came into the house of a prostitute whose name was Rahab, and slept there.', pt: 'De Sitim Josué, filho de Num, enviou secretamente dois homens como espias, dizendo-lhes: Ide reconhecer a terra, particularmente a Jericó. Foram pois, e entraram na casa duma prostituta, que se chamava Raabe, e pousaram ali.' },
      { v: 2, en: 'The king of Jericho was told, “Behold, men of the children of Israel came in here tonight to spy out the land.”', pt: 'Então deu-se notícia ao rei de Jericó, dizendo: Eis que esta noite vieram aqui uns homens dos filhos de Israel, para espiar a terra.' },
      { v: 3, en: 'Jericho’s king sent to Rahab, saying, “Bring out the men who have come to you, who have entered into your house; for they have come to spy out all the land.”', pt: 'Pelo que o rei de Jericó mandou dizer a Raabe: Faze sair os homens que vieram a ti e entraram na tua casa, porque vieram espiar toda a terra.' },
      { v: 4, en: 'The woman took the two men and hid them. Then she said, “Yes, the men came to me, but I didn’t know where they came from.', pt: 'Mas aquela mulher, tomando os dois homens, os escondeu, e disse: é verdade que os homens vieram a mim, porém eu não sabia donde eram;' },
      { v: 5, en: 'About the time of the shutting of the gate, when it was dark, the men went out. Where the men went, I don’t know. Pursue them quickly. You may catch up with them.”', pt: 'e aconteceu que, havendo-se de fechar a porta, sendo já escuro, aqueles homens saíram. Não sei para onde foram; ide após eles depressa, porque os alcançareis.' },
      { v: 6, en: 'But she had brought them up to the roof, and hidden them under the stalks of flax which she had laid in order on the roof.', pt: 'Ela, porém, os tinha feito subir ao eirado, e os tinha escondido entre as canas do linho que pusera em ordem sobre o eirado.' },
      { v: 7, en: 'The men pursued them along the way to the fords of the Jordan River. As soon as those who pursued them had gone out, they shut the gate.', pt: 'Assim foram esses homens após eles pelo caminho do Jordão, até os vaus; e, logo que saíram, fechou-se a porta.' },
      { v: 8, en: 'Before they had lain down, she came up to them on the roof.', pt: 'E, antes que os espias se deitassem, ela subiu ao eirado a ter com eles,' },
      { v: 9, en: 'She said to the men, “I know that Yahweh has given you the land, and that the fear of you has fallen upon us, and that all the inhabitants of the land melt away before you.', pt: 'e disse-lhes: Bem sei que o Senhor vos deu esta terra, e que o pavor de vós caiu sobre nós, e que todos os moradores da terra se derretem diante de vós.' },
      { v: 10, en: 'For we have heard how Yahweh dried up the water of the Red Sea before you, when you came out of Egypt; and what you did to the two kings of the Amorites, who were beyond the Jordan, to Sihon and to Og, whom you utterly destroyed.', pt: 'Porque temos ouvido que o Senhor secou as águas do Mar Vermelho diante de vós, quando saístes do Egito, e também o que fizestes aos dois reis dos amorreus, Siom e Ogue, que estavam além de Jordão, os quais destruístes totalmente.' },
      { v: 11, en: 'As soon as we had heard it, our hearts melted, and there wasn’t any more spirit in any man, because of you: for Yahweh your God, he is God in heaven above, and on earth beneath.', pt: 'Quando ouvimos isso, derreteram-se os nossos corações, e em ninguém mais há ânimo algum, por causa da vossa presença; porque o Senhor vosso Deus é Deus em cima no céu e embaixo na terra.' },
      { v: 12, en: 'Now therefore, please swear to me by Yahweh, since I have dealt kindly with you, that you also will deal kindly with my father’s house, and give me a true sign;', pt: 'Agora pois, peço-vos, jurai-me pelo Senhor que, como usei de bondade para convosco, vós também usareis de bondade para com a casa e meu pai; e dai-me um sinal seguro' },
      { v: 13, en: 'and that you will save alive my father, my mother, my brothers, and my sisters, and all that they have, and will deliver our lives from death.”', pt: 'de que conservareis em vida meu pai e minha mãe, como também meus irmãos e minhas irmãs, com todos os que lhes pertencem, e de que livrareis da morte as nossas vidas.' },
      { v: 14, en: 'The men said to her, “Our life for yours, if you don’t talk about this business of ours; and it shall be, when Yahweh gives us the land, that we will deal kindly and truly with you.”', pt: 'Então eles lhe responderam: A nossa vida responderá pela vossa, se não denunciardes este nosso negócio; e, quando o Senhor nos entregar esta terra, usaremos para contigo de bondade e de fidelidade.' },
      { v: 15, en: 'Then she let them down by a cord through the window; for her house was on the side of the wall, and she lived on the wall.', pt: 'Ela então os fez descer por uma corda pela janela, porquanto a sua casa estava sobre o muro da cidade, de sorte que morava sobre o muro;' },
      { v: 16, en: 'She said to them, “Go to the mountain, lest the pursuers find you. Hide yourselves there three days, until the pursuers have returned. Afterward, you may go your way.”', pt: 'e disse-lhes: Ide-vos ao monte, para que não vos encontrem os perseguidores, e escondei-vos lá três dias, até que eles voltem; depois podereis tomar o vosso caminho.' },
      { v: 17, en: 'The men said to her, “We will be guiltless of this your oath which you’ve made us to swear.', pt: 'Disseram-lhe os homens: Nós seremos inocentes no tocante a este juramento que nos fizeste jurar.' },
      { v: 18, en: 'Behold, when we come into the land, tie this line of scarlet thread in the window which you used to let us down. Gather to yourself into the house your father, your mother, your brothers, and all your father’s household.', pt: 'Eis que, quando nós entrarmos na terra, atarás este cordão de fio de escarlata à janela pela qual nos fizeste descer; e recolherás em casa contigo teu pai, tua mãe, teus irmãos e toda a família de teu pai.' },
      { v: 19, en: 'It shall be that whoever goes out of the doors of your house into the street, his blood will be on his head, and we will be guiltless. Whoever is with you in the house, his blood shall be on our head, if any hand is on him.', pt: 'Qualquer que sair fora das portas da tua casa, o seu sangue cairá sobre a sua cabeça, e nós seremos inocentes; mas qualquer que estiver contigo em casa, o seu sangue cairá sobre a nossa cabeça se nele se puser mão.' },
      { v: 20, en: 'But if you talk about this business of ours, then we shall be guiltless of your oath which you’ve made us to swear.”', pt: 'Se, porém, tu denunciares este nosso negócio, seremos desobrigados do juramento que nos fizeste jurar.' },
      { v: 21, en: 'She said, “Let it be as you have said.” She sent them away, and they departed. Then she tied the scarlet line in the window.', pt: 'Ao que ela disse: Conforme as vossas palavras, assim seja. Então os despediu, e eles se foram; e ela atou o cordão de escarlata à janela.' },
      { v: 22, en: 'They went, and came to the mountain, and stayed there three days, until the pursuers had returned. The pursuers sought them all along the way, but didn’t find them.', pt: 'Foram-se, pois, e chegaram ao monte, onde ficaram três dias, até que voltaram os perseguidores; pois estes os buscaram por todo o caminho, porém, não os acharam.' },
      { v: 23, en: 'Then the two men returned, descended from the mountain, crossed the river, and came to Joshua the son of Nun. They told him all that had happened to them.', pt: 'Então os dois homens, tornando a descer do monte, passaram o rio, chegaram a Josué, filho de Num, e lhe contaram tudo quanto lhes acontecera.' },
      { v: 24, en: 'They said to Joshua, “Truly Yahweh has delivered all the land into our hands. Moreover, all the inhabitants of the land melt away before us.”', pt: 'E disseram a Josué: Certamente o Senhor nos tem entregue nas mãos toda esta terra, pois todos os moradores se derretem diante de nós.' },
    ],
    3: [
      { v: 1, en: 'Joshua got up early in the morning; and they moved from Shittim, and came to the Jordan, he and all the children of Israel. They camped there before they crossed over.', pt: 'Levantou-se, pois, Josué de madrugada e, partindo de Sitim ele e todos os filhos de Israel, vieram ao Jordão; e pousaram ali, antes de atravessá-lo.' },
      { v: 2, en: 'After three days, the officers went through the middle of the camp;', pt: 'E sucedeu, ao fim de três dias, que os oficiais passaram pelo meio do arraial,' },
      { v: 3, en: 'and they commanded the people, saying, “When you see the ark of Yahweh your God’s covenant, and the priests the Levites bearing it, then leave your place, and follow it.', pt: 'e ordenaram ao povo, dizendo: Quando virdes a arca da pacto do Senhor vosso Deus sendo levada pelos levitas sacerdotes, partireis vós também do vosso lugar, e a seguireis' },
      { v: 4, en: 'Yet there shall be a space between you and it of about two thousand cubits by measure—don’t come closer to it—that you may know the way by which you must go; for you have not passed this way before.”', pt: '(haja, contudo, entre vós e ela, uma distância de dois mil côvados, e não vos chegueis a ela), para que saibais o caminho pelo qual haveis de ir, porquanto por este caminho nunca dantes passastes.' },
      { v: 5, en: 'Joshua said to the people, “Sanctify yourselves; for tomorrow Yahweh will do wonders among you.”', pt: 'Disse Josué também ae povo: Santificai-vos, porque amanhã o Senhor fará maravilhas no meio de vós.' },
      { v: 6, en: 'Joshua spoke to the priests, saying, “Take up the ark of the covenant, and cross over before the people.” They took up the ark of the covenant, and went before the people.', pt: 'E falou Josué aos sacerdotes, dizendo: Levantai a arca do pacto, e passai adiante do povo. Levantaram, pois, a arca do pacto, e foram andando adiante do povo.' },
      { v: 7, en: 'Yahweh said to Joshua, “Today I will begin to magnify you in the sight of all Israel, that they may know that as I was with Moses, so I will be with you.', pt: 'Então disse o Senhor a Josué: Hoje começarei a engrandecer- te perante os olhos de todo o Israel, para que saibam que, assim como fui com Moisés, serei contigo.' },
      { v: 8, en: 'You shall command the priests who bear the ark of the covenant, saying, ‘When you come to the brink of the waters of the Jordan, you shall stand still in the Jordan.’”', pt: 'Tu, pois, ordenarás aos sacerdotes que levam a arca do pacto, dizendo: Quando chegardes à beira das águas de Jordão, aí parareis.' },
      { v: 9, en: 'Joshua said to the children of Israel, “Come here, and hear the words of Yahweh your God.”', pt: 'Disse então Josué aos filhos de Israel: Aproximai-vos, e ouvi as palavras do Senhor vosso Deus.' },
      { v: 10, en: 'Joshua said, “By this you shall know that the living God is among you, and that he will without fail drive the Canaanite, and the Hittite, and the Hivite, and the Perizzite, and the Girgashite, and the Amorite, and the Jebusite out from before you.', pt: 'E acrescentou: Nisto conhecereis que o Deus vivo está no meio de vós, e que certamente expulsará de diante de vós os cananeus, os heteus, os heveus, os perizeus, os girgaseus, os amorreus e os jebuseus.' },
      { v: 11, en: 'Behold, the ark of the covenant of the Lord of all the earth passes over before you into the Jordan.', pt: 'Eis que a arca do pacto do Senhrr de toda a terra passará adiante de vós para o meio do Jordão.' },
      { v: 12, en: 'Now therefore take twelve men out of the tribes of Israel, for every tribe a man.', pt: 'Tomai, pois, agora doze homens das tribos de Israel, de cada tribo um homem;' },
      { v: 13, en: 'It shall be that when the soles of the feet of the priests who bear the ark of Yahweh, the Lord of all the earth, rest in the waters of the Jordan, that the waters of the Jordan will be cut off. The waters that come down from above shall stand in one heap.”', pt: 'porque assim que as plantas dos pés dos sacerdotes que levam a arca do Senhor, o Senhor de toda a terra, pousarem nas águas do Jordão, estas serão cortadas, isto é, as águas que vêm de cima, e, amontoadas, pararão.' },
      { v: 14, en: 'When the people moved from their tents to pass over the Jordan, the priests who bore the ark of the covenant being before the people,', pt: 'Quando, pois, o povo partiu das suas tendas para atravessar o Jordão, levando os sacerdotes a arca do pacto adiante do povo,' },
      { v: 15, en: 'and when those who bore the ark had come to the Jordan, and the feet of the priests who bore the ark had dipped in the edge of the water (for the Jordan overflows all its banks all the time of harvest),', pt: 'e quando os que levavam a arca chegaram ao Jordão, e os seus pés se mergulharam na beira das águas (porque o Jordão transbordava todas as suas ribanceiras durante todos os dias da sega),' },
      { v: 16, en: 'the waters which came down from above stood, and rose up in one heap, a great way off, at Adam, the city that is beside Zarethan; and those that went down toward the sea of the Arabah, even the Salt Sea, were wholly cut off. Then the people passed over near Jericho.', pt: 'as águas que vinham de cima, parando, levantaram-se num montão, mui longe, à altura de Adã, cidade que está junto a Zaretã; e as que desciam ao mar da Arabá, que é o Mar Salgado, foram de todo cortadas. Então o povo passou bem em frente de Jericó.' },
      { v: 17, en: 'The priests who bore the ark of Yahweh’s covenant stood firm on dry ground in the middle of the Jordan; and all Israel crossed over on dry ground, until all the nation had passed completely over the Jordan.', pt: 'Os sacerdotes que levavam a arca do pacto do Senhor pararam firmes em seco no meio do Jordão, e todo o Israel foi passando a pé enxuto, até que todo o povo acabou de passar o Jordão.' },
    ],
    4: [
      { v: 1, en: 'When all the nation had completely crossed over the Jordan, Yahweh spoke to Joshua, saying,', pt: 'Quando todo o povo acabara de passar o Jordão, falou o Senhor a Josué, dizendo:' },
      { v: 2, en: '“Take twelve men out of the people, a man out of every tribe,', pt: 'Tomai dentre o povo doze homens, de cada tribo um homem;' },
      { v: 3, en: 'and command them, saying, ‘Take from out of the middle of the Jordan, out of the place where the priests’ feet stood firm, twelve stones, and carry them over with you, and lay them down in the place where you’ll camp tonight.’”', pt: 'e mandai-lhes, dizendo: Tirai daqui, do meio do Jordão, do lugar em que estiveram parados os pés dos sacerdotes, doze pedras, levai-as convosco para a outra banda e depositai-as no lugar em que haveis de passar esta noite.' },
      { v: 4, en: 'Then Joshua called the twelve men, whom he had prepared of the children of Israel, a man out of every tribe.', pt: 'Chamou, pois, Josué os doze homens que escolhera dos filhos de Israel, de cada tribo um homem;' },
      { v: 5, en: 'Joshua said to them, “Cross before the ark of Yahweh your God into the middle of the Jordan, and each of you pick up a stone and put it on your shoulder, according to the number of the tribes of the children of Israel;', pt: 'e disse-lhes: Passai adiante da arca do Senhor vosso Deus, ao meio do Jordão, e cada um levante uma pedra sobre o ombro, segundo o número das tribos dos filhos de Israel;' },
      { v: 6, en: 'that this may be a sign among you, that when your children ask in the future, saying, ‘What do you mean by these stones?’', pt: 'para que isto seja por sinal entre vós; e quando vossos filhos no futuro perguntarem: Que significam estas pedras?' },
      { v: 7, en: 'then you shall tell them, ‘Because the waters of the Jordan were cut off before the ark of Yahweh’s covenant. When it crossed over the Jordan, the waters of the Jordan were cut off. These stones shall be for a memorial to the children of Israel forever.’”', pt: 'direis a eles que as águas do Jordão foram cortadas diante da arca do pacto de Senhor; quando ela passou pelo Jordão, as águas foram cortadas; e estas pedras serão para sempre por memorial aos filhos de Israel.' },
      { v: 8, en: 'The children of Israel did as Joshua commanded, and took up twelve stones out of the middle of the Jordan, as Yahweh spoke to Joshua, according to the number of the tribes of the children of Israel. They carried them over with them to the place where they camped, and laid them down there.', pt: 'Fizeram, pois, os filhos de Israel assim como Josué tinha ordenado, e levantaram doze pedras do meio do Jordão como o Senhor dissera a Josué, segundo o número das tribos dos filhos de Israel; e levaram-nas consigo ao lugar em que pousaram, e as depositaram ali.' },
      { v: 9, en: 'Joshua set up twelve stones in the middle of the Jordan, in the place where the feet of the priests who bore the ark of the covenant stood; and they are there to this day.', pt: 'Amontoou Josué também doze pedras no meio do Jordão, no lugar em que pararam os pés dos sacerdotes que levavam a arca do pacto; e ali estão até o dia de hoje.' },
      { v: 10, en: 'For the priests who bore the ark stood in the middle of the Jordan, until everything was finished that Yahweh commanded Joshua to speak to the people, according to all that Moses commanded Joshua; and the people hurried and passed over.', pt: 'Pois os sacerdotes que levavam a arca pararam no meio do Jordão, até que se cumpriu tudo quanto o Senhor mandara Josué dizer ao povo, conforme tudo o que Moisés tinha ordenado a Josué. E o povo apressou-se, e passou.' },
      { v: 11, en: 'When all the people had completely crossed over, Yahweh’s ark crossed over, with the priests, in the presence of the people.', pt: 'Assim que todo o povo acabara de passar, então passaram a arca do Senhor e os sacerdotes, à vista do povo.' },
      { v: 12, en: 'The children of Reuben, and the children of Gad, and the half-tribe of Manasseh, crossed over armed before the children of Israel, as Moses spoke to them.', pt: 'E passaram os filhos de Rúben e os filhos de Gade, e a meia tribo de Manassés, armados, adiante dos filhos de Israel, como Moisés lhes tinha dito;' },
      { v: 13, en: 'About forty thousand men, ready and armed for war passed over before Yahweh to battle, to the plains of Jericho.', pt: 'uns quarenta mil homens em pé de guerra passaram diante do Senhor para a batalha, às planícies de Jericó.' },
      { v: 14, en: 'On that day, Yahweh magnified Joshua in the sight of all Israel; and they feared him, as they feared Moses, all the days of his life.', pt: 'Naquele dia e Senhor engrandeceu a Josué aos olhos de todo o Israel; e temiam-no, como haviam temido a Moisés, por todos os dias da sua vida.' },
      { v: 15, en: 'Yahweh spoke to Joshua, saying,', pt: 'Depois falou o Senhor a Josué, dizendo:' },
      { v: 16, en: '“Command the priests who bear the ark of the testimony, that they come up out of the Jordan.”', pt: 'Dá ordem aos sacerdotes que levam a arca do testemunho, que subam do Jordão.' },
      { v: 17, en: 'Joshua therefore commanded the priests, saying, “Come up out of the Jordan!”', pt: 'Pelo que Josué deu ordem aos sacerdetes, dizendo: Subi do Jordão.' },
      { v: 18, en: 'When the priests who bore the ark of Yahweh’s covenant had come up out of the middle of the Jordan, and the soles of the priests’ feet had been lifted up to the dry ground, the waters of the Jordan returned to their place, and went over all its banks, as before.', pt: 'E aconteceu que, quando os sacerdotes que levavam a arca do pacto do Senhor subiram do meio do Jordão, e as plantas dos seus pés se puseram em terra seca, as águas do Jordão voltaram ao seu lugar, e trasbordavam todas as suas ribanceiras, como dantes.' },
      { v: 19, en: 'The people came up out of the Jordan on the tenth day of the first month, and encamped in Gilgal, on the east border of Jericho.', pt: 'O povo, pois, subiu do Jordão no dia dez do primeiro mês, e acampou-se em Gilgal, ao oriente de Jericó.' },
      { v: 20, en: 'Joshua set up those twelve stones, which they took out of the Jordan, in Gilgal.', pt: 'E as doze pedras, que tinham tirado do Jordão, levantou-as Josué em Gilgal;' },
      { v: 21, en: 'He spoke to the children of Israel, saying, “When your children ask their fathers in time to come, saying, ‘What do these stones mean?’', pt: 'e falou aos filhos de Israel, dizendo: Quando no futuro vossos filhos perguntarem a seus pais: Que significam estas pedras?' },
      { v: 22, en: 'Then you shall let your children know, saying, ‘Israel came over this Jordan on dry land.', pt: 'fareis saber a vossos filhos, dizendo: Israel passou a pé enxuto este Jordão.' },
      { v: 23, en: 'For Yahweh your God dried up the waters of the Jordan from before you, until you had crossed over, as Yahweh your God did to the Red Sea, which he dried up from before us, until we had crossed over;', pt: 'Porque o Senhor vosso Deus fez secar as águas do Jordão diante de vós, até que passásseis, assim como fizera ao Mar Vermelho, ao qual fez secar perante nós, até que passássemos;' },
      { v: 24, en: 'that all the peoples of the earth may know that Yahweh’s hand is mighty; that you may fear Yahweh your God forever.’”', pt: 'para que todos os povos da terra conheçam que a mão do Senhor é forte; a fim de que vós também temais ao Senhor vosso Deus para sempre.' },
    ],
    5: [
      { v: 1, en: 'When all the kings of the Amorites, who were beyond the Jordan westward, and all the kings of the Canaanites, who were by the sea, heard how Yahweh had dried up the waters of the Jordan from before the children of Israel, until we had crossed over, their heart melted, and there was no more spirit in them, because of the children of Israel.', pt: 'Quando, pois, todos os reis dos amorreus que estavam ao oeste do Jordão, e todos os reis dos cananeus que estavam ao lado do mar, ouviram que o Senhor tinha secado as águas do Jordão de diante dos filhos de Israel, até que passassem, derreteu-se-lhes o coração, e não houve mais ânimo neles, por causa dos filhos de Israel.' },
      { v: 2, en: 'At that time, Yahweh said to Joshua, “Make flint knives, and circumcise again the sons of Israel the second time.”', pt: 'Naquele tempo disse o Senhor a Josué: Faze facas de pederneira, e circuncida segunda vez aos filhos de Israel.' },
      { v: 3, en: 'Joshua made himself flint knives, and circumcised the sons of Israel at the hill of the foreskins.', pt: 'Então Josué fez facas de pederneira, e circuncidou aos filhos de Israel em Gibeate-Haaralote.' },
      { v: 4, en: 'This is the reason Joshua circumcised them: all the people who came out of Egypt, who were males, even all the men of war, died in the wilderness along the way, after they came out of Egypt.', pt: 'Esta é a razão por que Josué os circuncidou: todo o povo que tinha saído do Egito, os homens, todos os homens de guerra, já haviam morrido no deserto, pelo caminho, depois que saíram do Egito.' },
      { v: 5, en: 'For all the people who came out were circumcised; but all the people who were born in the wilderness along the way as they came out of Egypt had not been circumcised.', pt: 'Todos estes que saíram estavam circuncidados, mas nenhum dos que nasceram no deserto, pelo caminho, depois de terem saído do Egito, havia sido circuncidado.' },
      { v: 6, en: 'For the children of Israel walked forty years in the wilderness, until all the nation, even the men of war who came out of Egypt, were consumed, because they didn’t listen to Yahweh’s voice. Yahweh swore to them that he wouldn’t let them see the land which Yahweh swore to their fathers that he would give us, a land flowing with milk and honey.', pt: 'Pois quarenta anos andaram os filhos de Israel pelo deserto, até se acabar toda a nação, isto é, todos os homens de guerra que saíram do Egito, e isso porque não obedeceram à voz do Senhor; aos quais o Senhor tinha jurado que não lhes havia de deixar ver a terra que, com juramento, prometera a seus pais nos daria, terra que mana leite e mel.' },
      { v: 7, en: 'Their children, whom he raised up in their place, were circumcised by Joshua; for they were uncircumcised, because they had not circumcised them on the way.', pt: 'Mas em lugar deles levantou seus filhos; a estes Josué circuncidou, porquanto estavam incircuncisos, porque não os haviam circuncidado pelo caminho.' },
      { v: 8, en: 'When they were done circumcising the whole nation, they stayed in their places in the camp until they were healed.', pt: 'E depois que foram todos circuncidados, permaneceram no seu lugar no arraial, até que sararam.' },
      { v: 9, en: 'Yahweh said to Joshua, “Today I have rolled away the reproach of Egypt from you.” Therefore the name of that place was called Gilgal, to this day.', pt: 'Disse então o Senhor a Josué: Hoje revolvi de sobre vós o opróbrio do Egito; pelo que se chama aquele lugar: Gilgal, até o dia de hoje.' },
      { v: 10, en: 'The children of Israel encamped in Gilgal. They kept the Passover on the fourteenth day of the month at evening in the plains of Jericho.', pt: 'Estando, pois, os filhos de Israel acampados em Gilgal, celebraram a páscoa no dia catorze do mês, à tarde, nas planícies de Jericó.' },
      { v: 11, en: 'They ate unleavened cakes and parched grain of the produce of the land on the next day after the Passover, in the same day.', pt: 'E, ao outro dia depois da páscoa, nesse mesmo dia, comeram, do produto da terra, pães ázimos e espigas tostadas.' },
      { v: 12, en: 'The manna ceased on the next day, after they had eaten of the produce of the land. The children of Israel didn’t have manna any more; but they ate of the fruit of the land of Canaan that year.', pt: 'E no dia depois de terem comido do produto da terra, cessou o maná, e os filhos de Israel não o tiveram mais; porém nesse ano comeram dos produtos da terra de Canaã.' },
      { v: 13, en: 'When Joshua was by Jericho, he lifted up his eyes and looked, and behold, a man stood in front of him with his sword drawn in his hand. Joshua went to him and said to him, “Are you for us, or for our enemies?”', pt: 'Ora, estando Josué perto de Jericó, levantou os olhos, e olhou; e eis que estava em pé diante dele um homem que tinha na mão uma espada nua. Chegou-se Josué a ele, e perguntou-lhe: És tu por nós, ou pelos nossos adversários?' },
      { v: 14, en: 'He said, “No; but I have come now as commander of Yahweh’s army.” Joshua fell on his face to the earth, and worshiped, and asked him, “What does my lord say to his servant?”', pt: 'Respondeu ele: Não; mas venho agora como príncipe do exército do Senhor. Então Josué, prostrando-se com o rosto em terra, o adorou e perguntou-lhe: Que diz meu Senhor ao seu servo?' },
      { v: 15, en: 'The prince of Yahweh’s army said to Joshua, “Take off your shoes; for the place on which you stand is holy.” Joshua did so.', pt: 'Então respondeu o príncipe do exército do Senhor a Josué: Tira os sapatos dos pés, porque o lugar em que estás é santo. E Josué assim fez:' },
    ],
    6: [
      { v: 1, en: 'Now Jericho was tightly shut up because of the children of Israel. No one went out, and no one came in.', pt: 'Ora, Jericó se conservava rigorosamente fechada por causa dos filhos de Israel; ninguém saía nem entrava.' },
      { v: 2, en: 'Yahweh said to Joshua, “Behold, I have given Jericho into your hand, with its king and the mighty men of valor.', pt: 'Então disse o Senhor a Josué: Olha, entrego na tua mão Jericó, o seu rei e os seus homens valorosos.' },
      { v: 3, en: 'All of your men of war shall march around the city, going around the city once. You shall do this six days.', pt: 'Vós, pois, todos os homens de guerra, rodeareis a cidade, contornando-a uma vez por dia; assim fareis por seis dias.' },
      { v: 4, en: 'Seven priests shall bear seven trumpets of rams’ horns before the ark. On the seventh day, you shall march around the city seven times, and the priests shall blow the trumpets.', pt: 'Sete sacerdotes levarão sete trombetas de chifres de carneiros adiante da arca; e no sétimo dia rodeareis a cidade sete vezes, e os sacerdotes tocarão as trombetas.' },
      { v: 5, en: 'It shall be that when they make a long blast with the ram’s horn, and when you hear the sound of the trumpet, all the people shall shout with a great shout; and the city wall shall fall down flat, and the people shall go up, every man straight in front of him.”', pt: 'E será que, fazendo-se sonido prolongado da trombeta, e ouvindo vós tal sonido, todo o povo dará um grande brado; então o muro da cidade cairá rente com o chão, e o povo subirá, cada qual para o lugar que lhe ficar defronte:' },
      { v: 6, en: 'Joshua the son of Nun called the priests, and said to them, “Take up the ark of the covenant, and let seven priests bear seven trumpets of rams’ horns before Yahweh’s ark.”', pt: 'Chamou, pois, Josué, filho de Num, aos sacerdotes, e disse-lhes: Levai a arca do pacto, e sete sacerdotes levem sete trombetas de chifres de carneiros, adiante da arca do Senhor.' },
      { v: 7, en: 'They said to the people, “Advance! March around the city, and let the armed men pass on before Yahweh’s ark.”', pt: 'E disse ao povo: Passai e rodeai a cidade; e marchem os homens armados adiante da arca do Senhor.' },
      { v: 8, en: 'It was so, that when Joshua had spoken to the people, the seven priests bearing the seven trumpets of rams’ horns before Yahweh advanced and blew the trumpets, and the ark of Yahweh’s covenant followed them.', pt: 'Assim, pois, se fez como Josué dissera ao povo: os sete sacerdotes, levando as sete trombetas adiante do Senhor, passaram, e tocaram-nas; e a arca do pacto do Senhor os seguia.' },
      { v: 9, en: 'The armed men went before the priests who blew the trumpets, and the ark went after them. The trumpets sounded as they went.', pt: 'E os homens armados iam adiante dos sacerdotes que tocavam as trombetas, e a retaguarda seguia após a arca, os sacerdotes sempre tocando as trombetas.' },
      { v: 10, en: 'Joshua commanded the people, saying, “You shall not shout, nor let your voice be heard, neither shall any word proceed out of your mouth, until the day I tell you to shout. Then you shall shout.”', pt: 'Josué tinha dado ordem ao povo, dizendo: Não gritareis, nem fareis ouvir a vossa voz, nem sairá palavra alguma da vossa boca, até o dia em que eu vos disser: gritai! Então gritareis.' },
      { v: 11, en: 'So he caused Yahweh’s ark to go around the city, going about it once. Then they came into the camp, and stayed in the camp.', pt: 'Assim fizeram a arca do Senhor rodear a cidade, contornando-a uma vez; então entraram no arraial, e ali passaram a noite.' },
      { v: 12, en: 'Joshua rose early in the morning, and the priests took up Yahweh’s ark.', pt: 'Josué levantou-se de madrugada, e os sacerdotes tomaram a arca do Senhor.' },
      { v: 13, en: 'The seven priests bearing the seven trumpets of rams’ horns in front of Yahweh’s ark went on continually, and blew the trumpets. The armed men went in front of them. The rear guard came after Yahweh’s ark. The trumpets sounded as they went.', pt: 'Os sete sacerdotes que levavam as sete trombetas de chifres de carneiros adiante da arca da Senhor iam andando, tocando as trombetas; os homens armados iam adiante deles, e a retaguarda seguia atrás da arca do Senhor, os sacerdotes sempre tocando as trombetas.' },
      { v: 14, en: 'The second day they marched around the city once, and returned into the camp. They did this six days.', pt: 'E rodearam a cidade uma vez no segundo dia, e voltaram ao arraial. Assim fizeram por seis dias.' },
      { v: 15, en: 'On the seventh day, they rose early at the dawning of the day, and marched around the city in the same way seven times. Only on this day they marched around the city seven times.', pt: 'No sétimo dia levantaram-se bem de madrugada, e da mesma maneira rodearam a cidade sete vezes; somente naquele dia rodearam-na sete vezes.' },
      { v: 16, en: 'At the seventh time, when the priests blew the trumpets, Joshua said to the people, “Shout, for Yahweh has given you the city!', pt: 'E quando os sacerdotes pela sétima vez tocavam as trombetas, disse Josué ao povo: Gritai, porque o Senhor vos entregou a cidade.' },
      { v: 17, en: 'The city shall be devoted, even it and all that is in it, to Yahweh. Only Rahab the prostitute shall live, she and all who are with her in the house, because she hid the messengers that we sent.', pt: 'A cidade, porém, com tudo quanto nela houver, será danátema ao Senhor; somente a prostituta Raabe viverá, ela e todos os que com ela estiverem em casa, porquanto escondeu os mensageiros que enviamos.' },
      { v: 18, en: 'But as for you, only keep yourselves from what is devoted to destruction, lest when you have devoted it, you take of the devoted thing; so you would make the camp of Israel accursed, and trouble it.', pt: 'Mas quanto a vós, guardai-vos do anátema, para que, depois de o terdes feito tal, não tomeis dele coisa alguma, e não façais anátema o arraial de Israel, e o perturbeis.' },
      { v: 19, en: 'But all the silver, gold, and vessels of brass and iron, are holy to Yahweh. They shall come into Yahweh’s treasury.”', pt: 'Contudo, toda a prata, e o ouro, e os vasos de bronze e de ferro, são consagrados ao Senhor; irão para o tesouro do Senhor.' },
      { v: 20, en: 'So the people shouted and the priests blew the trumpets. When the people heard the sound of the trumpet, the people shouted with a great shout, and the wall fell down flat, so that the people went up into the city, every man straight in front of him, and they took the city.', pt: 'Gritou, pois, o povo, e os sacerdotes tocaram as trombetas; ouvindo o povo o sonido da trombeta, deu um grande brado, e o muro caiu rente com o chão, e o povo subiu à cidade, cada qual para o lugar que lhe ficava defronte, e tomaram a cidade:' },
      { v: 21, en: 'They utterly destroyed all that was in the city, both man and woman, both young and old, and ox, sheep, and donkey, with the edge of the sword.', pt: 'E destruíram totalmente, ao fio da espada, tudo quanto havia na cidade, homem e mulher, menino e velho, bois, ovelhas e jumentos.' },
      { v: 22, en: 'Joshua said to the two men who had spied out the land, “Go into the prostitute’s house, and bring the woman and all that she has out from there, as you swore to her.”', pt: 'Então disse Josué aos dois homens que tinham espiado a terra: Entrai na casa da prostituta, e tirai-a dali com tudo quanto tiver, como lhe prometestes com juramento.' },
      { v: 23, en: 'The young men who were spies went in, and brought out Rahab with her father, her mother, her brothers, and all that she had. They also brought out all of her relatives, and they set them outside of the camp of Israel.', pt: 'Entraram, pois, os mancebos espias, e tiraram Raabe, seu pai, sua mãe, seus irmãos, e todos quantos lhe pertenciam; e, trazendo todos os seus parentes, os puseram fora do arraial de Israel.' },
      { v: 24, en: 'They burned the city with fire, and all that was in it. Only they put the silver, the gold, and the vessels of brass and of iron into the treasury of Yahweh’s house.', pt: 'A cidade, porém, e tudo quanto havia nela queimaram a fogo; tão-somente a prata, e o ouro, e os vasos de bronze e de ferro, colocaram-nos no tesouro da casa do Senhor.' },
      { v: 25, en: 'But Rahab the prostitute, her father’s household, and all that she had, Joshua saved alive. She lives in the middle of Israel to this day, because she hid the messengers, whom Joshua sent to spy out Jericho.', pt: 'Assim Josué poupou a vida à prostituta Raabe, à família de seu pai, e a todos quantos lhe pertenciam; e ela ficou habitando no meio de Israel até o dia de hoje, porquanto escondera os mensageiros que Josué tinha enviado a espiar a Jericó.' },
      { v: 26, en: 'Joshua commanded them with an oath at that time, saying, “Cursed is the man before Yahweh, who rises up and builds this city Jericho. With the loss of his firstborn he will lay its foundation, and with the loss of his youngest son he will set up its gates.”', pt: 'Também nesse tempo Josué os esconjurou, dizendo: Maldito diante do Senhor seja o homem que se levantar e reedificar esta cidade de Jericó; com a perda do seu primogênito a fundará, e com a perda do seu filho mais novo lhe colocará as portas.' },
      { v: 27, en: 'So Yahweh was with Joshua; and his fame was in all the land.', pt: 'Assim era o Senhor com Josué; e corria a sua fama por toda a terra.' },
    ],
    7: [
      { v: 1, en: 'But the children of Israel committed a trespass in the devoted things; for Achan, the son of Carmi, the son of Zabdi, the son of Zerah, of the tribe of Judah, took some of the devoted things. Therefore Yahweh’s anger burned against the children of Israel.', pt: 'Mas os filhos de Israel cometeram uma transgressão no tocante ao anátema, pois Acã, filho de Carmi, filho de Zabdi, filho de Zerá, da tribo de Judá, tomou do anátema; e a ira do Senhor se acendeu contra os filhos de Israel.' },
      { v: 2, en: 'Joshua sent men from Jericho to Ai, which is beside Beth Aven, on the east side of Bethel, and spoke to them, saying, “Go up and spy out the land.” The men went up and spied out Ai.', pt: 'Josué enviou de Jericó alguns homens a Ai, que está junto a Bete-Áven ao Oriente de Betel, e disse-lhes: Subi, e espiai a terra. Subiram, pois, aqueles homens, e espiaram a Ai.' },
      { v: 3, en: 'They returned to Joshua, and said to him, “Don’t let all the people go up; but let about two or three thousand men go up and strike Ai. Don’t make all the people to toil there, for there are only a few of them.”', pt: 'Voltaram a Josué, e disseram-lhe: Não suba todo o povo; subam uns dois ou três mil homens, e destruam a Ai. Não fatigues ali a todo o povo, porque os habitantes são poucos.' },
      { v: 4, en: 'So about three thousand men of the people went up there, and they fled before the men of Ai.', pt: 'Assim, subiram lá do povo cerca de três mil homens, os quais fugiram diante dos homens de Ai.' },
      { v: 5, en: 'The men of Ai struck about thirty-six men of them, and they chased them from before the gate even to Shebarim, and struck them at the descent. The hearts of the people melted, and became like water.', pt: 'E os homens de Ai mataram deles cerca de trinta e seis e, havendo-os perseguido desde a porta até Sebarim, bateram-nos na descida; e o coração do povo se derreteu e se tornou como água.' },
      { v: 6, en: 'Joshua tore his clothes, and fell to the earth on his face before Yahweh’s ark until the evening, he and the elders of Israel; and they put dust on their heads.', pt: 'Então Josué rasgou as suas vestes, e se prostrou com o rosto em terra perante a arca do Senhor até a tarde, ele e os anciãos de Israel; e deitaram pó sobre as suas cabeças.' },
      { v: 7, en: 'Joshua said, “Alas, Lord Yahweh, why have you brought this people over the Jordan at all, to deliver us into the hand of the Amorites, to cause us to perish? I wish that we had been content and lived beyond the Jordan!', pt: 'E disse Josué: Ah, Senhor Deus! por que fizeste a este povo atravessar o Jordão, para nos entregares nas mãos dos amorreus, para nos fazeres perecer? Oxalá nos tivéssemos contentado em morarmos além do Jordão.' },
      { v: 8, en: 'Oh, Lord, what shall I say, after Israel has turned their backs before their enemies!', pt: 'Ah, Senhor! que direi, depois que Israel virou as costas diante dos seus inimigos?' },
      { v: 9, en: 'For the Canaanites and all the inhabitants of the land will hear of it, and will surround us, and cut off our name from the earth. What will you do for your great name?”', pt: 'Pois os cananeus e todos os moradores da terra o ouvirão e, cercando-nos, exterminarão da terra o nosso nome; e então, que farás pelo teu grande nome?' },
      { v: 10, en: 'Yahweh said to Joshua, “Get up! Why have you fallen on your face like that?', pt: 'Respondeu o Senhor a Josué: Levanta-te! por que estás assim prostrado com o rosto em terra?' },
      { v: 11, en: 'Israel has sinned. Yes, they have even transgressed my covenant which I commanded them. Yes, they have even taken some of the devoted things, and have also stolen, and also deceived. They have even put it among their own stuff.', pt: 'Israel pecou; eles transgrediram o meu pacto que lhes tinha ordenado; tomaram do anátema, furtaram-no e, dissimulando, esconderam-no entre a sua bagagem.' },
      { v: 12, en: 'Therefore the children of Israel can’t stand before their enemies. They turn their backs before their enemies, because they have become devoted for destruction. I will not be with you any more, unless you destroy the devoted things from among you.', pt: 'Por isso os filhos de Israel não puderam subsistir perante os seus inimigos, viraram as costas diante deles, porquanto se fizeram anátema. Não serei mais convosco, se não destruirdes o anátema do meio de vós.' },
      { v: 13, en: '“Get up! Sanctify the people, and say, ‘Sanctify yourselves for tomorrow, for Yahweh, the God of Israel, says, “There is a devoted thing among you, Israel. You cannot stand before your enemies until you take away the devoted thing from among you.”', pt: 'Levanta-te santifica o povo, e dize-lhe: Santificai-vos para amanhã, pois assim diz o Senhor, o Deus de Israel: Anátema há no meio de ti, Israel; não poderás suster-te diante dos teus inimigos, enquanto não tirares do meio de ti o anátema.' },
      { v: 14, en: '“‘In the morning therefore you shall be brought near by your tribes. It shall be that the tribe which Yahweh selects shall come near by families. The family which Yahweh selects shall come near by households. The household which Yahweh selects shall come near man by man.', pt: 'Amanhã, pois, vos chegareis, segundo as vossas tribos; a tribo que o Senhor tomar se chegará por famílias; a família que o Senhor tomar se chegará por casas; e a casa que o Senhor tomar se chegará homem por homem.' },
      { v: 15, en: 'It shall be, that he who is taken with the devoted thing shall be burned with fire, he and all that he has, because he has transgressed Yahweh’s covenant, and because he has done a disgraceful thing in Israel.’”', pt: 'E aquele que for tomado com o anátema, será queimado no fogo, ele e tudo quanto tiver, porquanto transgrediu o pacto do Senhor, e fez uma loucura em Israel.' },
      { v: 16, en: 'So Joshua rose up early in the morning and brought Israel near by their tribes. The tribe of Judah was selected.', pt: 'Então Josué se levantou de madrugada, e fez chegar Israel segundo as suas tribos, e foi tomada por sorte a tribo de Judá;' },
      { v: 17, en: 'He brought near the family of Judah; and he selected the family of the Zerahites. He brought near the family of the Zerahites man by man, and Zabdi was selected.', pt: 'fez chegar a tribo de Judá, e foi tomada a família dos zeraítas; fez chegar a familia dos zeraítas, homem por homem, e foi tomado Zabdi;' },
      { v: 18, en: 'He brought near his household man by man, and Achan, the son of Carmi, the son of Zabdi, the son of Zerah, of the tribe of Judah, was selected.', pt: 'fez chegar a casa de Zabdi, homem por homem, e foi tomado Acã, filho de Carmi, filho de Zabdi, filho de Zerá, da tribo de Judá.' },
      { v: 19, en: 'Joshua said to Achan, “My son, please give glory to Yahweh, the God of Israel, and make confession to him. Tell me now what you have done! Don’t hide it from me!”', pt: 'Então disse Josué a Acã: Filho meu, dá, peço-te, glória ao Senhor Deus de Israel, e faze confissão perante ele. Declara-me agora o que fizeste; não mo ocultes.' },
      { v: 20, en: 'Achan answered Joshua, and said, “I have truly sinned against Yahweh, the God of Israel, and this is what I have done.', pt: 'Respondeu Acã a Josué: Verdadeiramente pequei contra o Senhor Deus de Israel, e eis o que fiz:' },
      { v: 21, en: 'When I saw among the plunder a beautiful Babylonian robe, two hundred shekels of silver, and a wedge of gold weighing fifty shekels, then I coveted them and took them. Behold, they are hidden in the ground in the middle of my tent, with the silver under it.”', pt: 'quando vi entre os despojos uma boa capa babilônica, e duzentos siclos de prata, e uma cunha de ouro do peso de cinqüenta siclos, cobicei-os e tomei-os; eis que estão escondidos na terra, no meio da minha tenda, e a prata debaixo da capa.' },
      { v: 22, en: 'So Joshua sent messengers, and they ran to the tent. Behold, it was hidden in his tent, with the silver under it.', pt: 'Então Josué enviou mensageiros, que foram correndo à tenda; e eis que tudo estava escondido na sua tenda, estando a prata debaixo da capa.' },
      { v: 23, en: 'They took them from the middle of the tent, and brought them to Joshua and to all the children of Israel. They laid them down before Yahweh.', pt: 'Tomaram, pois, aquelas coisas do meio da tenda, e as trouxeram a Josué e a todos os filhos de Israel; e as puseram perante o Senhor.' },
      { v: 24, en: 'Joshua, and all Israel with him, took Achan the son of Zerah, the silver, the robe, the wedge of gold, his sons, his daughters, his cattle, his donkeys, his sheep, his tent, and all that he had; and they brought them up to the valley of Achor.', pt: 'Então Josué e todo o Israel com ele tomaram Acã, filho de Zerá, e a prata, a capa e a cunha de ouro, e seus filhos e suas filhas, e seus bois, jumentos e ovelhas, e a sua tenda, e tudo quanto tinha, e levaram-nos ao vale de Acor.' },
      { v: 25, en: 'Joshua said, “Why have you troubled us? Yahweh will trouble you today.” All Israel stoned him with stones, and they burned them with fire and stoned them with stones.', pt: 'E disse Josué: Por que nos perturbaste? hoje o Senhor te perturbará a ti: E todo o Israel o apedrejou; queimaram-nos no fogo, e os apedrejaram:' },
      { v: 26, en: 'They raised over him a great heap of stones that remains to this day. Yahweh turned from the fierceness of his anger. Therefore the name of that place was called “The valley of Achor” to this day.', pt: 'E levantaram sobre ele um grande montão de pedras, que permanece até o dia de hoje. E o Senhor se apartou do ardor da sua ira. Por isso se chama aquele lugar até hoje o vale de Acor.' },
    ],
    8: [
      { v: 1, en: 'Yahweh said to Joshua, “Don’t be afraid, and don’t be dismayed. Take all the warriors with you, and arise, go up to Ai. Behold, I have given into your hand the king of Ai, with his people, his city, and his land.', pt: 'Então disse o Senhor a Josué: Não temas, e não te espantes; toma contigo toda a gente de guerra, levanta-te, e sobe a Ai. Olha que te entreguei na tua mão o rei de Ai, o seu povo, a sua cidade e a sua terra.' },
      { v: 2, en: 'You shall do to Ai and her king as you did to Jericho and her king, except you shall take its goods and its livestock for yourselves. Set an ambush for the city behind it.”', pt: 'Farás pois a Ai e a seu rei, como fizeste a Jericó e a seu rei; salvo que para vós tomareis os seus despojos, e o seu gado. Põe emboscadas à cidade, por detrás dela.' },
      { v: 3, en: 'So Joshua arose, with all the warriors, to go up to Ai. Joshua chose thirty thousand men, the mighty men of valor, and sent them out by night.', pt: 'Então Josué levantou-se, com toda a gente de guerra, para subir contra Ai; e escolheu Josué trinta mil homens valorosos, e enviou-os de noite.' },
      { v: 4, en: 'He commanded them, saying, “Behold, you shall lie in ambush against the city, behind the city. Don’t go very far from the city, but all of you be ready.', pt: 'E deu-lhes ordem, dizendo: Ponde-vos de emboscada contra a cidade, por detrás dela; não vos distancieis muito da cidade, mas estai todos vós apercebidos.' },
      { v: 5, en: 'I and all the people who are with me will approach to the city. It shall happen, when they come out against us, as at the first, that we will flee before them.', pt: 'Mas eu e todo o povo que está comigo nos aproximaremos da cidade; e quando eles nos saírem ao encontro, como dantes, fugiremos diante deles.' },
      { v: 6, en: 'They will come out after us, until we have drawn them away from the city; for they will say, ‘They flee before us, like the first time.’ So we will flee before them,', pt: 'E eles sairão atrás de nós, até que os tenhamos afastado da cidade, pois dirão: Fogem diante de nós como dantes. Assim fugiremos diante deles;' },
      { v: 7, en: 'and you shall rise up from the ambush, and take possession of the city; for Yahweh your God will deliver it into your hand.', pt: 'e vós saireis da emboscada, e tomareis a cidade, porque o Senhor vosso Deus vo-la entregará nas maos.' },
      { v: 8, en: 'It shall be, when you have seized the city, that you shall set the city on fire. You shall do this according to Yahweh’s word. Behold, I have commanded you.”', pt: 'Logo que tiverdes tomado a cidade, pôr-lhe-eis fogo, fazendo conforme a palavra do Senhor; olhai que vo-lo tenho mandado.' },
      { v: 9, en: 'Joshua sent them out; and they went to set up the ambush, and stayed between Bethel and Ai, on the west side of Ai; but Joshua stayed among the people that night.', pt: 'Assim Josué os enviou, e eles se foram à emboscada, colocando-se entre Betel e Ai, ao ocidente de Ai; porém Josué passou aquela noite no meio do povo.' },
      { v: 10, en: 'Joshua rose up early in the morning, mustered the people, and went up, he and the elders of Israel, before the people to Ai.', pt: 'Levantando-se Josué de madrugada, passou o povo em revista; então subiu, com os anciãos de Israel, adiante do povo contra Ai.' },
      { v: 11, en: 'All the people, even the men of war who were with him, went up, and came near, and came before the city, and encamped on the north side of Ai. Now there was a valley between him and Ai.', pt: 'Todos os homens armados que estavam com ele subiram e, aproximando-se pela frente da cidade, acamparam-se ao norte de Ai, havendo um vale entre eles e Ai.' },
      { v: 12, en: 'He took about five thousand men, and set them in ambush between Bethel and Ai, on the west side of the city.', pt: 'Tomou também cerca de cinco mil homens, e pô-los de emboscada entre Betel e Ai, ao ocidente da cidade.' },
      { v: 13, en: 'So they set the people, even all the army who was on the north of the city, and their ambush on the west of the city; and Joshua went that night into the middle of the valley.', pt: 'Assim dispuseram o povo, todo o arraial ao norte da cidade, e a sua emboscada ao ocidente da cidade. Marchou Josué aquela noite até o meio do vale.' },
      { v: 14, en: 'When the king of Ai saw it, they hurried and rose up early, and the men of the city went out against Israel to battle, he and all his people, at the time appointed, before the Arabah; but he didn’t know that there was an ambush against him behind the city.', pt: 'Quando o rei de Ai viu isto, ele e todo o seu povo se apressaram, levantando-se de madrugada, e os homens da cidade saíram ao encontro de Israel ao combate, ao lugar determinado, defronte da planície; mas ele não sabia que se achava uma emboscada contra ele atrás da cidade.' },
      { v: 15, en: 'Joshua and all Israel made as if they were beaten before them, and fled by the way of the wilderness.', pt: 'Josué, pois, e todo o Israel fingiram-se feridos diante deles, e furiram pelo caminho do deserto:' },
      { v: 16, en: 'All the people who were in the city were called together to pursue after them. They pursued Joshua, and were drawn away from the city.', pt: 'Portanto, todo o povo que estava na cidade foi convocado para os perseguir; e seguindo eles após Josué, afastaram-se da cidade.' },
      { v: 17, en: 'There was not a man left in Ai or Beth El who didn’t go out after Israel. They left the city open, and pursued Israel.', pt: 'Nem um só homem ficou em Ai, nem em Betel, que não saísse após Israel; assim deixaram a cidade aberta, e seguiram a Israel:' },
      { v: 18, en: 'Yahweh said to Joshua, “Stretch out the javelin that is in your hand toward Ai, for I will give it into your hand.” Joshua stretched out the javelin that was in his hand toward the city.', pt: 'Então o Senhor disse a Josué: Estende para Ai a lança que tens na mão; porque eu ta entregarei. E Josué estendeu para a cidade a lança que estava na sua mão.' },
      { v: 19, en: 'The ambush arose quickly out of their place, and they ran as soon as he had stretched out his hand, and entered into the city, and took it. They hurried and set the city on fire.', pt: 'E, tendo ele estendido a mão, os que estavam de emboscada se levantaram apressadamente do seu lugar e, correndo, entraram na cidade, e a tomaram; e, apressando-se, puseram fogo à cidade.' },
      { v: 20, en: 'When the men of Ai looked behind them, they saw, and behold, the smoke of the city ascended up to heaven, and they had no power to flee this way or that way. The people who fled to the wilderness turned back on the pursuers.', pt: 'Nisso, olhando os homens de Ai para trás, viram a fumaça da cidade, que subia ao céu, e não puderam fugir nem para uma parte nem para outra, porque o povo que fugia para o deserto se tornou contra eles.' },
      { v: 21, en: 'When Joshua and all Israel saw that the ambush had taken the city, and that the smoke of the city ascended, then they turned again, and killed the men of Ai.', pt: 'E vendo Josué e todo o Israel que a emboscada tomara a cidade, e que a fumaça da cidade subia, voltaram e feriram os homens de Ai.' },
      { v: 22, en: 'The others came out of the city against them, so they were in the middle of Israel, some on this side, and some on that side. They struck them, so that they let none of them remain or escape.', pt: 'Também aqueles que estavam na cidade lhes saíram ao encontro, e assim os de Ai ficaram no meio dos israelitas, estando estes de uma e de outra parte; e feriram-nos, de sorte que não deixaram ficar nem escapar nenhum deles.' },
      { v: 23, en: 'They captured the king of Ai alive, and brought him to Joshua.', pt: 'Mas ao rei de Ai tomaram vivo, e o trouxeram a Josué.' },
      { v: 24, en: 'When Israel had finished killing all the inhabitants of Ai in the field, in the wilderness in which they pursued them, and they had all fallen by the edge of the sword, until they were consumed, all Israel returned to Ai, and struck it with the edge of the sword.', pt: 'Quando os israelitas acabaram de matar todos os moradores de Ai no campo, no deserto para onde os tinham seguido, e havendo todos caído ao fio da espada até serem consumidos, então todo o Israel voltou para Ai e a feriu a fio de espada.' },
      { v: 25, en: 'All that fell that day, both of men and women, were twelve thousand, even all the men of Ai.', pt: 'Ora, todos os que caíram naquele dia, assim homens como mulheres, foram doze mil, isto é, todos os de Ai.' },
      { v: 26, en: 'For Joshua didn’t draw back his hand, with which he stretched out the javelin, until he had utterly destroyed all the inhabitants of Ai.', pt: 'Pois Josué não retirou a mão, que estendera com a lança, até destruir totalmente a todos os moradores de Ai.' },
      { v: 27, en: 'Israel took for themselves only the livestock and the goods of that city, according to Yahweh’s word which he commanded Joshua.', pt: 'Tão-somente os israelitas tomaram para si o gado e os despojos da cidade, conforme a palavra que o Senhor ordenara a Josue:' },
      { v: 28, en: 'So Joshua burned Ai, and made it a heap forever, even a desolation, to this day.', pt: 'Queimou pois Josué a Ai, e a tornou num perpétuo montão de ruínas, como o é até o dia de hoje.' },
      { v: 29, en: 'He hanged the king of Ai on a tree until the evening, and at sundown Joshua commanded, and they took his body down from the tree, and threw it at the entrance of the gate of the city, and raised a great heap of stones on it that remains to this day.', pt: 'Ao rei de Ai enforcou num madeiro, deixando-o ali até a tarde. Ao pôr do sol, por ordem de Josué, tiraram do madeiro o cadáver, lançaram-no à porta da cidade e levantaram sobre ele um grande montão de pedras, que permanece até o dia de hoje.' },
      { v: 30, en: 'Then Joshua built an altar to Yahweh, the God of Israel, on Mount Ebal,', pt: 'Então Josué edificou um altar ao Senhor Deus de Israel, no monte Ebal,' },
      { v: 31, en: 'as Moses the servant of Yahweh commanded the children of Israel, as it is written in the book of the law of Moses, an altar of uncut stones, on which no one had lifted up any iron. They offered burnt offerings on it to Yahweh and sacrificed peace offerings.', pt: 'como Moisés, servo do Senhor, ordenara aos filhos de Israel, conforme o que está escrito no livro da lei de Moisés, a saber: um altar de pedras brutas, sobre as quais não se levantara ferramenta; e ofereceram sobre ele holocaustos ao Senhor, e sacrificaram ofertas parcíficas.' },
      { v: 32, en: 'He wrote there on the stones a copy of Moses’ law, which he wrote in the presence of the children of Israel.', pt: 'Também ali, na presença dos filhos de Israel, escreveu em pedras uma cópia da lei de Moisés, a qual este escrevera.' },
      { v: 33, en: 'All Israel, their elders and officers, and their judges, stood on both sides of the ark before the priests the Levites, who carried the ark of Yahweh’s covenant, the foreigner as well as the native; half of them in front of Mount Gerizim, and half of them in front of Mount Ebal, as Moses the servant of Yahweh had commanded at the first, that they should bless the people of Israel.', pt: 'E todo o Israel, tanto o estrangeiro como o natural, com os seus anciãos, oficiais e juízes, estava de um e de outro lado da arca, perante os levitas sacerdotes que levavam a arca do pacto do Senhor; metade deles em frente do monte Gerizim, e a outra metade em frente do monte Ebal, como Moisés, servo do Senhor, dantes ordenara, para que abençoassem o povo de Israel.' },
      { v: 34, en: 'Afterward he read all the words of the law, the blessing and the curse, according to all that is written in the book of the law.', pt: 'Depois leu em alta voz todas as palavras da lei, a bênção e a maldição, conforme tudo o que está escrito no livro da lei.' },
      { v: 35, en: 'There was not a word of all that Moses commanded, which Joshua didn’t read before all the assembly of Israel, with the women, the little ones, and the foreigners who were among them.', pt: 'Palavra nenhuma houve, de tudo o que Moisés ordenara, que Josué não lesse perante toda a congregação de Israel, e as mulheres, e os pequeninos, e os estrangeiros que andavam no meio deles.' },
    ],
    9: [
      { v: 1, en: 'When all the kings who were beyond the Jordan, in the hill country, and in the lowland, and on all the shore of the great sea in front of Lebanon, the Hittite, the Amorite, the Canaanite, the Perizzite, the Hivite, and the Jebusite, heard of it', pt: 'Depois sucedeu que, ouvindo isto todos os reis que estavam além do Jordão, na região montanhosa, na baixada e em toda a costa do grande mar, defronte do Líbano, os heteus, os amorreus, os cananeus, os perizeus, os heveus, e os jebuseus' },
      { v: 2, en: 'they gathered themselves together to fight with Joshua and with Israel, with one accord.', pt: 'se ajuntaram de comum acordo para pelejar contra Josué e contra Israel.' },
      { v: 3, en: 'But when the inhabitants of Gibeon heard what Joshua had done to Jericho and to Ai,', pt: 'Ora, os moradores de Gibeão, ouvindo o que Josué fizera a Jericó e a Ai.' },
      { v: 4, en: 'they also resorted to a ruse, and went and made as if they had been ambassadors, and took old sacks on their donkeys, and old, torn-up and bound up wine skins,', pt: 'usaram de astúcia: foram e se fingiram embaixadores, tomando sacos velhos sobre os seus jumentos, e odres de vinho velhos, rotos e recosidos,' },
      { v: 5, en: 'and old and patched shoes on their feet, and wore old garments. All the bread of their food supply was dry and moldy.', pt: 'tendo nos seus pés sapatos velhos e remendados, e trajando roupas velhas; e todo o pão que traziam para o caminho era seco e bolorento.' },
      { v: 6, en: 'They went to Joshua at the camp at Gilgal, and said to him and to the men of Israel, “We have come from a far country. Now therefore make a covenant with us.”', pt: 'E vieram a Josué, ao arraial em Gilgal, e disseram a ele e aos homens de Israel: Somos vindos duma terra longínqua; fazei, pois, agora pacto conosco.' },
      { v: 7, en: 'The men of Israel said to the Hivites, “What if you live among us? How could we make a covenant with you?”', pt: 'Responderam os homens de Israel a estes heveus: Bem pode ser que habiteis no meio de nós; como pois faremos pacto convosco?' },
      { v: 8, en: 'They said to Joshua, “We are your servants.” Joshua said to them, “Who are you? Where do you come from?”', pt: 'Então eles disseram a Josué: Nós somos teus servos. Ao que lhes perguntou Josué: Quem sois vós? e donde vindes?' },
      { v: 9, en: 'They said to him, “Your servants have come from a very far country because of the name of Yahweh your God; for we have heard of his fame, all that he did in Egypt,', pt: 'Responderam-lhe: Teus servos vieram duma terra mui distante, por causa do nome do Senhor teu Deus, porquanto ouvimos a sua fama, e tudo o que fez no Egito,' },
      { v: 10, en: 'and all that he did to the two kings of the Amorites who were beyond the Jordan, to Sihon king of Heshbon and to Og king of Bashan, who was at Ashtaroth.', pt: 'e tudo o que fez aos dois reis dos amorreus, que estavam além do Jordão, a Siom, rei de Hesbom, e a Ogue, rei de Basã, que estava em Astarote.' },
      { v: 11, en: 'Our elders and all the inhabitants of our country spoke to us, saying, ‘Take supplies in your hand for the journey, and go to meet them. Tell them, “We are your servants. Now make a covenant with us.”’', pt: 'Pelo que nossos anciãos e todos os moradores da nossa terra nos falaram, dizendo: Tomai nas mãos provisão para o caminho, e ide-lhes ao encontro, e dizei-lhes: Nós somos vossos servos; fazei, pois, agora pacto conosco.' },
      { v: 12, en: 'This our bread we took hot for our supplies out of our houses on the day we went out to go to you; but now, behold, it is dry, and has become moldy.', pt: 'Este nosso pão tomamo-lo quente das nossas casas para nossa provisão, no dia em que saímos para vir ter convosco, e ei-lo aqui agora seco e bolorento;' },
      { v: 13, en: 'These wine skins, which we filled, were new; and behold, they are torn. These our garments and our shoes have become old because of the very long journey.”', pt: 'estes odres, que enchemos de vinho, eram novos, e ei-los aqui já rotos; e esta nossa roupa e nossos sapatos já envelheceram em razão do mui longo caminho.' },
      { v: 14, en: 'The men sampled their provisions, and didn’t ask counsel from Yahweh’s mouth.', pt: 'Então os homens de Israel tomaram da provisão deles, e não pediram conselho ao Senhor.' },
      { v: 15, en: 'Joshua made peace with them, and made a covenant with them, to let them live. The princes of the congregation swore to them.', pt: 'Assim Josué fez paz com eles; também fez um pacto com eles, prometendo poupar-lhes a vida; e os príncipes da congregação lhes prestaram juramento.' },
      { v: 16, en: 'At the end of three days after they had made a covenant with them, they heard that they were their neighbors, and that they lived among them.', pt: 'Três dias depois de terem feito pacto com eles, ouviram que eram vizinhos e que moravam no meio deles.' },
      { v: 17, en: 'The children of Israel traveled and came to their cities on the third day. Now their cities were Gibeon, Chephirah, Beeroth, and Kiriath Jearim.', pt: 'Tendo partido os filhos de Israel, chegaram ao terceiro dia às cidades deles, que eram Gibeão, Cefira, Beerote e Quiriate-Jearir.' },
      { v: 18, en: 'The children of Israel didn’t strike them, because the princes of the congregation had sworn to them by Yahweh, the God of Israel. All the congregation murmured against the princes.', pt: 'Mas os filhos de Israel não os mataram, porquanto os príncipes da congregação lhes haviam prestado juramento pelo Senhor, o Deus de Israel; pelo que toda a congregação murmurava contra os príncipes.' },
      { v: 19, en: 'But all the princes said to all the congregation, “We have sworn to them by Yahweh, the God of Israel. Now therefore we may not touch them.', pt: 'Mas os príncipes disseram a toda a congregação: Nós lhes prestamos juramento pelo Senhor, o Deus de Israel, e agora não lhes podemos tocar.' },
      { v: 20, en: 'We will do this to them, and let them live; lest wrath be on us, because of the oath which we swore to them.”', pt: 'Isso cumpriremos para com eles, poupando-lhes a vida, para que não haja ira sobre nós, por causa do juramento que lhes fizemos.' },
      { v: 21, en: 'The princes said to them, “Let them live, so they became wood cutters and drawers of water for all the congregation, as the princes had spoken to them.”', pt: 'Disseram, pois, os príncipes: Vivam. Assim se tornaram rachadores de lenha e tiradores de água para toda a congregação, como os príncipes lhes disseram.' },
      { v: 22, en: 'Joshua called for them, and he spoke to them, saying, “Why have you deceived us, saying, ‘We are very far from you,’ when you live among us?', pt: 'Então Josué os chamou, e lhes disse: Por que nos enganastes, dizendo: Mui longe de vós habitamos, morando vós no meio de nós?' },
      { v: 23, en: 'Now therefore you are cursed, and some of you will never fail to be slaves, both wood cutters and drawers of water for the house of my God.”', pt: 'Agora, pois, sois malditos, e dentre vós nunca deixará de haver servos, rachadores de lenha e tiradores de água para a casa do meu Deus.' },
      { v: 24, en: 'They answered Joshua, and said, “Because your servants were certainly told how Yahweh your God commanded his servant Moses to give you all the land, and to destroy all the inhabitants of the land from before you. Therefore we were very afraid for our lives because of you, and have done this thing.', pt: 'Respondendo a Josué, disseram: Porquanto foi anunciado aos teus servos que o Senhor teu Deus ordenou a Moisés, seu servo, que vos desse toda esta terra, e destruísse todos os seus moradores diante de vós, temíamos muito pelas nossas vidas por causa de vós, e fizemos isso.' },
      { v: 25, en: 'Now, behold, we are in your hand. Do to us as it seems good and right to you to do.”', pt: 'E eis que agora estamos na tua mão; faze aquilo que te pareça bom e reto que se nos faça.' },
      { v: 26, en: 'He did so to them, and delivered them out of the hand of the children of Israel, so that they didn’t kill them.', pt: 'Assim pois ele lhes fez, e livrou-os das mãos dos filhos de Israel, de sorte que estes não os mataram.' },
      { v: 27, en: 'That day Joshua made them wood cutters and drawers of water for the congregation and for Yahweh’s altar to this day, in the place which he should choose.', pt: 'Mas, naquele dia, Josué os fez rachadores de lenha e tiradores de água para a congregação e para o altar do Senhor, no lugar que ele escolhesse, como ainda o são.' },
    ],
    10: [
      { v: 1, en: 'Now when Adoni-Zedek king of Jerusalem heard how Joshua had taken Ai, and had utterly destroyed it; as he had done to Jericho and her king, so he had done to Ai and her king; and how the inhabitants of Gibeon had made peace with Israel, and were among them,', pt: 'Quando Adoni-Zedeque, rei de Jerusalém, ouviu que Josué tomara a Ai, e a destruíra totalmente (pois este fizera a Ai e ao seu rei como tinha feito a Jericó e ao seu rei), e que os moradores de Gibeão tinham feito paz com os israelitas, e estavam no meio deles,' },
      { v: 2, en: 'they were very afraid, because Gibeon was a great city, as one of the royal cities, and because it was greater than Ai, and all its men were mighty.', pt: 'temeu muito, pois Gibeão era uma cidade grande como uma das cidades reais, e era ainda maior do que Ai, e todos os seus homens eram valorosos.' },
      { v: 3, en: 'Therefore Adoni-Zedek king of Jerusalem sent to Hoham king of Hebron, Piram king of Jarmuth, Japhia king of Lachish, and Debir king of Eglon, saying,', pt: 'Pelo que Adoni-Zedeque, rei de Jerusalém, enviou mensageiros a Hoão, rei de Hebrom, a Pirã, rei de Jarmute, a Jafia, rei de Laquis, e a Debir, rei de Eglom, para lhes dizer:' },
      { v: 4, en: '“Come up to me and help me. Let us strike Gibeon; for they have made peace with Joshua and with the children of Israel.”', pt: 'Subi a mim, e ajudai-me; firamos a Gibeão, porquanto fez paz com Josué e com os filhos de Israel.' },
      { v: 5, en: 'Therefore the five kings of the Amorites, the king of Jerusalem, the king of Hebron, the king of Jarmuth, the king of Lachish, and the king of Eglon, gathered themselves together and went up, they and all their armies, and encamped against Gibeon, and made war against it.', pt: 'Então se ajuntaram, e subiram cinco reis dos amorreus, o rei de Jerusalém, o rei de Hebrom, o rei de Jarmute, o rei de Laquis, o rei de Eglom, eles e todos os seus exércitos, e sitiaram a Gibeão e pelejaram contra ela.' },
      { v: 6, en: 'The men of Gibeon sent to Joshua at the camp at Gilgal, saying, “Don’t abandon your servants! Come up to us quickly and save us! Help us; for all the kings of the Amorites that dwell in the hill country have gathered together against us.”', pt: 'Enviaram, pois, os homens de Gibeão a Josué, ao arraial em Gilgal, a dizer-lhe: Não retires de teus servos a tua mão; sobe apressadamente a nós, e livra-nos, e ajuda-nos, porquanto se ajuntaram contra nós todos os reis dos amorreus, que habitam na região montanhosa.' },
      { v: 7, en: 'So Joshua went up from Gilgal, he, and the whole army with him, including all the mighty men of valor.', pt: 'Josué, pois, subiu de Gilgal com toda a gente de guerra e todos os homens valorosos.' },
      { v: 8, en: 'Yahweh said to Joshua, “Don’t fear them, for I have delivered them into your hands. Not a man of them will stand before you.”', pt: 'E o Senhor disse a Josué: Não os temas, porque os entreguei na tua mão; nenhum deles te poderá resistir.' },
      { v: 9, en: 'Joshua therefore came to them suddenly. He marched from Gilgal all night.', pt: 'E Josué deu de repente sobre eles, tendo marchado a noite toda, subindo de Gilgal;' },
      { v: 10, en: 'Yahweh confused them before Israel. He killed them with a great slaughter at Gibeon, and chased them by the way of the ascent of Beth Horon, and struck them to Azekah and to Makkedah.', pt: 'e o Senhor os pôs em desordem diante de Israel, que os desbaratou com grande matança em Gibeão, e os perseguiu pelo caminho que sobe a Bete-Horom, ferindo-os até Azeca e Maqueda.' },
      { v: 11, en: 'As they fled from before Israel, while they were at the descent of Beth Horon, Yahweh hurled down great stones from the sky on them to Azekah, and they died. There were more who died from the hailstones than those whom the children of Israel killed with the sword.', pt: 'Pois, quando eles iam fugindo de diante de Israel, à descida de Bete-Horom, o Senhor lançou sobre eles, do céu, grandes pedras até Azeca, e eles morreram; e foram mais os que morreram das pedras da saraiva do que os que os filhos de Israel mataram à espada.' },
      { v: 12, en: 'Then Joshua spoke to Yahweh in the day when Yahweh delivered up the Amorites before the children of Israel. He said in the sight of Israel, “Sun, stand still on Gibeon! You, moon, stop in the valley of Aijalon!”', pt: 'Então Josué falou ao Senhor, no dia em que o Senhor entregou os amorreus na mão dos filhos de Israel, e disse na presença de Israel: Sol, detém-se sobre Gibeão, e tu, lua, sobre o vale de Aijalom.' },
      { v: 13, en: 'The sun stood still, and the moon stayed, until the nation had avenged themselves of their enemies. Isn’t this written in the book of Jashar? The sun stayed in the middle of the sky, and didn’t hurry to go down about a whole day.', pt: 'E o sol se deteve, e a lua parou, até que o povo se vingou de seus inimigos. Não está isto escrito no livro de Jasar? O sol, pois, se deteve no meio do céu, e não se apressou a pôr-se, quase um dia inteiro.' },
      { v: 14, en: 'There was no day like that before it or after it, that Yahweh listened to the voice of a man; for Yahweh fought for Israel.', pt: 'E não houve dia semelhante a esse, nem antes nem depois dele, atendendo o Senhor assim à voz dum homem; pois o Senhor pelejava por Israel.' },
      { v: 15, en: 'Joshua returned, and all Israel with him, to the camp to Gilgal.', pt: 'Depois voltou Josué, e todo o Israel com ele, ao arraial em Gilgal.' },
      { v: 16, en: 'These five kings fled, and hid themselves in the cave at Makkedah.', pt: 'Aqueles cinco reis, porém, fugiram e se esconderam na caverna que há em Maqueda.' },
      { v: 17, en: 'Joshua was told, saying, “The five kings have been found, hidden in the cave at Makkedah.”', pt: 'E isto foi anunciado a Josué nestas palavras: Acharam-se os cinco reis escondidos na caverna em Maqueda.' },
      { v: 18, en: 'Joshua said, “Roll large stones to cover the cave’s entrance, and set men by it to guard them;', pt: 'Disse, pois, Josué: Arrastai grandes pedras para a boca da caverna, e junto a ela ponde homens que os guardem.' },
      { v: 19, en: 'but don’t stay there. Pursue your enemies, and attack them from the rear. Don’t allow them to enter into their cities; for Yahweh your God has delivered them into your hand.”', pt: 'Vós, porém, não vos detenhais; persegui os vossos inimigos, matando os que vão ficando atrás; não os deixeis entrar nas suas cidades, porque o Senhor vosso Deus já vo-los entregou nas mãos.' },
      { v: 20, en: 'When Joshua and the children of Israel had finished killing them with a very great slaughter until they were consumed, and the remnant which remained of them had entered into the fortified cities,', pt: 'Quando Josué e os filhos de Israel acabaram de os ferir com mui grande matança, até serem eles exterminados, e os que ficaram deles se retiraram às cidades fortificadas,' },
      { v: 21, en: 'all the people returned to the camp to Joshua at Makkedah in peace. None moved his tongue against any of the children of Israel.', pt: 'todo o povo voltou em paz a Josué, ao arraial em Maqueda. Não havia ninguém que movesse a sua língua contra os filhos de Israel.' },
      { v: 22, en: 'Then Joshua said, “Open the cave entrance, and bring those five kings out of the cave to me.”', pt: 'Depois disse Josué: Abri a boca da caverna, e trazei-me para fora aqueles cinco reis.' },
      { v: 23, en: 'They did so, and brought those five kings out of the cave to him: the king of Jerusalem, the king of Hebron, the king of Jarmuth, the king of Lachish, and the king of Eglon.', pt: 'Fizeram, pois, assim, e trouxeram-lhe aqueles cinco reis para fora da caverna: o rei de Jerusalém, o rei de Hebrom, o rei de Jarmute, o rei de Laquis, e o rei de Eglom.' },
      { v: 24, en: 'When they brought those kings out to Joshua, Joshua called for all the men of Israel, and said to the chiefs of the men of war who went with him, “Come near. Put your feet on the necks of these kings.” They came near, and put their feet on their necks.', pt: 'Quando os trouxeram a Josué, este chamou todos os homens de Israel, e disse aos comandantes dos homens de guerra que o haviam acompanhado: Chegai-vos, ponde os pés sobre os pescoços destes reis. E eles se chegaram e puseram os pés sobre os pescoços deles.' },
      { v: 25, en: 'Joshua said to them, “Don’t be afraid, nor be dismayed. Be strong and courageous, for Yahweh will do this to all your enemies against whom you fight.”', pt: 'Então Josué lhes disse: Não temais, nem vos atemorizeis; esforçai-vos e tende bom ânimo, porque assim fará o Senhor a todos os vossos inimigos, contra os quais haveis de pelejar.' },
      { v: 26, en: 'Afterward Joshua struck them, put them to death, and hanged them on five trees. They were hanging on the trees until the evening.', pt: 'Depois disto Josué os feriu, e os matou, e os pendurou em cinco madeiros, onde ficaram pendurados até a tarde.' },
      { v: 27, en: 'At the time of the going down of the sun, Joshua commanded, and they took them down off the trees, and threw them into the cave in which they had hidden themselves, and laid great stones on the mouth of the cave, which remain to this very day.', pt: 'Ao pôr do sol, por ordem de Josué, tiraram-nos dos madeiros, lançaram-nos na caverna em que se haviam escondido, e puseram à boca da mesma grandes pedras, que ainda ali estão até o dia de hoje.' },
      { v: 28, en: 'Joshua took Makkedah on that day, and struck it with the edge of the sword, with its king. He utterly destroyed it and all the souls who were in it. He left no one remaining. He did to the king of Makkedah as he had done to the king of Jericho.', pt: 'Naquele mesmo dia Josué tomou a Maqueda, e feriu-a a fio de espada, bem como a seu rei; totalmente os destruiu com todos os que nela havia, sem deixar ali nem sequer um. Fez, pois, ao rei de Maqueda como fizera ao rei de Jericó.' },
      { v: 29, en: 'Joshua passed from Makkedah, and all Israel with him, to Libnah, and fought against Libnah.', pt: 'De Maqueda, Josué, e todo o Israel com ele, passou a Libna, e pelejou contra ela.' },
      { v: 30, en: 'Yahweh delivered it also, with its king, into the hand of Israel. He struck it with the edge of the sword, and all the souls who were in it. He left no one remaining in it. He did to its king as he had done to the king of Jericho.', pt: 'E a esta também, e a seu rei, o Senhor entregou na mão de Israel, que a feriu a fio de espada com todos os que nela havia, sem deixar ali nem sequer um. Fez, pois, ao seu rei como fizera ao rei de Jericó.' },
      { v: 31, en: 'Joshua passed from Libnah, and all Israel with him, to Lachish, and encamped against it, and fought against it.', pt: 'De Libna, Josué, e todo o Israel com ele, passou a Laquis, e a sitiou, e pelejou contra ela.' },
      { v: 32, en: 'Yahweh delivered Lachish into the hand of Israel. He took it on the second day, and struck it with the edge of the sword, with all the souls who were in it, according to all that he had done to Libnah.', pt: 'O Senhor entregou também a Laquis na mão de Israel, que a tomou no segundo dia, e a feriu a fio de espada com todos os que nela havia, conforme tudo o que fizera a Libna.' },
      { v: 33, en: 'Then Horam king of Gezer came up to help Lachish; and Joshua struck him and his people, until he had left him no one remaining.', pt: 'Então Horão, rei de Gezer, subiu para ajudar a Laquis; porém Josué o feriu, a ele e ao seu povo, até não lhe deixar nem sequer um.' },
      { v: 34, en: 'Joshua passed from Lachish, and all Israel with him, to Eglon; and they encamped against it and fought against it.', pt: 'De Laquis, Josué, e todo o Israel com ele, passou a Eglom, e a sitiaram, e pelejaram contra ela,' },
      { v: 35, en: 'They took it on that day, and struck it with the edge of the sword. He utterly destroyed all the souls who were in it that day, according to all that he had done to Lachish.', pt: 'e no mesmo dia a tomaram, ferindo-a a fio de espada; destruiu totalmente nesse mesmo dia todos os que nela estavam, conforme tudo o que fizera a Laquis.' },
      { v: 36, en: 'Joshua went up from Eglon, and all Israel with him, to Hebron; and they fought against it.', pt: 'De Eglom, Josué, e todo o Israel com ele, subiu a Hebrom; pelejaram contra ela,' },
      { v: 37, en: 'They took it, and struck it with the edge of the sword, with its king and all its cities, and all the souls who were in it. He left no one remaining, according to all that he had done to Eglon; but he utterly destroyed it, and all the souls who were in it.', pt: 'tomaram-na, e a feriram ao fio da espada, bem como ao seu rei, e a todas as suas cidades, com todos os que nelas havia. A ninguém deixou com vida, mas, conforme tudo o que fizera a Eglom, a destruiu totalmente, com todos os que nela havia.' },
      { v: 38, en: 'Joshua returned, and all Israel with him, to Debir, and fought against it.', pt: 'Então Josué, e todo o Israel com ele, voltou a Debir, pelejou contra ela,' },
      { v: 39, en: 'He took it, with its king and all its cities. They struck them with the edge of the sword, and utterly destroyed all the souls who were in it. He left no one remaining. As he had done to Hebron, so he did to Debir, and to its king; as he had done also to Libnah, and to its king.', pt: 'e a tomou com o seu rei e com todas as suas cidades; feriu-as a fio de espada, e a todos os que nelas havia destruiu totalmente, não deixando nem sequer um. Como fizera a Hebrom, e como fizera também a Libna e ao seu rei, assim fez a Debir e ao seu rei.' },
      { v: 40, en: 'So Joshua struck all the land, the hill country, the South, the lowland, the slopes, and all their kings. He left no one remaining, but he utterly destroyed all that breathed, as Yahweh, the God of Israel, commanded.', pt: 'Assim feriu Josué toda aquela terra, a região montanhosa, o Negebe, a baixada, e as faldas das montanhas, e a todos os seus reis. Não deixou nem sequer um; mas a tudo o que tinha fôlego destruiu totalmente, como ordenara o Senhor, o Deus de Israel:' },
      { v: 41, en: 'Joshua struck them from Kadesh Barnea even to Gaza, and all the country of Goshen, even to Gibeon.', pt: 'Assim Josué os feriu desde Cades-Barnéia até Gaza, como também toda a terra de Gósem, até Gibeão.' },
      { v: 42, en: 'Joshua took all these kings and their land at one time because Yahweh, the God of Israel, fought for Israel.', pt: 'E de uma só vez tomou Josué todos esses reis e a sua terra, porquanto o Senhor, o Deus de Israel, pelejava por Israel.' },
      { v: 43, en: 'Joshua returned, and all Israel with him, to the camp to Gilgal.', pt: 'Então Josué, e todo o Israel com ele, voltou ao arraial em Gilgal.' },
    ],
    11: [
      { v: 1, en: 'When Jabin king of Hazor heard of it, he sent to Jobab king of Madon, to the king of Shimron, to the king of Achshaph,', pt: 'Quando Jabim, rei de Hazor, ouviu isso, enviou mensageiros a Jobabe, rei de Madom, e ao rei de Sinrom, e ao rei de Acsafe,' },
      { v: 2, en: 'and to the kings who were on the north, in the hill country, in the Arabah south of Chinneroth, in the lowland, and in the heights of Dor on the west,', pt: 'e aos reis que estavam ao norte, na região montanhosa, na Arabá ao sul de Quinerote, na baixada, e nos planaltos de Dor ao ocidente;' },
      { v: 3, en: 'to the Canaanite on the east and on the west, the Amorite, the Hittite, the Perizzite, the Jebusite in the hill country, and the Hivite under Hermon in the land of Mizpah.', pt: 'ao cananeu do oriente e do ocidente, ao amorreu, ao heteu, ao perizeu, ao jebuseu na região montanhosa, e ao heveu ao pé de Hermom na terra de Mizpá.' },
      { v: 4, en: 'They went out, they and all their armies with them, many people, even as the sand that is on the seashore in multitude, with very many horses and chariots.', pt: 'Saíram pois eles, com todos os seus exércitos, muito povo, em multidão como a areia que está na praia do mar, e muitíssimos cavalos e carros.' },
      { v: 5, en: 'All these kings met together; and they came and encamped together at the waters of Merom, to fight with Israel.', pt: 'Todos esses reis, reunindo-se, vieram e juntos se acamparam às águas de Merom, para pelejarem contra Israel.' },
      { v: 6, en: 'Yahweh said to Joshua, “Don’t be afraid because of them; for tomorrow at this time, I will deliver them up all slain before Israel. You shall hamstring their horses and burn their chariots with fire.”', pt: 'Disse o Senhor a Josué: Não os temas, pois amanhã a esta hora eu os entregarei todos mortos diante de Israel. Os seus cavalos jarretarás, e os seus carros queimarás a fogo.' },
      { v: 7, en: 'So Joshua came suddenly, with all the warriors, against them by the waters of Merom, and attacked them.', pt: 'Josué, pois, com toda a gente de guerra, sobreveio-lhes de repente às águas de Merom, e deu sobre eles.' },
      { v: 8, en: 'Yahweh delivered them into the hand of Israel, and they struck them, and chased them to great Sidon, and to Misrephoth Maim, and to the valley of Mizpah eastward. They struck them until they left them no one remaining.', pt: 'E o Senhor os entregou na mão dos israelitas, que os feriram e os perseguiram até a grande Sidom, e até Misrefote-Maim, e até o vale de Mizpe ao oriente; e feriram-nos até não lhes deixar nem sequer um.' },
      { v: 9, en: 'Joshua did to them as Yahweh told him. He hamstrung their horses and burned their chariots with fire.', pt: 'Fez-lhes Josué como o Senhor lhe dissera: os seus cavalos jarretou, e os seus carros queimou a fogo.' },
      { v: 10, en: 'Joshua turned back at that time, and took Hazor, and struck its king with the sword: for Hazor used to be the head of all those kingdoms.', pt: 'Naquele tempo Josué voltou e tomou também a Hazor, e feriu à espada ao seu rei, porquanto Hazor dantes era a cabeça de todos estes reinos.' },
      { v: 11, en: 'They struck all the souls who were in it with the edge of the sword, utterly destroying them. There was no one left who breathed. He burned Hazor with fire.', pt: 'E passaram ao fio da espada a todos os que nela havia, destruindo-os totalmente; nada restou do que tinha fôlego; e a Hazor ele queimou a fogo.' },
      { v: 12, en: 'Joshua captured all the cities of those kings, with their kings, and he struck them with the edge of the sword, and utterly destroyed them; as Moses the servant of Yahweh commanded.', pt: 'Josué, pois, tomou todas as cidades desses reis, e a eles mesmos, e os passou ao fio da espada, destruindo-os totalmente, como ordenara Moisés, servo do Senhor.' },
      { v: 13, en: 'But as for the cities that stood on their mounds, Israel burned none of them, except Hazor only. Joshua burned that.', pt: 'Contudo, quanto às cidades que se achavam sobre os seus altos, a nenhuma delas queimou Israel, salvo somente a Hazor; a essa Josué queimou.' },
      { v: 14, en: 'The children of Israel took all the plunder of these cities, with the livestock, as plunder for themselves; but every man they struck with the edge of the sword, until they had destroyed them. They didn’t leave any who breathed.', pt: 'Mas todos os despojos dessas cidades, e o gado, tomaram-nos os filhos de Israel como presa para si; porém feriram ao fio da espada todos os homens, até os destruírem; nada deixaram do que tinha fôlego de vida.' },
      { v: 15, en: 'As Yahweh commanded Moses his servant, so Moses commanded Joshua. Joshua did so. He left nothing undone of all that Yahweh commanded Moses.', pt: 'Como o Senhor ordenara a Moisés, seu servo, assim Moisés ordenou a Josué, e assim Josué o fez; não deixou de fazer coisa alguma de tudo o que o Senhor ordenara a Moisés.' },
      { v: 16, en: 'So Joshua captured all that land, the hill country, all the South, all the land of Goshen, the lowland, the Arabah, the hill country of Israel, and the lowland of the same;', pt: 'Assim Josué tomou toda aquela terra, a região montanhosa, todo o Negebe, e toda a terra de Gósem e a baixada, e a Arabá, e a região montanhosa de Israel com a sua baixada,' },
      { v: 17, en: 'from Mount Halak, that goes up to Seir, even to Baal Gad in the valley of Lebanon under Mount Hermon. He took all their kings, struck them, and put them to death.', pt: 'desde o monte Halaque, que sobe a Seir, até Baal-Gade, no vale do Líbano, ao pé do monte Hermom; também tomou todos os seus reis, e os feriu e os matou.' },
      { v: 18, en: 'Joshua made war a long time with all those kings.', pt: 'Por muito tempo Josué fez guerra contra todos esses reis.' },
      { v: 19, en: 'There was not a city that made peace with the children of Israel, except the Hivites, the inhabitants of Gibeon. They took all in battle.', pt: 'Não houve cidade que fizesse paz com os filhos de Israel, senão os heveus, moradores de Gibeão; a todas tomaram à força de armas.' },
      { v: 20, en: 'For it was of Yahweh to harden their hearts, to come against Israel in battle, that he might utterly destroy them, that they might have no favor, but that he might destroy them, as Yahweh commanded Moses.', pt: 'Porquanto do Senhor veio o endurecimento dos seus corações para saírem à guerra contra Israel, a fim de que fossem destruídos totalmente, e não achassem piedade alguma, mas fossem exterminados, como o Senhor tinha ordenado a Moisés.' },
      { v: 21, en: 'Joshua came at that time, and cut off the Anakim from the hill country, from Hebron, from Debir, from Anab, and from all the hill country of Judah, and from all the hill country of Israel: Joshua utterly destroyed them with their cities.', pt: 'Naquele tempo veio Josué, e exterminou os anaquins da região montanhosa de Hebrom, de Debir, de Anabe, de toda a região montanhosa de Judá, e de toda a região montanhosa de Israel; Josué os destruiu totalmente com as suas cidades.' },
      { v: 22, en: 'There were none of the Anakim left in the land of the children of Israel. Only in Gaza, in Gath, and in Ashdod, did some remain.', pt: 'Não foi deixado nem sequer um dos anaquins na terra dos filhos de Israel; somente ficaram alguns em Gaza, em Gate, e em Asdode.' },
      { v: 23, en: 'So Joshua took the whole land, according to all that Yahweh spoke to Moses; and Joshua gave it for an inheritance to Israel according to their divisions by their tribes. The land had rest from war.', pt: 'Assim Josué tomou toda esta terra conforme tudo o que o Senhor tinha dito a Moisés; e Josué a deu em herança a Israel, pelas suas divisões, segundo as suas tribos; e a terra repousou da guerra.' },
    ],
    12: [
      { v: 1, en: 'Now these are the kings of the land, whom the children of Israel struck, and possessed their land beyond the Jordan toward the sunrise, from the valley of the Arnon to Mount Hermon, and all the Arabah eastward:', pt: 'Estes, pois, são os reis da terra, aos quais os filhos de Israel feriram e cujas terras possuíram, do Jordão para o nascente do sol, desde o vale do Arnom até o monte Hermom, e toda a Arabá para o oriente:' },
      { v: 2, en: 'Sihon king of the Amorites, who lived in Heshbon, and ruled from Aroer, which is on the edge of the valley of the Arnon, and the middle of the valley, and half Gilead, even to the river Jabbok, the border of the children of Ammon;', pt: 'Siom, rei dos amorreus, que habitava em Hesbom e que dominava desde Aroer, que está a borda do vale do Arnom, e desde o meio do vale, e a metade de Gileade, até o ribeiro Jaboque, termo dos amonitas;' },
      { v: 3, en: 'and the Arabah to the sea of Chinneroth, eastward, and to the sea of the Arabah, even the Salt Sea, eastward, the way to Beth Jeshimoth; and on the south, under the slopes of Pisgah:', pt: 'e a Arabá até o mar de Quinerote para o oriente, e até o mar da Arabá, o Mar Salgado, para o oriente, pelo caminho de Bete-Jesimote, e no sul abaixo das faldas de Pisga;' },
      { v: 4, en: 'and the border of Og king of Bashan, of the remnant of the Rephaim, who lived at Ashtaroth and at Edrei,', pt: 'como também o termo de Ogue, rei de Basã, que era do restante dos refains, o qual habitava em Astarote, e em Edrei,' },
      { v: 5, en: 'and ruled in Mount Hermon, and in Salecah, and in all Bashan, to the border of the Geshurites and the Maacathites, and half Gilead, the border of Sihon king of Heshbon.', pt: 'e dominava no monte Hermom, e em Salca, e em toda a Basã, até o termo dos gesureus e dos maacateus, e metade de Gileade, termo de siom, rei de Hesbom.' },
      { v: 6, en: 'Moses the servant of Yahweh and the children of Israel struck them. Moses the servant of Yahweh gave it for a possession to the Reubenites, and the Gadites, and the half-tribe of Manasseh.', pt: 'Moisés, servo do Senhor, e os filhos de Israel os feriram; e Moisés, servo do Senhor, deu essa terra em possessão aos rubenitas, e aos gaditas, e à meia tribo de Manassés:' },
      { v: 7, en: 'These are the kings of the land whom Joshua and the children of Israel struck beyond the Jordan westward, from Baal Gad in the valley of Lebanon even to Mount Halak, that goes up to Seir. Joshua gave it to the tribes of Israel for a possession according to their divisions;', pt: 'E estes são os reis da terra, aos quais Josué e os filhos de Israel feriram, do Jordão para o ocidente, desde Baal-Gade, no vale do Líbano, até o monte Halaque, que sobe a Seir (e Josué deu as suas terras às tribos de Israel em possessão, segundo as suas divisoes,' },
      { v: 8, en: 'in the hill country, and in the lowland, and in the Arabah, and in the slopes, and in the wilderness, and in the South; the Hittite, the Amorite, and the Canaanite, the Perizzite, the Hivite, and the Jebusite:', pt: 'isto é, o que havia na região montanhosa, na baixada, na Arabá, nas faldas das montanhas, no deserto e no Negebe: o heteu, o amorreu, e o cananeu, o perizeu, o heveu, e o jebuseu);' },
      { v: 9, en: 'the king of Jericho, one; the king of Ai, which is beside Bethel, one;', pt: 'o rei de Jericó, o rei de Ai, que está ao lado de Betel,' },
      { v: 10, en: 'the king of Jerusalem, one; the king of Hebron, one;', pt: 'o rei de Jerusalém, o rei de Hebrom,' },
      { v: 11, en: 'the king of Jarmuth, one; the king of Lachish, one;', pt: 'o rei de Jarmute, o rei de Laquis,' },
      { v: 12, en: 'the king of Eglon, one; the king of Gezer, one;', pt: 'o rei de Eglom, o rei de Gezer,' },
      { v: 13, en: 'the king of Debir, one; the king of Geder, one;', pt: 'o rei de Debir, o rei de Geder,' },
      { v: 14, en: 'the king of Hormah, one; the king of Arad, one;', pt: 'o rei de Horma, o rei de Arade,' },
      { v: 15, en: 'the king of Libnah, one; the king of Adullam, one;', pt: 'o rei de Libna, o rei de Adulão,' },
      { v: 16, en: 'the king of Makkedah, one; the king of Bethel, one;', pt: 'o rei de Maqueda, o rei de Betel,' },
      { v: 17, en: 'the king of Tappuah, one; the king of Hepher, one;', pt: 'o rei de Tapua, o rei de Hefer,' },
      { v: 18, en: 'the king of Aphek, one; the king of Lassharon, one;', pt: 'o rei de Afeque, o rei de Lassarom,' },
      { v: 19, en: 'the king of Madon, one; the king of Hazor, one;', pt: 'o rei de Madom, o rei de Hazor,' },
      { v: 20, en: 'the king of Shimron Meron, one; the king of Achshaph, one;', pt: 'o rei de Sinrom-Merom, o rei de Acsafe,' },
      { v: 21, en: 'the king of Taanach, one; the king of Megiddo, one;', pt: 'o rei de Taanaque, o rei de Megido,' },
      { v: 22, en: 'the king of Kedesh, one; the king of Jokneam in Carmel, one;', pt: 'o rei de Quedes, o rei de Jocneão do Carmelo,' },
      { v: 23, en: 'the king of Dor in the height of Dor, one; the king of Goiim in Gilgal, one;', pt: 'o rei de Dor no outeiro de Dor, o rei de Goiim em Gilgal,' },
      { v: 24, en: 'the king of Tirzah, one: all the kings thirty-one.', pt: 'o rei de Tirza: trinta e um reis ao todo.' },
    ],
    13: [
      { v: 1, en: 'Now Joshua was old and well advanced in years. Yahweh said to him, “You are old and advanced in years, and there remains yet very much land to be possessed.', pt: 'Era Josué já velho e avançado em anos, quando lhe disse o Senhor: Já estás velho e avançado em anos, e ainda fica muitíssima terra para se possuir.' },
      { v: 2, en: '“This is the land that still remains: all the regions of the Philistines, and all the Geshurites;', pt: 'A terra que ainda fica é esta: todas as regiões dos filisteus, bem como todas as dos gesureus,' },
      { v: 3, en: 'from the Shihor, which is before Egypt, even to the border of Ekron northward, which is counted as Canaanite; the five lords of the Philistines; the Gazites, and the Ashdodites, the Ashkelonites, the Gittites, and the Ekronites; also the Avvim,', pt: 'desde Sior, que está defronte do Egito, até o termo de Ecrom para o norte, que se tem como pertencente aos cananeus; os cinco chefes dos filisteus; o gazeu, o asdodeu, o asqueloneu, o giteu, e o ecroneu; também os aveus;' },
      { v: 4, en: 'on the south; all the land of the Canaanites, and Mearah that belongs to the Sidonians, to Aphek, to the border of the Amorites;', pt: 'no sul toda a terra, dos cananeus, e Meara, que pertence aos sidônios, até Afeca, até o termo dos amorreus;' },
      { v: 5, en: 'and the land of the Gebalites, and all Lebanon, toward the sunrise, from Baal Gad under Mount Hermon to the entrance of Hamath;', pt: 'como também a terra dos Gebalitas, e todo o Líbano para o nascente do sol, desde Baal-Gade, ao pé do monte Hermom, até a entrada de Hamate;' },
      { v: 6, en: 'all the inhabitants of the hill country from Lebanon to Misrephoth Maim, even all the Sidonians. I will drive them out from before the children of Israel. Just allocate it to Israel for an inheritance, as I have commanded you.', pt: 'todos os habitantes da região montanhosa desde o Líbano até Misrefote-Maim, a saber, todos os sidônios. Eu os lançarei de diante dos filhos de Israel; tão-somente reparte a terra a Israel por herança, como já te mandei.' },
      { v: 7, en: 'Now therefore divide this land for an inheritance to the nine tribes and the half-tribe of Manasseh.”', pt: 'Reparte, pois, agora esta terra por herança às nove tribos, e à meia tribo de Manassés.' },
      { v: 8, en: 'With him the Reubenites and the Gadites received their inheritance, which Moses gave them, beyond the Jordan eastward, even as Moses the servant of Yahweh gave them:', pt: 'Com a outra meia tribo os rubenitas e os gaditas já haviam recebido a sua herança do Jordão para o oriente, a qual Moisés, servo do Senhor, lhes tinha dado:' },
      { v: 9, en: 'from Aroer, that is on the edge of the valley of the Arnon, and the city that is in the middle of the valley, and all the plain of Medeba to Dibon;', pt: 'desde Aroer, que está à borda do vale do Arnom, e a cidade que está no meio do vale, e todo o planalto de Medeba até Dibom;' },
      { v: 10, en: 'and all the cities of Sihon king of the Amorites, who reigned in Heshbon, to the border of the children of Ammon;', pt: 'e todas as cidades de Siom, rei dos amorreus, que reinou em Hesbom, até o termo dos amonitas;' },
      { v: 11, en: 'and Gilead, and the border of the Geshurites and Maacathites, and all Mount Hermon, and all Bashan to Salecah;', pt: 'e Gileade, e o território dos gesureus e dos maacateus, e todo o monte Hermom, e toda a Basã até Salca;' },
      { v: 12, en: 'all the kingdom of Og in Bashan, who reigned in Ashtaroth and in Edrei (the same was left of the remnant of the Rephaim); for Moses attacked these, and drove them out.', pt: 'todo o reino de Ogue em Basã, que reinou em Astarote e em Edrei (ele era dos refains que ficaram); pois que Moisés os feriu e expulsou.' },
      { v: 13, en: 'Nevertheless the children of Israel didn’t drive out the Geshurites, nor the Maacathites: but Geshur and Maacath live within Israel to this day.', pt: 'Contudo os filhos de Israel não expulsaram os gesureus nem os maacateus, os quais ficaram habitando no meio de Israel até o dia de hoje.' },
      { v: 14, en: 'Only he gave no inheritance to the tribe of Levi. The offerings of Yahweh, the God of Israel, made by fire are his inheritance, as he spoke to him.', pt: 'Tão-somente à tribo de Levi não deu herança; as ofertas queimadas ao Senhor, Deus de Israel, são a sua herança, como lhe tinha dito.' },
      { v: 15, en: 'Moses gave to the tribe of the children of Reuben according to their families.', pt: 'Assim Moisés deu herança à tribo dos filhos de Rúben conforme as suas famílias.' },
      { v: 16, en: 'Their border was from Aroer, that is on the edge of the valley of the Arnon, and the city that is in the middle of the valley, and all the plain by Medeba;', pt: 'E foi o seu território desde Aroer, que está à borda do vale do Amom, e a cidade que está no meio do vale, e todo o planalto junto a Medeba;' },
      { v: 17, en: 'Heshbon, and all its cities that are in the plain; Dibon, Bamoth Baal, Beth Baal Meon,', pt: 'Hesbom, e todas as suas cidades que estão no planalto; Dibom, Bamote-Baal e Bete-Baal-Meom;' },
      { v: 18, en: 'Jahaz, Kedemoth, Mephaath,', pt: 'Jaza, Qa espada até serem consumidos, então todo o Israel' },
      { v: 19, en: 'Kiriathaim, Sibmah, Zereth Shahar in the mount of the valley,', pt: 'Quiriataim, Sibma e Zerete-Saar, no monte do vale;' },
      { v: 20, en: 'Beth Peor, the slopes of Pisgah, Beth Jeshimoth,', pt: 'Bete-Peor, as faldas de Pisga e Bete-Jesimote;' },
      { v: 21, en: 'all the cities of the plain, and all the kingdom of Sihon king of the Amorites, who reigned in Heshbon, whom Moses struck with the chiefs of Midian, Evi, Rekem, Zur, Hur, and Reba, the princes of Sihon, who lived in the land.', pt: 'todas as cidades do planalto, e todo o reino de Siom, rei dos amorreus, que reinou em Hesbom, a quem Moisés feriu juntamente com os príncipes de Midiã: Evi, Requem, Zur, Hur e Reba, príncipes de Siom, que moravam naquela terra.' },
      { v: 22, en: 'The children of Israel also killed Balaam the son of Beor, the soothsayer, with the sword, among the rest of their slain.', pt: 'Também ao adivinho Balaão, filho de Beor, os filhos de Israel mataram à espada, juntamente com os demais que por eles foram mortos.' },
      { v: 23, en: 'The border of the children of Reuben was the bank of the Jordan. This was the inheritance of the children of Reuben according to their families, the cities and its villages.', pt: 'E ficou sendo o Jordão o termo dos filhos de Rúben. Essa região, com as suas cidades e aldeias, foi a herança dos filhos de Rúben, segundo as suas famílias.' },
      { v: 24, en: 'Moses gave to the tribe of Gad, to the children of Gad, according to their families.', pt: 'Também deu Moisés herança à tribo de Gade, aos filhos de Gade, segundo as suas famílias.' },
      { v: 25, en: 'Their border was Jazer, and all the cities of Gilead, and half the land of the children of Ammon, to Aroer that is near Rabbah;', pt: 'E foi o seu território Jazer, e todas as cidades de Gileade, e metade da terra dos amonitas, até Aroer, que está defronte de Rabá;' },
      { v: 26, en: 'and from Heshbon to Ramath Mizpeh, and Betonim; and from Mahanaim to the border of Debir;', pt: 'e desde Hesbom até Ramá-Mizpe, e Betonim, e desde Maanaim até o termo de Debir;' },
      { v: 27, en: 'and in the valley, Beth Haram, Beth Nimrah, Succoth, and Zaphon, the rest of the kingdom of Sihon king of Heshbon, the Jordan’s bank, to the uttermost part of the sea of Chinnereth beyond the Jordan eastward.', pt: 'e no vale, Bete-Arã, Bete-Ninra, Sucote e Zafom, resto do reino de Siom, rei de Hesbom, tendo o Jordão por termo, até a extremidade do mar de Quinerete, do Jordão para o oriente.' },
      { v: 28, en: 'This is the inheritance of the children of Gad according to their families, the cities and its villages.', pt: 'Essa região, com as suas cidades e aldeias, foi a herança dos filhos da Gade, segundo as suas famílias.' },
      { v: 29, en: 'Moses gave an inheritance to the half-tribe of Manasseh. It was for the half-tribe of the children of Manasseh according to their families.', pt: 'Também deu Moisés herança à meia tribo de Manassés; a qual foi repartida à meia tribo dos filhos de Manassés segundo as suas famílias.' },
      { v: 30, en: 'Their border was from Mahanaim, all Bashan, all the kingdom of Og king of Bashan, and all the villages of Jair, which are in Bashan, sixty cities.', pt: 'Foi o seu território desde Maanaim; toda a Basã, todo o reino de Ogue, rei de Basã, e todas as aldeias de Jair, que estão em Basã, sessenta ao todo;' },
      { v: 31, en: 'Half Gilead, Ashtaroth, and Edrei, the cities of the kingdom of Og in Bashan, were for the children of Machir the son of Manasseh, even for the half of the children of Machir according to their families.', pt: 'e metade de Gileade, e Astarote, e Edrei, cidades do reino de Ogue, em Basã, foram para os filhos de Maquir, filho de Manassés, isto é, para a metade dos filhos de Maquir, segundo as suas famílias.' },
      { v: 32, en: 'These are the inheritances which Moses distributed in the plains of Moab, beyond the Jordan at Jericho, eastward.', pt: 'Isso é o que Moisés repartiu em herança nas planícies de Moabe, do Jordão para o oriente, na altura de Jericó.' },
      { v: 33, en: 'But Moses gave no inheritance to the tribe of Levi. Yahweh, the God of Israel, is their inheritance, as he spoke to them.', pt: 'Contudo, à tribo de Levi Moisés não deu herança; o Senhor, Deus de Israel, é a sua herança, como lhe tinha dito.' },
    ],
    14: [
      { v: 1, en: 'These are the inheritances which the children of Israel took in the land of Canaan, which Eleazar the priest, Joshua the son of Nun, and the heads of the fathers’ houses of the tribes of the children of Israel, distributed to them,', pt: 'Estas, pois, são as heranças que os filhos de Israel receberam na terra de Canaã, as quais Eleazar, o sacerdote, e Josué, filho de Num, e os cabeças das casas paternas das tribos dos filhos de Israel lhes repartiram.' },
      { v: 2, en: 'by the lot of their inheritance, as Yahweh commanded by Moses, for the nine tribes, and for the half-tribe.', pt: 'Foi feita por sorte a partilha da herança entre as nove tribos e meia, como o Senhor ordenara por intermédio de Moisés.' },
      { v: 3, en: 'For Moses had given the inheritance of the two tribes and the half-tribe beyond the Jordan; but to the Levites he gave no inheritance among them.', pt: 'Porquanto às duas tribos e meia Moisés já dera herança além do Jordão; mas aos levitas não deu herança entre eles.' },
      { v: 4, en: 'For the children of Joseph were two tribes, Manasseh and Ephraim. They gave no portion to the Levites in the land, except cities to dwell in, with their suburbs for their livestock and for their property.', pt: 'Os filhos de José eram duas tribos, Manassés e Efraim; e aos levitas não se deu porção na terra, senão cidades em que habitassem e os arrabaldes delas para o seu gado e para os seus bens. :' },
      { v: 5, en: 'The children of Israel did as Yahweh commanded Moses, and they divided the land.', pt: 'Como o Senhor ordenara a Moises, assim fizeram os filhos de Israel e repartiram a terra.' },
      { v: 6, en: 'Then the children of Judah came near to Joshua in Gilgal. Caleb the son of Jephunneh the Kenizzite said to him, “You know the thing that Yahweh spoke to Moses the man of God concerning me and concerning you in Kadesh Barnea.', pt: 'Então os filhos de Judá chegaram a Josué em Gilgal; e Calebe, filho de Jefoné o quenezeu, lhe disse: Tu sabes o que o Senhor falou a Moisés, homem de Deus, em Cades-Barnéia, a respeito de mim e de ti.' },
      { v: 7, en: 'I was forty years old when Moses the servant of Yahweh sent me from Kadesh Barnea to spy out the land. I brought him word again as it was in my heart.', pt: 'Quarenta anos tinha eu quando Moisés, servo do Senhor, me enviou de Cades-Barnéia para espiar a terra, e eu lhe trouxe resposta, como sentia no meu coração.' },
      { v: 8, en: 'Nevertheless, my brothers who went up with me made the heart of the people melt; but I wholly followed Yahweh my God.', pt: 'Meus irmãos que subiram comigo fizeram derreter o coraçao o povo; mas eu perseverei em seguir ao Senhor meu Deus.' },
      { v: 9, en: 'Moses swore on that day, saying, ‘Surely the land where you walked shall be an inheritance to you and to your children forever, because you have wholly followed Yahweh my God.’', pt: 'Naquele dia Moisés jurou, dizendo: Certamente a terra em que pisou o teu pé te será por herança a ti e a teus filhos para sempre, porque perseveraste em seguir ao Senhor meu Deus.' },
      { v: 10, en: '“Now, behold, Yahweh has kept me alive, as he spoke, these forty-five years, from the time that Yahweh spoke this word to Moses, while Israel walked in the wilderness. Now, behold, I am eighty-five years old, today.', pt: 'E agora eis que o Senhor, como falou, me conservou em vida estes quarentá e cinco anos, desde o tempo em que o Senhor falou esta palavra a Moisés, andando Israel ainda no deserto; e eis que hoje tenho já oitenta e cinco anos;' },
      { v: 11, en: 'As yet I am as strong today as I was in the day that Moses sent me. As my strength was then, even so is my strength now for war, to go out and to come in.', pt: 'ainda hoje me acho tão forte como no dia em que Moisés me enviou; qual era a minha força então, tal é agora a minha força, tanto para a guerra como para sair e entrar.' },
      { v: 12, en: 'Now therefore give me this hill country, of which Yahweh spoke in that day; for you heard in that day how the Anakim were there, and great and fortified cities. It may be that Yahweh will be with me, and I shall drive them out, as Yahweh said.”', pt: 'Agora, pois, dá-me este monte de que o Senhor falou naquele dia; porque tu ouviste, naquele dia, que estavam ali os anaquins, bem como cidades grandes e fortificadas. Porventura o Senhor será comigo para os expulsar, como ele disse.' },
      { v: 13, en: 'Joshua blessed him; and he gave Hebron to Caleb the son of Jephunneh for an inheritance.', pt: 'Então Josué abençoou a Calebe, filho de Jefoné, e lhe deu Hebrom em herança.' },
      { v: 14, en: 'Therefore Hebron became the inheritance of Caleb the son of Jephunneh the Kenizzite to this day, because he followed Yahweh, the God of Israel wholeheartedly.', pt: 'Portanto Hebrom ficou sendo herança de Calebe, filho de Jefoné o quenezeu, até o dia de hoje, porquanto perseverara em seguir ao Senhor Deus de Israel.' },
      { v: 15, en: 'Now the name of Hebron before was Kiriath Arba, after the greatest man among the Anakim. Then the land had rest from war.', pt: 'Ora, o nome de Hebrom era outrora Quiriate-Arba, porque Arba era o maior homem entre os anaquins. E a terra repousou da guerra.' },
    ],
    15: [
      { v: 1, en: 'The lot for the tribe of the children of Judah according to their families was to the border of Edom, even to the wilderness of Zin southward, at the uttermost part of the south.', pt: 'A sorte que coube à tribo dos filhos de Judá, segundo as suas famílias, se estende até o termo de Edom, até o deserto de Zim para o sul, na extremidade do lado meridional' },
      { v: 2, en: 'Their south border was from the uttermost part of the Salt Sea, from the bay that looks southward;', pt: 'O seu termo meridional, partindo da extremidade do Mar Salgado, da baía que dá para o sul,' },
      { v: 3, en: 'and it went out southward of the ascent of Akrabbim, and passed along to Zin, and went up by the south of Kadesh Barnea, and passed along by Hezron, went up to Addar, and turned towards Karka;', pt: 'estende-se para o sul, até a subida de Acrabim, passa a Zim, sobe pelo sul de Cades-Barnéia, passa por Hezrom, sobe a Adar, e vira para Carca;' },
      { v: 4, en: 'and it passed along to Azmon, went out at the brook of Egypt; and the border ended at the sea. This shall be your south border.', pt: 'daí passa a Azmom, chega até o ribeiro do Egito, e por ele vai até o mar. Este será o vosso termo meridional.' },
      { v: 5, en: 'The east border was the Salt Sea, even to the end of the Jordan. The border of the north quarter was from the bay of the sea at the end of the Jordan.', pt: 'O termo oriental é o Mar Salgado, até a foz do Jordão. O termo setentrional, partindo da baía do mar na foz do Jordão,' },
      { v: 6, en: 'The border went up to Beth Hoglah, and passed along by the north of Beth Arabah; and the border went up to the stone of Bohan the son of Reuben.', pt: 'sobe até Bete-Hogla, passa ao norte de Bete-Arabá, e sobe até a pedra de Boã, filho de Rúben;' },
      { v: 7, en: 'The border went up to Debir from the valley of Achor, and so northward, looking toward Gilgal, that faces the ascent of Adummim, which is on the south side of the river. The border passed along to the waters of En Shemesh, and ended at En Rogel.', pt: 'sobe mais este termo a Debir, desde o vale de Acor, indo para o norte em direção a Gilgal, a qual está defronte da subida de Adumim, que se acha ao lado meridional do ribeiro; então continua este termo até as águas de En-Semes, e os seus extremos chegam a En-Rogel;' },
      { v: 8, en: 'The border went up by the valley of the son of Hinnom to the side of the Jebusite (also called Jerusalem) southward; and the border went up to the top of the mountain that lies before the valley of Hinnom westward, which is at the farthest part of the valley of Rephaim northward.', pt: 'sobe ainda pelo vale de Ben-Hinom, até a saliência meridional do monte jebuseu (isto é, Jerusalém); sobe ao cume do monte que está fronteiro ao vale de Hinom para o ocidente, na extremidade do vale dos refains para o norte;' },
      { v: 9, en: 'The border extended from the top of the mountain to the spring of the waters of Nephtoah, and went out to the cities of Mount Ephron; and the border extended to Baalah (also called Kiriath Jearim);', pt: 'do cume do monte se estende até a fonte das águas de Neftoa e, seguindo até as cidades do monte de Efrom, estende-se ainda até Baalá (esta é Quiriate-Jearim) ;' },
      { v: 10, en: 'and the border turned about from Baalah westward to Mount Seir, and passed along to the side of Mount Jearim (also called Chesalon) on the north, and went down to Beth Shemesh, and passed along by Timnah;', pt: 'de Baalá este termo volta para o ocidente, até o monte Seir, passa ao lado do monte Jearim da banda do norte (este é Quesalom) , desce a Bete-Semes e passa por Timna;' },
      { v: 11, en: 'and the border went out to the side of Ekron northward; and the border extended to Shikkeron, and passed along to Mount Baalah, and went out at Jabneel; and the goings out of the border were at the sea.', pt: 'segue mais este termo até o lado de Ecrom para o norte e, indo para Siquerom e passando o monte de Baalá, chega a Jabneel; e assim este termo finda no mar.' },
      { v: 12, en: 'The west border was to the shore of the great sea. This is the border of the children of Judah according to their families.', pt: 'O termo ocidental é o mar grande. São esses os termos dos filhos de Judá ao redor, segundo as suas famílias.' },
      { v: 13, en: 'He gave to Caleb the son of Jephunneh a portion among the children of Judah, according to the commandment of Yahweh to Joshua, even Kiriath Arba, named after the father of Anak (also called Hebron).', pt: 'Deu-se, porém, a Calebe, filho de Jefoné, uma porção no meio dos filhos de Judá, conforme a ordem do Senhor a Josué, a saber, Quiriate-Arba, que é Hebrom (Arba era o pai de Anaque).' },
      { v: 14, en: 'Caleb drove out the three sons of Anak: Sheshai, and Ahiman, and Talmai, the children of Anak.', pt: 'E Calebe expulsou dali os três filhos de Anaque: Sesai, Aimã e Talmai, descendentes de Anaque.' },
      { v: 15, en: 'He went up against the inhabitants of Debir: now the name of Debir before was Kiriath Sepher.', pt: 'Dali subiu contra os habitantes de Debir. Ora, o nome de Debir era dantes Quiriate-Sefer.' },
      { v: 16, en: 'Caleb said, “He who strikes Kiriath Sepher, and takes it, to him I will give Achsah my daughter as wife.”', pt: 'Disse então Calebe: A quem atacar Quiriate-Sefer e a tomar, darei a minha filha Acsa por mulher.' },
      { v: 17, en: 'Othniel the son of Kenaz, the brother of Caleb, took it: and he gave him Achsah his daughter as wife.', pt: 'Tomou-a, pois, Otniel, filho de Quenaz, irmão de Calebe; e este lhe deu a sua filha Acsa por mulher.' },
      { v: 18, en: 'When she came, she had him ask her father for a field. She got off her donkey, and Caleb said, “What do you want?”', pt: 'Estando ela em caminho para a casa de Otniel, persuadiu-o que pedisse um campo ao pai dela. E quando ela saltou do jumento, Calebe lhe perguntou: Que é que tens?' },
      { v: 19, en: 'She said, “Give me a blessing. Because you have set me in the land of the South, give me also springs of water.” So he gave her the upper springs and the lower springs.', pt: 'Respondeu ela: Dá-me um presente; porquanto me deste terra no Negebe, dá-me também fontes d\'água. Então lhe deu as fontes superiores e as fontes inferiores.' },
      { v: 20, en: 'This is the inheritance of the tribe of the children of Judah according to their families.', pt: 'Esta é a herança da tribo dos filhos de Judá, segundo as suas famílias.' },
      { v: 21, en: 'The farthest cities of the tribe of the children of Judah toward the border of Edom in the South were Kabzeel, Eder, Jagur,', pt: 'As cidades pertencentes à tribo dos filhos de Judá, no extremo sul, para o lado de Edom, são: Cabzeel, Eder, Jagur,' },
      { v: 22, en: 'Kinah, Dimonah, Adadah,', pt: 'Quiná, Dimona, Adada,' },
      { v: 23, en: 'Kedesh, Hazor, Ithnan,', pt: 'Quedes, Hazor, Itnã,' },
      { v: 24, en: 'Ziph, Telem, Bealoth,', pt: 'Zife, Telem, Bealote,' },
      { v: 25, en: 'Hazor Hadattah, Kerioth Hezron (also called Hazor),', pt: 'Hazor-Hadada, Queriote-Hezrom (que é Hazor),' },
      { v: 26, en: 'Amam, Shema, Moladah,', pt: 'Amã, Sema, Molada,' },
      { v: 27, en: 'Hazar Gaddah, Heshmon, Beth Pelet,', pt: 'Hazar-Gada, Hesmom, Bete-Pelete,' },
      { v: 28, en: 'Hazar Shual, Beersheba, Biziothiah,', pt: 'Hazar-Sual, Berseba, Biziotiá,' },
      { v: 29, en: 'Baalah, Iim, Ezem,', pt: 'Baalá, Iim, Ezem,' },
      { v: 30, en: 'Eltolad, Chesil, Hormah,', pt: 'Eltolade, Quesil, Horma,' },
      { v: 31, en: 'Ziklag, Madmannah, Sansannah,', pt: 'Ziclague, Madmana, Sansana,' },
      { v: 32, en: 'Lebaoth, Shilhim, Ain, and Rimmon. All the cities are twenty-nine, with their villages.', pt: 'Lebaote, Silim, Aim e Rimom; ao todo, vinte e nove cidades, e as suas aldeias.' },
      { v: 33, en: 'In the lowland, Eshtaol, Zorah, Ashnah,', pt: 'Na baixada: Estaol, Zorá, Asná,' },
      { v: 34, en: 'Zanoah, En Gannim, Tappuah, Enam,', pt: 'Zanoa, En-Ganim, Tapua, Enã,' },
      { v: 35, en: 'Jarmuth, Adullam, Socoh, Azekah,', pt: 'Jarmute, Adulão, Socó, Azeca,' },
      { v: 36, en: 'Shaaraim, Adithaim and Gederah (or Gederothaim); fourteen cities with their villages.', pt: 'Saraim, Aditaim, Gedera e Gederotaim; catorze cidades e as suas aldeias.' },
      { v: 37, en: 'Zenan, Hadashah, Migdal Gad,', pt: 'Zenã, Hadasa, Migdal-Gade,' },
      { v: 38, en: 'Dilean, Mizpah, Joktheel,', pt: 'Dileã, Mizpe, Jocteel,' },
      { v: 39, en: 'Lachish, Bozkath, Eglon,', pt: 'Laquis, Bozcate, Erglom,' },
      { v: 40, en: 'Cabbon, Lahmam, Chitlish,', pt: 'Cabom, Laamás, Quitlis,' },
      { v: 41, en: 'Gederoth, Beth Dagon, Naamah, and Makkedah; sixteen cities with their villages.', pt: 'Gederote, Bete-Dagom, Naama e Maqueda; dezesseis cidades e as suas aldeias.' },
      { v: 42, en: 'Libnah, Ether, Ashan,', pt: 'Libna, Eter, Asã,' },
      { v: 43, en: 'Iphtah, Ashnah, Nezib,', pt: 'Iftá, Asná, Nezibe,' },
      { v: 44, en: 'Keilah, Achzib, and Mareshah; nine cities with their villages.', pt: 'Queila, Aczibe e Maressa; nove cidades e as suas aldeias.' },
      { v: 45, en: 'Ekron, with its towns and its villages;', pt: 'Ecrom, com as suas vilas e aldeias;' },
      { v: 46, en: 'from Ekron even to the sea, all that were by the side of Ashdod, with their villages.', pt: 'desde Ecrom até o mar, todas as que estão nas adjacências de Asdode, e as suas aldeias;' },
      { v: 47, en: 'Ashdod, its towns and its villages; Gaza, its towns and its villages; to the brook of Egypt, and the great sea with its coastline.', pt: 'Asdode, com as suas vilas e aldeias; Gaza, com as suas vilas e aldeias, até o rio do Egito, e o mar grande, que serve de termo.' },
      { v: 48, en: 'In the hill country, Shamir, Jattir, Socoh,', pt: 'E na região montanhosa: Samir, Jatir, Socó,' },
      { v: 49, en: 'Dannah, Kiriath Sannah (which is Debir),', pt: 'Daná, Quiriate-Saná (que é Debir),' },
      { v: 50, en: 'Anab, Eshtemoh, Anim,', pt: 'Anabe, Estemó, Anim,' },
      { v: 51, en: 'Goshen, Holon, and Giloh; eleven cities with their villages.', pt: 'Gósem Holom e Gilo; onze cidades e as suas aldeias.' },
      { v: 52, en: 'Arab, Dumah, Eshan,', pt: 'Arabe, Dumá, Esã,' },
      { v: 53, en: 'Janim, Beth Tappuah, Aphekah,', pt: 'Janim, Bete-Tapua, Afeca,' },
      { v: 54, en: 'Humtah, Kiriath Arba (also called Hebron), and Zior; nine cities with their villages.', pt: 'Hunta, Quiriate-Arba (que é Hebrom) e Zior; nove cidades e as suas aldeias.' },
      { v: 55, en: 'Maon, Carmel, Ziph, Jutah,', pt: 'Maom, Carmelo, Zife, Jutá,' },
      { v: 56, en: 'Jezreel, Jokdeam, Zanoah,', pt: 'Jizreel, Jocdeão, Zanoa,' },
      { v: 57, en: 'Kain, Gibeah, and Timnah; ten cities with their villages.', pt: 'Caim, Gibeá e Timna; dez cidades e as suas aldeias.' },
      { v: 58, en: 'Halhul, Beth Zur, Gedor,', pt: 'Halul, Bete-Zur, Gedor,' },
      { v: 59, en: 'Maarath, Beth Anoth, and Eltekon; six cities with their villages.', pt: 'Maarate, Bete-Anote e Eltecom; seis cidades e as suas aldeias.' },
      { v: 60, en: 'Kiriath Baal (also called Kiriath Jearim), and Rabbah; two cities with their villages.', pt: 'Quiriate-Baal (que é Quiriate-Jearim) e Rabá; duas cidades e as suas aldeias.' },
      { v: 61, en: 'In the wilderness, Beth Arabah, Middin, Secacah,', pt: 'No deserto: Bete-Arabá, Midim, Secaca,' },
      { v: 62, en: 'Nibshan, the City of Salt, and En Gedi; six cities with their villages.', pt: 'Nibsã, a cidade do Sal e En-Gedi; seis cidades e as suas aldeias.' },
      { v: 63, en: 'As for the Jebusites, the inhabitants of Jerusalem, the children of Judah couldn’t drive them out; but the Jebusites live with the children of Judah at Jerusalem to this day.', pt: 'Não puderam, porém, os filhos de Judá expulsar os jebuseus que habitavam em Jerusalém; assim ficaram habitando os jebuseus com os filhos de Judá em Jerusalém, até o dia de hoje.' },
    ],
    16: [
      { v: 1, en: 'The lot came out for the children of Joseph from the Jordan at Jericho, at the waters of Jericho on the east, even the wilderness, going up from Jericho through the hill country to Bethel.', pt: 'Saiu depois a sorte dos filhos de José, a qual, partindo do Jordão, na altura de Jericó, junto às águas de Jericó ao oriente, se estende pelo deserto que sobe de Jericó através da região montanhosa até Betel;' },
      { v: 2, en: 'It went out from Bethel to Luz, and passed along to the border of the Archites to Ataroth;', pt: 'de Betel vai para Luz, e passa ao termo dos arquitas, até Atarote;' },
      { v: 3, en: 'and it went down westward to the border of the Japhletites, to the border of Beth Horon the lower, and on to Gezer; and ended at the sea.', pt: 'desce para o ocidente até o termo dos jafletitas, até o termo de Bete-Horom de baixo, e daí até Gezer, indo terminar no mar.' },
      { v: 4, en: 'The children of Joseph, Manasseh and Ephraim, took their inheritance.', pt: 'Assim receberam a sua herança os filhos de José, Manassés e Efraim.' },
      { v: 5, en: 'This was the border of the children of Ephraim according to their families. The border of their inheritance eastward was Ataroth Addar, to Beth Horon the upper.', pt: 'Ora, fica o termo dos filhos de Efraim, segundo as suas famílias, como se segue: para o oriente o termo da sua herança é Atarote-Adar até Bete-Horom de cima;' },
      { v: 6, en: 'The border went out westward at Michmethath on the north. The border turned about eastward to Taanath Shiloh, and passed along it on the east of Janoah.', pt: 'sai este termo para o ocidente junto a Micmetá ao norte e vira para o oriente até Taanate-Siló, margeando-a a leste de Janoa;' },
      { v: 7, en: 'It went down from Janoah to Ataroth, to Naarah, reached to Jericho, and went out at the Jordan.', pt: 'desce de Janoa a Atarote e a Naarate, toca em Jericó e termina no Jordão:' },
      { v: 8, en: 'From Tappuah the border went along westward to the brook of Kanah; and ended at the sea. This is the inheritance of the tribe of the children of Ephraim according to their families;', pt: 'De Tapua estende-se para o ocidente até o ribeiro de Caná, e vai terminar no mar. Esta é a herança da tribo dos filhos de Efraim, segundo as suas famílias,' },
      { v: 9, en: 'together with the cities which were set apart for the children of Ephraim in the middle of the inheritance of the children of Manasseh, all the cities with their villages.', pt: 'juntamente com as cidades que se separaram para os filhos de Efraim no meio da herança dos filhos de Manassés, todas as cidades e suas aldeias.' },
      { v: 10, en: 'They didn’t drive out the Canaanites who lived in Gezer; but the Canaanites dwell in the territory of Ephraim to this day, and have become servants to do forced labor.', pt: 'E não expulsaram aos cananeus que habitavam em Gezer; mas os cananeus ficaram habitando no meio dos efraimitas até o dia de hoje, e tornaram-se servos, sujeitos ao trabalho forçado.' },
    ],
    17: [
      { v: 1, en: 'This was the lot for the tribe of Manasseh, for he was the firstborn of Joseph. As for Machir the firstborn of Manasseh, the father of Gilead, because he was a man of war, therefore he had Gilead and Bashan.', pt: 'Também coube sorte à tribo de Manassés, porquanto era o primogênito de José. Quanto a Maquir, o primogênito de Manassés, pai de Gileade, porquanto era homem de guerra, obtivera Gileade e Basã.' },
      { v: 2, en: 'So this was for the rest of the children of Manasseh according to their families: for the children of Abiezer, for the children of Helek, for the children of Asriel, for the children of Shechem, for the children of Hepher, and for the children of Shemida. These were the male children of Manasseh the son of Joseph according to their families.', pt: 'Também os outros filhos de Manassés tiveram a sua parte, segundo as suas famílias, a saber: os filhos de Abiezer, os filhos de Heleque, os filhos de Asriel, os filhos de Siquém, os filhos de Hefer, e os filhos de semida. Esses são os filhos de Manassés, filho de José, segundo as suas famílias.' },
      { v: 3, en: 'But Zelophehad, the son of Hepher, the son of Gilead, the son of Machir, the son of Manasseh, had no sons, but daughters. These are the names of his daughters: Mahlah, Noah, Hoglah, Milcah, and Tirzah.', pt: 'Zelofeade, porém, filho de Hefer, filho de Gileade, filho de Maquir, filho de Manassés, não teve filhos, mas só filhas; e estes são os nomes de suas filhas: Macla, Noa, Hogla, Milca e Tirza.' },
      { v: 4, en: 'They came to Eleazar the priest, and to Joshua the son of Nun, and to the princes, saying, “Yahweh commanded Moses to give us an inheritance among our brothers.” Therefore according to the commandment of Yahweh he gave them an inheritance among the brothers of their father.', pt: 'Estas, pois, se apresentaram diante de Eleazar, o sacerdote, e diante de Josué, filho de Num, e diante dos príncipes, dizendo: O Senhor ordenou a Moisés que se nos desse herança no meio de nossos irmãos. Pelo que se lhes deu herança no meio dos irmãos de seu pai, conforme a ordem do Senhor.' },
      { v: 5, en: 'Ten parts fell to Manasseh, besides the land of Gilead and Bashan, which is beyond the Jordan;', pt: 'E couberam a Manassés dez quinhões, afora a terra de Gileade e Basã, que está além do Jordão;' },
      { v: 6, en: 'because the daughters of Manasseh had an inheritance among his sons. The land of Gilead belonged to the rest of the sons of Manasseh.', pt: 'porque as filhas de Manassés possuíram herança entre os filhos dele; e a terra de Gileade coube aos outros filhos de Manassés.' },
      { v: 7, en: 'The border of Manasseh was from Asher to Michmethath, which is before Shechem. The border went along to the right hand, to the inhabitants of En Tappuah.', pt: 'Ora, o termo de Manassés vai desde Aser até Micmetá, que está defronte de Siquém; e estende-se pela direita até os moradores de En-Tapua.' },
      { v: 8, en: 'The land of Tappuah belonged to Manasseh; but Tappuah on the border of Manasseh belonged to the children of Ephraim.', pt: 'A terra de Tapua ficou pertencendo a Manassés; porém Tapua, junto ao termo de Manassés, pertencia aos filhos de Efraim .' },
      { v: 9, en: 'The border went down to the brook of Kanah, southward of the brook. These cities belonged to Ephraim among the cities of Manasseh. The border of Manasseh was on the north side of the brook, and ended at the sea.', pt: 'Então desce este termo ao ribeiro de Caná; a Efraim couberam as cidades ao sul do ribeiro no meio das cidades de Manassés; o termo de Manassés está ao norte do ribeiro, e vai até o mar.' },
      { v: 10, en: 'Southward it was Ephraim’s, and northward it was Manasseh’s, and the sea was his border. They reached to Asher on the north, and to Issachar on the east.', pt: 'Ao sul a terra é de Efraim, e ao norte de Manassés, sendo o mar o seu termo. Estendem-se ao norte até Aser, e ao oriente até Issacar' },
      { v: 11, en: 'Manasseh had three heights in Issachar, in Asher Beth Shean and its towns, and Ibleam and its towns, and the inhabitants of Dor and its towns, and the inhabitants of Endor and its towns, and the inhabitants of Taanach and its towns, and the inhabitants of Megiddo and its towns.', pt: 'Porque em Issacar e em Aser couberam a Manassés Bete-Seã e suas vilas, Ibleão e suas vilas, os habitantes de Dor e suas vilas, os habitantes de En-Dor e suas vilas, os habitantes de Taanaque e suas vilas, e os habitantes de Megido e suas vilas, com os seus três outeiros.' },
      { v: 12, en: 'Yet the children of Manasseh couldn’t drive out the inhabitants of those cities; but the Canaanites would dwell in that land.', pt: 'Contudo os filhos de Manassés não puderam expulsar os habitantes daquelas cidades, porquanto os cananeus persistiram em habitar naquela terra.' },
      { v: 13, en: 'When the children of Israel had grown strong, they put the Canaanites to forced labor, and didn’t utterly drive them out.', pt: 'Mas quando os filhos de Israel se tornaram fortes, sujeitaram os cananeus a trabalhos forçados, porém não os expulsaram de todo.' },
      { v: 14, en: 'The children of Joseph spoke to Joshua, saying, “Why have you given me just one lot and one part for an inheritance, since we are a numerous people, because Yahweh has blessed us so far?”', pt: 'Então os filhos de José falaram a Josué, dizendo: Por que me deste por herança apenas uma sorte e um quinhão, sendo eu um povo numeroso, porquanto o Senhor até aqui me tem abençoado?' },
      { v: 15, en: 'Joshua said to them, “If you are a numerous people, go up to the forest, and clear land for yourself there in the land of the Perizzites and of the Rephaim; since the hill country of Ephraim is too narrow for you.”', pt: 'Respondeu-lhes Josué: Se és povo numeroso, sobe ao bosque, e corta para ti lugar ali na terra dos perizeus e dos refains, desde que a região montanhosa de Efraim te é estreita demais.' },
      { v: 16, en: 'The children of Joseph said, “The hill country is not enough for us. All the Canaanites who dwell in the land of the valley have chariots of iron, both those who are in Beth Shean and its towns, and those who are in the valley of Jezreel.”', pt: 'Tornaram os filhos de José: A região montanhosa não nos bastaria; além disso todos os cananeus que habitam na terra do vale têm carros de ferro, tanto os de Bete-Seã e das suas vilas, como os que estão no vale de Jizreel.' },
      { v: 17, en: 'Joshua spoke to the house of Joseph, that is, to Ephraim and to Manasseh, saying, “You are a numerous people, and have great power. You shall not have one lot only;', pt: 'Então Josué falou a casa de José, isto é, a Efraim e a Manassés, dizendo: Povo numeroso és tu, e tens grande força; não terás uma sorte apenas;' },
      { v: 18, en: 'but the hill country shall be yours. Although it is a forest, you shall cut it down, and it’s farthest extent shall be yours; for you shall drive out the Canaanites, though they have chariots of iron, and though they are strong.”', pt: 'porém a região montanhosa será tua; ainda que é bosque, cortá-lo-ás, e as suas extremidades serão tuas; porque expulsarás os cananeus, não obstante terem eles carros de ferro e serem fortes:' },
    ],
    18: [
      { v: 1, en: 'The whole congregation of the children of Israel assembled themselves together at Shiloh, and set up the Tent of Meeting there. The land was subdued before them.', pt: 'Ora, toda a congregação dos filhos de Israel, havendo conquistado a terra, se reuniu em Siló, e ali armou a tenda da revelação.' },
      { v: 2, en: 'Seven tribes remained among the children of Israel, which had not yet divided their inheritance.', pt: 'E dentre os filhos de Israel restavam sete tribos que ainda não tinham repartido a sua herança.' },
      { v: 3, en: 'Joshua said to the children of Israel, “How long will you neglect to go in to possess the land, which Yahweh, the God of your fathers, has given you?', pt: 'Disse, pois, Josué aos filhos de Israel: Até quando sereis remissos em entrardes para possuir a terra que o Senhor Deus de vossos pais vos deu?' },
      { v: 4, en: 'Appoint for yourselves three men from each tribe. I will send them, and they shall arise, walk through the land, and describe it according to their inheritance; and they shall come to me.', pt: 'Designai vós a três homens de cada tribo, e eu os enviarei; e eles sairão a percorrer a terra, e a demarcarão segundo as suas heranças, e voltarão a ter comigo.' },
      { v: 5, en: 'They shall divide it into seven portions. Judah shall live in his borders on the south, and the house of Joseph shall live in their borders on the north.', pt: 'Reparti-la-ão em sete partes; Judá ficará no seu termo da banda do sul; e a casa de José ficará no seu termo da banda do norte.' },
      { v: 6, en: 'You shall survey the land into seven parts, and bring the description here to me; and I will cast lots for you here before Yahweh our God.', pt: 'Sim, vós demarcareis a terra em sete partes, e me trareis a mim a sua descrição; eu vos lançarei as sortes aqui perante o Senhor nosso Deus.' },
      { v: 7, en: 'However, the Levites have no portion among you; for the priesthood of Yahweh is their inheritance. Gad, Reuben, and the half-tribe of Manasseh have received their inheritance east of the Jordan, which Moses the servant of Yahweh gave them.”', pt: 'Porquanto os levitas não têm parte no meio de vós, porque o sacerdócio do Senhor é a sua herança; e Gade, Rúben e a meia tribo de Manassés já receberam a sua herança além do Jordão para o oriente, a qual lhes deu Moisés, servo do Senhor.' },
      { v: 8, en: 'The men arose and went. Joshua commanded those who went to survey the land, saying, “Go walk through the land, survey it, and come again to me. I will cast lots for you here before Yahweh in Shiloh.”', pt: 'Então aqueles homens se aprontaram para saírem; e Josué deu ordem a esses que iam demarcar a terra, dizendo: Ide, percorrei a terra, e demarcai-a; então vinde ter comigo; e aqui em Siló vos lançarei as sortes perante o Senhor.' },
      { v: 9, en: 'The men went and passed through the land, and surveyed it by cities into seven portions in a book. They came to Joshua to the camp at Shiloh.', pt: 'Foram, pois, aqueles homens e, passando pela terra, a demarcaram em sete partes segundo as suas cidades, descrevendo-a num livro; e voltaram a Josué, ao arraial em Siló.' },
      { v: 10, en: 'Joshua cast lots for them in Shiloh before Yahweh. There Joshua divided the land to the children of Israel according to their divisions.', pt: 'Então Josué lhes lançou as sortes em Siló, perante o Senhor; e ali repartiu Josué a terra entre os filhos de Israel, conforme as suas divisões.' },
      { v: 11, en: 'The lot of the tribe of the children of Benjamin came up according to their families. The border of their lot went out between the children of Judah and the children of Joseph.', pt: 'E surgiu a sorte da tribo dos filhos de Benjamim, segundo as suas famílias, e coube-lhe o território da sua sorte entre os filhos de Judá e os filhos de José.' },
      { v: 12, en: 'Their border on the north quarter was from the Jordan. The border went up to the side of Jericho on the north, and went up through the hill country westward. It ended at the wilderness of Beth Aven.', pt: 'O seu termo ao norte, partindo do Jordão, vai até a saliência ao norte de Jericó e, subindo pela região montanhosa para o ocidente, chega até o deserto de Bete-Áven;' },
      { v: 13, en: 'The border passed along from there to Luz, to the side of Luz (also called Bethel), southward. The border went down to Ataroth Addar, by the mountain that lies on the south of Beth Horon the lower.', pt: 'dali passa até Luz, ao lado de Luz (que é Betel) para o sul; e desce a Atarote-Adar, junto ao monte que está ao sul de Bete-Horom de baixo;' },
      { v: 14, en: 'The border extended, and turned around on the west quarter southward, from the mountain that lies before Beth Horon southward; and ended at Kiriath Baal (also called Kiriath Jearim), a city of the children of Judah. This was the west quarter.', pt: 'e vai este termo virando, pelo lado ocidental, para o sul desde o monte que está defronte de Bete-Horom; e chega a Quiriate-Baal (que é Quiriate-Jearim), cidade dos filhos de Judá. Esta é a sua fronteira ocidental.' },
      { v: 15, en: 'The south quarter was from the farthest part of Kiriath Jearim. The border went out westward, and went out to the spring of the waters of Nephtoah.', pt: 'A sua fronteira meridional começa desde a extremidade de Quiriate-Jearim, e dali se estende até Efrom, até a fonte das águas de Neftoa;' },
      { v: 16, en: 'The border went down to the farthest part of the mountain that lies before the valley of the son of Hinnom, which is in the valley of Rephaim northward. It went down to the valley of Hinnom, to the side of the Jebusite southward, and went down to En Rogel.', pt: 'desce à extremidade do monte que está fronteiro ao vale de Ben-Hinom, que está no vale dos refains, para o norte; também desce ao vale de Hinom da banda dos jebuseus para o sul; e desce ainda até En-Rogel;' },
      { v: 17, en: 'It extended northward, went out at En Shemesh, and went out to Geliloth, which is over against the ascent of Adummim. It went down to the stone of Bohan the son of Reuben.', pt: 'passando para o norte, chega a En-Semes, e dali sai a Gelilote, que está defronte da subida de Adumim; desce à pedra de Boã, filho de Rúben;' },
      { v: 18, en: 'It passed along to the side over against the Arabah northward, and went down to the Arabah.', pt: 'segue para o norte, margeando a Arabá, e desce ainda até a Arabá;' },
      { v: 19, en: 'The border passed along to the side of Beth Hoglah northward; and the border ended at the north bay of the Salt Sea, at the south end of the Jordan. This was the south border.', pt: 'segue dali para o norte, ladeando Bete-Hogla; e os seus extremos chegam à baía setentrional do Mar Salgado, na extremidade meridional do Jordão. Esse é o termo do sul.' },
      { v: 20, en: 'The Jordan was its border on the east quarter. This was the inheritance of the children of Benjamin, by the borders around it, according to their families.', pt: 'E o Jordão é o seu termo oriental. Essa é a herança dos filhos de Benjamim, pelos seus termos ao redor, segundo as suas famílias.' },
      { v: 21, en: 'Now the cities of the tribe of the children of Benjamin according to their families were Jericho, Beth Hoglah, Emek Keziz,', pt: 'Ora, as cidades da tribo dos filhos de Benjamim, segundo as suas famílias, são: Jericó, Bete-Hogla, Emeque-Queziz,' },
      { v: 22, en: 'Beth Arabah, Zemaraim, Bethel,', pt: 'Bete-Arabá, Zemaraim, Betel,' },
      { v: 23, en: 'Avvim, Parah, Ophrah,', pt: 'Avim, Pará, Ofra,' },
      { v: 24, en: 'Chephar Ammoni, Ophni, and Geba; twelve cities with their villages.', pt: 'Quefar-Ha-Amonai. Ofni e Gaba; doze cidades e as suas aldeias.' },
      { v: 25, en: 'Gibeon, Ramah, Beeroth,', pt: 'Gibeão, Ramá, Beerote,' },
      { v: 26, en: 'Mizpeh, Chephirah, Mozah,', pt: 'Mizpe, Cefira, Moza,' },
      { v: 27, en: 'Rekem, Irpeel, Taralah,', pt: 'Requem, Irpeel, Tarala,' },
      { v: 28, en: 'Zelah, Eleph, the Jebusite (also called Jerusalem), Gibeath, and Kiriath; fourteen cities with their villages. This is the inheritance of the children of Benjamin according to their families.', pt: 'Zela, Elefe e Jebus (esta é Jerusalém), Gibeá e Quiriate; catorze cidades e as suas aldeias. Essa é a herança dos filhos de Benjamim, segundo as suas familias.' },
    ],
    19: [
      { v: 1, en: 'The second lot came out for Simeon, even for the tribe of the children of Simeon according to their families. Their inheritance was in the middle of the inheritance of the children of Judah.', pt: 'Saiu a segunda sorte a Simeão, isto é, à tribo dos filhos de Simeão, segundo as suas famílias; e foi a sua herança no meio da herança dos filhos de Judá.' },
      { v: 2, en: 'They had for their inheritance Beersheba (or Sheba), Moladah,', pt: 'Tiveram, pois, na sua herança: Berseba, Seba, Molada,' },
      { v: 3, en: 'Hazar Shual, Balah, Ezem,', pt: 'Hazar-Sual, Balá, Ezem,' },
      { v: 4, en: 'Eltolad, Bethul, Hormah,', pt: 'Eltolade, Betul, Horma,' },
      { v: 5, en: 'Ziklag, Beth Marcaboth, Hazar Susah,', pt: 'Ziclague, Bete-Marcabote, Hazar-Susa,' },
      { v: 6, en: 'Beth Lebaoth, and Sharuhen; thirteen cities with their villages;', pt: 'Bete-Lebaote e Saruém; treze cidades e as suas aldeias.' },
      { v: 7, en: 'Ain, Rimmon, Ether, and Ashan; four cities with their villages;', pt: 'Aim, Rimom, Eter e Asã; quatro cidades e as suas aldeias;' },
      { v: 8, en: 'and all the villages that were around these cities to Baalath Beer, Ramah of the South. This is the inheritance of the tribe of the children of Simeon according to their families.', pt: 'e todas as aldeias que havia em redor dessas cidades, até Baalate-Ber, que é Ramá do sul. Essa é a herança da tribo dos filhos de Simeão, segundo as suas famílias.' },
      { v: 9, en: 'Out of the part of the children of Judah was the inheritance of the children of Simeon; for the portion of the children of Judah was too much for them. Therefore the children of Simeon had inheritance in the middle of their inheritance.', pt: 'Ora, do quinhão dos filhos de Judá tirou-se a herança dos filhos de Simeão, porquanto a porção dos filhos de Judá era demasiadamente grande para eles; pelo que os filhos de Simeão receberam herança no meio da herança deles.' },
      { v: 10, en: 'The third lot came up for the children of Zebulun according to their families. The border of their inheritance was to Sarid.', pt: 'Surgiu a terceira sorte aos filhos de Zebulom, segundo as suas familias. Vai o termo da sua herança até Saride;' },
      { v: 11, en: 'Their border went up westward, even to Maralah, and reached to Dabbesheth. It reached to the brook that is before Jokneam.', pt: 'sobe para o ocidente até Marala, estende-se até Dabesete, e chega até o ribeiro que está defronte de Jocneão;' },
      { v: 12, en: 'It turned from Sarid eastward toward the sunrise to the border of Chisloth Tabor. It went out to Daberath, and went up to Japhia.', pt: 'de Saride vira para o oriente, para o nascente do sol, até o termo de Quislote-Tabor, estende-se a Daberate, e vai subindo a Jafia;' },
      { v: 13, en: 'From there it passed along eastward to Gath Hepher, to Ethkazin; and it went out at Rimmon which stretches to Neah.', pt: 'dali passa para o oriente a Gate-Hefer, a Ete-Cazim, chegando a Rimom-Metoar e virando-se para Neá;' },
      { v: 14, en: 'The border turned around it on the north to Hannathon; and it ended at the valley of Iphtah El;', pt: 'vira ao norte para Hanatom, e chega ao vale de Iftael;' },
      { v: 15, en: 'Kattath, Nahalal, Shimron, Idalah, and Bethlehem: twelve cities with their villages.', pt: 'e Catate, Naalal, Sinrom, Idala e Belém; doze cidades e as suas aldeias.' },
      { v: 16, en: 'This is the inheritance of the children of Zebulun according to their families, these cities with their villages.', pt: 'Essa é a herança dos filhos de Zebulom, segundo as suas famílias, essas cidades e as suas aldeias.' },
      { v: 17, en: 'The fourth lot came out for Issachar, even for the children of Issachar according to their families.', pt: 'A quarta sorte saiu aos filhos de Issacar, segundo as suas famílias.' },
      { v: 18, en: 'Their border was to Jezreel, Chesulloth, Shunem,', pt: 'Vai o seu termo até Jizreel, Quesulote, Suném.' },
      { v: 19, en: 'Hapharaim, Shion, Anaharath,', pt: 'Hafaraim, Siom, Anaarate,' },
      { v: 20, en: 'Rabbith, Kishion, Ebez,', pt: 'Rabite, Quisiom, Abes,' },
      { v: 21, en: 'Remeth, Engannim, En Haddah, and Beth Pazzez.', pt: 'Remete, En-Ganim, En-Hada e Bete-Pazez,' },
      { v: 22, en: 'The border reached to Tabor, Shahazumah, and Beth Shemesh. Their border ended at the Jordan: sixteen cities with their villages.', pt: 'estendendo-se este termo até Tabor, Saazima e Bete-Semes; e vai terminar no Jordão; dezesseis cidades e as suas aldeias.' },
      { v: 23, en: 'This is the inheritance of the tribe of the children of Issachar according to their families, the cities with their villages.', pt: 'Essa é a herança da tribo dos filhos de Issacar, segundo as suas famílias, essas cidades e as suas aldeias.' },
      { v: 24, en: 'The fifth lot came out for the tribe of the children of Asher according to their families.', pt: 'Saiu a quinta sorte à tribo dos filhos de Aser, segundo as suas famílias.' },
      { v: 25, en: 'Their border was Helkath, Hali, Beten, Achshaph,', pt: 'O seu termo inclui Helcate, Hali, Bétem, Acsafe,' },
      { v: 26, en: 'Allammelech, Amad, Mishal. It reached to Carmel westward, and to Shihorlibnath.', pt: 'Alameleque, Amade e Misal; estende-se para o ocidente até Carmelo e Sior-Libnate;' },
      { v: 27, en: 'It turned toward the sunrise to Beth Dagon, and reached to Zebulun, and to the valley of Iphtah El northward to Beth Emek and Neiel. It went out to Cabul on the left hand,', pt: 'vira para o nascente do sol a Bete-Dagom; chega a Zebulom e ao vale de Iftael para o norte, até Bete-Emeque e Neiel; estende-se pela esquerda até Cabul,' },
      { v: 28, en: 'and Ebron, Rehob, Hammon, and Kanah, even to great Sidon.', pt: 'Ebrom, Reobe, Hamom e Caná, até a grande Sidom;' },
      { v: 29, en: 'The border turned to Ramah, to the fortified city of Tyre; and the border turned to Hosah. It ended at the sea by the region of Achzib;', pt: 'vira para Ramá, e para a cidade fortificada de Tiro, desviando-se então para Hosa, donde vai até o mar; Maalabe, Aczibe,' },
      { v: 30, en: 'Ummah also, and Aphek, and Rehob: twenty-two cities with their villages.', pt: 'Umá, Afeca e Reobe; ao todo, vinte e duas cidades e as suas aldeias.' },
      { v: 31, en: 'This is the inheritance of the tribe of the children of Asher according to their families, these cities with their villages.', pt: 'Essa é a herança da tribo dos filhos de Aser, segundo as suas famílias, essas cidades e as suas aldeias.' },
      { v: 32, en: 'The sixth lot came out for the children of Naphtali, even for the children of Naphtali according to their families.', pt: 'Saiu a sexta sorte aos filhos de Naftali, segundo as suas famílias.' },
      { v: 33, en: 'Their border was from Heleph, from the oak in Zaanannim, Adami-nekeb, and Jabneel, to Lakkum. It ended at the Jordan.', pt: 'Vai o seu termo desde Helefe e desde o carvalho em Zaananim, e Adâmi-Nequebe e Jabneel, até Lacum, terminando no Jordão;' },
      { v: 34, en: 'The border turned westward to Aznoth Tabor, and went out from there to Hukkok. It reached to Zebulun on the south, and reached to Asher on the west, and to Judah at the Jordan toward the sunrise.', pt: 'vira para o ocidente até Aznote-Tabor, e dali passa a Hucoque; chega a Zebulom, da banda do sul, e a Aser, da banda do ocidente, e a Judá, à margem do Jordão, para o oriente.' },
      { v: 35, en: 'The fortified cities were Ziddim, Zer, Hammath, Rakkath, Chinnereth,', pt: 'E são as cidades fortificadas: Zidim, Zer, Hamate, Racate, Quinerete,' },
      { v: 36, en: 'Adamah, Ramah, Hazor,', pt: 'Adama, Ramá, Hazor,' },
      { v: 37, en: 'Kedesh, Edrei, En Hazor,', pt: 'Quedes, Edrei, En-Hazor,' },
      { v: 38, en: 'Iron, Migdal El, Horem, Beth Anath, and Beth Shemesh; nineteen cities with their villages.', pt: 'Irom, Migdal-El, Horem, Bete-Anate e Bete-Semes; dezenove cidades e as suas aldeias.' },
      { v: 39, en: 'This is the inheritance of the tribe of the children of Naphtali according to their families, the cities with their villages.', pt: 'Essa é a herança da tribo dos filhos de Naftali, segundo as suas famílias, essas cidades e as suas aldeias.' },
      { v: 40, en: 'The seventh lot came out for the tribe of the children of Dan according to their families.', pt: 'A sétima sorte saiu à tribo dos filhos de Dã, segundo as suas famílias.' },
      { v: 41, en: 'The border of their inheritance was Zorah, Eshtaol, Irshemesh,', pt: 'O termo da sua herança inclui: Zorá, Estaol, Ir-Semes,' },
      { v: 42, en: 'Shaalabbin, Aijalon, Ithlah,', pt: 'Saalabim, Aijalom, Itla,' },
      { v: 43, en: 'Elon, Timnah, Ekron,', pt: 'Elom, Timnate, Ecrom,' },
      { v: 44, en: 'Eltekeh, Gibbethon, Baalath,', pt: 'Elteque, Gibetom, Baalate,' },
      { v: 45, en: 'Jehud, Bene Berak, Gath Rimmon,', pt: 'Jeúde, Bene-Beraque, Gate-Rimom,' },
      { v: 46, en: 'Me Jarkon, and Rakkon, with the border over against Joppa.', pt: 'Me-Jarcom e Racom, com o território defronte de Jope.' },
      { v: 47, en: 'The border of the children of Dan went out beyond them; for the children of Dan went up and fought against Leshem, and took it, and struck it with the edge of the sword, and possessed it, and lived therein, and called Leshem, Dan, after the name of Dan their forefather.', pt: 'Saiu, porém, pequena o território dos filhos de Dã; pelo que os filhos de Dã subiram, pelejaram contra Lesem e a tomaram; feriram-na ao fio da espada, tomaram posse dela e habitaram-na; e a Lesem chamaram Dã, conforme o nome de Dã, seu pai.' },
      { v: 48, en: 'This is the inheritance of the tribe of the children of Dan according to their families, these cities with their villages.', pt: 'Essa é a herança da tribo dos filhos de Dã, segundo as suas famílias, essas cidades e as suas aldeias.' },
      { v: 49, en: 'So they finished distributing the land for inheritance by its borders. The children of Israel gave an inheritance to Joshua the son of Nun among them.', pt: 'Tendo os filhos de Israel acabado de repartir a terra em herança segundo os seus termos, deram a Josué, filho de Num, herança no meio deles.' },
      { v: 50, en: 'According to Yahweh’s commandment, they gave him the city which he asked, even Timnathserah in the hill country of Ephraim; and he built the city, and lived there.', pt: 'Segundo a ordem do Senhor lhe deram a cidade que pediu, Timnate-Sera, na região montanhosa de Efraim; e ele reedificou a cidade, e habitou nela.' },
      { v: 51, en: 'These are the inheritances, which Eleazar the priest, Joshua the son of Nun, and the heads of the fathers’ houses of the tribes of the children of Israel, distributed for inheritance by lot in Shiloh before Yahweh, at the door of the Tent of Meeting. So they finished dividing the land.', pt: 'Essas são as heranças que Eleazar, o sacerdote, e Josué, filho de Num, e os cabeças das casas paternas nas tribos dos filhos de Israel repartiram em herança por sorte em Siló, perante o Senhor, à porta da tenda da revelação. E assim acabaram de repartir a terra.' },
    ],
    20: [
      { v: 1, en: 'Yahweh spoke to Joshua, saying,', pt: 'Falou mais o Senhor a Josué:' },
      { v: 2, en: '“Speak to the children of Israel, saying, ‘Assign the cities of refuge, of which I spoke to you by Moses,', pt: 'Dize aos filhos de Israel: Designai para vós as cidades de refúgio, de que vos falei por intermédio de Moisés,' },
      { v: 3, en: 'that the man slayer who kills any person accidentally or unintentionally may flee there. They shall be to you for a refuge from the avenger of blood.', pt: 'a fim de que fuja para ali o homicida, que tiver matado alguma pessoa involuntariamente, e não com intento; e elas vos servirão de refúgio contra o vingador do sangue.' },
      { v: 4, en: 'He shall flee to one of those cities, and shall stand at the entrance of the gate of the city, and declare his case in the ears of the elders of that city. They shall take him into the city with them, and give him a place, that he may live among them.', pt: 'Fugindo ele para uma dessas cidades, apresentar-se-á à porta da mesma, e exporá a sua causa aos anciãos da tal cidade; então eles o acolherão ali e lhe darão lugar, para que habite com eles.' },
      { v: 5, en: 'If the avenger of blood pursues him, then they shall not deliver up the man slayer into his hand; because he struck his neighbor unintentionally, and didn’t hate him before.', pt: 'Se, pois, o vingador do sangue o perseguir, não lhe entregarão o homicida, porquanto feriu a seu próximo sem intenção e sem odiá-lo dantes.' },
      { v: 6, en: 'He shall dwell in that city until he stands before the congregation for judgment, until the death of the high priest that shall be in those days. Then the man slayer shall return, and come to his own city, and to his own house, to the city he fled from.’”', pt: 'E habitará nessa cidade até que compareça em juizo perante a congregação, até que morra o sumo sacerdote que houver naqueles dias; então o homicida voltará, e virá à sua cidade e à sua casa, à cidade donde tiver fugido.' },
      { v: 7, en: 'They set apart Kedesh in Galilee in the hill country of Naphtali, Shechem in the hill country of Ephraim, and Kiriath Arba (also called Hebron) in the hill country of Judah.', pt: 'Então designaram a Quedes na Galiléia, na região montanhosa de Naftali, a Siquém na região montanhosa de Efraim, e a Quiriate-Arba (esta é Hebrom) na região montanhosa de Judá.' },
      { v: 8, en: 'Beyond the Jordan at Jericho eastward, they assigned Bezer in the wilderness in the plain out of the tribe of Reuben, Ramoth in Gilead out of the tribe of Gad, and Golan in Bashan out of the tribe of Manasseh.', pt: 'E, além do Jordão na altura de Jericó para o oriente, designaram a Bezer, no deserto, no planalto da tribo de Rúben a Ramote, em Gileade, da tribo de Gade, e a Golã, em Basã, da tribo de Manassés.' },
      { v: 9, en: 'These were the appointed cities for all the children of Israel, and for the alien who lives among them, that whoever kills any person unintentionally might flee there, and not die by the hand of the avenger of blood, until he stands trial before the congregation.', pt: 'Foram estas as cidades designadas para todos os filhos de Israel, e para o estrangeiro que peregrinasse entre eles, para que se acolhesse a elas todo aquele que matasse alguma pessoa involuntariamente, para que não morresse às mãos do vingador do sangue, até se apresentar perante a congregaçao.' },
    ],
    21: [
      { v: 1, en: 'Then the heads of fathers’ houses of the Levites came near to Eleazar the priest, and to Joshua the son of Nun, and to the heads of fathers’ houses of the tribes of the children of Israel.', pt: 'Então os cabeças das casas paternas dos levitas chegaram a Eleazar, o sacerdote, e a Josué, filho de Num, e aos cabeças das casas paternas nas tribos dos filhos de Israel,' },
      { v: 2, en: 'They spoke to them at Shiloh in the land of Canaan, saying, “Yahweh commanded through Moses to give us cities to dwell in, with their suburbs for our livestock.”', pt: 'em Siló, na terra de Canaã, e lhes falaram, dizendo: O Senhor ordenou, por intermédio de Moisés, que se nos dessem cidades em que habitássemos, e os seus arrabaldes para os nossos animais.' },
      { v: 3, en: 'The children of Israel gave to the Levites out of their inheritance, according to the commandment of Yahweh, these cities with their suburbs.', pt: 'Pelo que os filhos de Israel deram aos levitas, da sua herança, conforme a ordem do Senhor, as seguintes cidades e seus arrabaldes.' },
      { v: 4, en: 'The lot came out for the families of the Kohathites. The children of Aaron the priest, who were of the Levites, had thirteen cities by lot out of the tribe of Judah, out of the tribe of the Simeonites, and out of the tribe of Benjamin.', pt: 'Saiu, pois, a sorte às famílias dos coatitas; e aos filhos de Arão, o sacerdote, que eram dos levitas, caíram por sorte, da tribo de Judá, da tribo de Simeão e da tribo de Benjamim, treze cidades;' },
      { v: 5, en: 'The rest of the children of Kohath had ten cities by lot out of the families of the tribe of Ephraim, out of the tribe of Dan, and out of the half-tribe of Manasseh.', pt: 'aos outros filhos de Coate caíram por sorte, das famílias da tribo de Efraim, da tribo de Dã e da meia tribo de Manassés, dez cidades;' },
      { v: 6, en: 'The children of Gershon had thirteen cities by lot out of the families of the tribe of Issachar, out of the tribe of Asher, out of the tribe of Naphtali, and out of the half-tribe of Manasseh in Bashan.', pt: 'aos filhos de Gérson caíram por sorte, das famílias da tribo de Issacar, da tribo de Aser, da tribo de Naftali e da meia tribo de Manassés em Basã, treze cidades;' },
      { v: 7, en: 'The children of Merari according to their families had twelve cities out of the tribe of Reuben, out of the tribe of Gad, and out of the tribe of Zebulun.', pt: 'e aos filhos de Merári, segundo as suas familias, da tribo de Rúben, da tribo de Gade e da tribo de Zebulom, doze cidades.' },
      { v: 8, en: 'The children of Israel gave these cities with their suburbs by lot to the Levites, as Yahweh commanded by Moses.', pt: 'Assim deram os filhos de Israel aos levitas estas cidades e seus arrabaldes por sorte, como o Senhor ordenara por intermédio de Moisés.' },
      { v: 9, en: 'They gave out of the tribe of the children of Judah, and out of the tribe of the children of Simeon, these cities which are mentioned by name:', pt: 'Ora, deram, da tribo dos filhos de Judá e da tribo dos filhos de Simeão, estas cidades que por nome vão aqui mencionadas,' },
      { v: 10, en: 'and they were for the children of Aaron, of the families of the Kohathites, who were of the children of Levi; for theirs was the first lot.', pt: 'as quais passaram a pertencer aos filhos de Arão, sendo estes das famílias dos coatitas e estes, por sua vez, dos filhos de Levi; porquanto lhes caiu a primeira sorte.' },
      { v: 11, en: 'They gave them Kiriath Arba, named after the father of Anak (also called Hebron), in the hill country of Judah, with its suburbs around it.', pt: 'Assim lhes deram Quiriate-Arba, que é Hebrom, na região montanhosa de Judá, e seus arrabaldes em redor (Arba era o pai de Anaque).' },
      { v: 12, en: 'But they gave the fields of the city and its villages to Caleb the son of Jephunneh for his possession.', pt: 'Mas deram o campo da cidade e suas aldeias a Calebe, filho de Jefoné, por sua possessão.' },
      { v: 13, en: 'To the children of Aaron the priest they gave Hebron with its suburbs, the city of refuge for the man slayer, Libnah with its suburbs,', pt: 'Aos filhos de Arão, o sacerdote, deram Hebrom, cidade de refúgio do homicida, e seus arrabaldes, Libna e seus arrabaldes,' },
      { v: 14, en: 'Jattir with its suburbs, Eshtemoa with its suburbs,', pt: 'Jatir e seus arrabaldes, Estemoa e seus arrabaldes,' },
      { v: 15, en: 'Holon with its suburbs, Debir with its suburbs,', pt: 'Holom e seus arrabaldes, Debir e seus arrabaldes,' },
      { v: 16, en: 'Ain with its suburbs, Juttah with its suburbs, and Beth Shemesh with its suburbs: nine cities out of those two tribes.', pt: 'Aim e seus arrabaldes, Jutá e seus arrabaldes, Bete-Semes e seus arrabaldes; nove cidades dessas duas tribos.' },
      { v: 17, en: 'Out of the tribe of Benjamin, Gibeon with its suburbs, Geba with its suburbs,', pt: 'E da tribo de Benjamim, Gibeão e seus arrabaldes, Geba e seus arrabaldes,' },
      { v: 18, en: 'Anathoth with its suburbs, and Almon with its suburbs: four cities.', pt: 'Anatote e seus arrabaldes, Almom e seus arrabaldes; quatro cidades.' },
      { v: 19, en: 'All the cities of the children of Aaron, the priests, were thirteen cities with their suburbs.', pt: 'Todas as cidades dos sacerdotes, filhos de Arão, foram treze cidades e seus arrabaldes.' },
      { v: 20, en: 'The families of the children of Kohath, the Levites, even the rest of the children of Kohath, had the cities of their lot out of the tribe of Ephraim.', pt: 'As famílias dos filhos de Coate, levitas, isto é, os demais filhos de Coate, receberam as cidades da sua sorte; da tribo de Efraim' },
      { v: 21, en: 'They gave them Shechem with its suburbs in the hill country of Ephraim, the city of refuge for the man slayer, and Gezer with its suburbs,', pt: 'deram-lhes Siquém, cidade de refúgio do homicida, e seus arrabaldes, na região montanhosa de Efraim, Gezer e seus arrabaldes,' },
      { v: 22, en: 'Kibzaim with its suburbs, and Beth Horon with its suburbs: four cities.', pt: 'Quibzaim e seus arrabaldes, Bete-Horom e seus arrabaldes; quatro cidades.' },
      { v: 23, en: 'Out of the tribe of Dan, Elteke with its suburbs, Gibbethon with its suburbs,', pt: 'E da tribo de Dã, Elteque e seus arrabaldes, Gibetom e seus arrabaldes,' },
      { v: 24, en: 'Aijalon with its suburbs, Gath Rimmon with its suburbs: four cities.', pt: 'Aijalom e seus arrabaldes, Gate-Rimon e seus arrabaldes; quatro cidades.' },
      { v: 25, en: 'Out of the half-tribe of Manasseh, Taanach with its suburbs, and Gath Rimmon with its suburbs: two cities.', pt: 'E da meia tribo de Manassés, Taanaque e seus arrabaldes, e Gate-Rimon e seus arrabaldes; duas cidades.' },
      { v: 26, en: 'All the cities of the families of the rest of the children of Kohath were ten with their suburbs.', pt: 'As famílias dos demais filhos de Coate tiveram ao todo dez cidades e seus arrabaldes.' },
      { v: 27, en: 'They gave to the children of Gershon, of the families of the Levites, out of the half-tribe of Manasseh Golan in Bashan with its suburbs, the city of refuge for the man slayer, and Be Eshterah with its suburbs: two cities.', pt: 'Aos filhos de Gérsom das famílias dos levitas, deram, da meia tribo de Manassés, Golã, cidade de refúgio do homicida, em Basã, e seus arrabaldes, e Beesterá e seus arrabaldes; duas cidades.' },
      { v: 28, en: 'Out of the tribe of Issachar, Kishion with its suburbs, Daberath with its suburbs,', pt: 'E da tribo de Issacar, Quisiom e seus arrabaldes, Daberate e seus arrabaldes,' },
      { v: 29, en: 'Jarmuth with its suburbs, En Gannim with its suburbs: four cities.', pt: 'Jarmute e seus arrabaldes, En-Ganim e seus arrabaldes; quatro cidades.' },
      { v: 30, en: 'Out of the tribe of Asher, Mishal with its suburbs, Abdon with its suburbs,', pt: 'E da tribo de Aser, Misal e seus arrabaldes, Abdom e seus arrabaldes,' },
      { v: 31, en: 'Helkath with its suburbs, and Rehob with its suburbs: four cities.', pt: 'Helcate e seus arrabaldes, Reobe e seus arrabaldes; quatro cidades.' },
      { v: 32, en: 'Out of the tribe of Naphtali, Kedesh in Galilee with its suburbs, the city of refuge for the man slayer, Hammothdor with its suburbs, and Kartan with its suburbs: three cities.', pt: 'E da tribo de Naftali, Quedes, cidade de refúgio do homicida, na Galiléia, e seus arrabaldes, Hamote-Dor e seus arrabaldes, Cartã e seus arrabaldes; três cidades.' },
      { v: 33, en: 'All the cities of the Gershonites according to their families were thirteen cities with their suburbs.', pt: 'Todas as cidades dos gersonitas, segundo as suas famílias, foram treze cidades e seus arrabaldes.' },
      { v: 34, en: 'To the families of the children of Merari, the rest of the Levites, out of the tribe of Zebulun, Jokneam with its suburbs, Kartah with its suburbs,', pt: 'Âs famílias dos filhos de Merári, aos demais levitas, deram da tribo de Zebulom, Jocneão e seus arrabaldes, Cartá e seus arrabaldes,' },
      { v: 35, en: 'Dimnah with its suburbs, and Nahalal with its suburbs: four cities.', pt: 'Dimna e seus arrabaldes, Naalal e seus arrabaldes; quatro cidades.' },
      { v: 36, en: 'Out of the tribe of Reuben, Bezer with its suburbs, Jahaz with its suburbs,', pt: 'E da tribo de Rúben, Bezer e seus arrabaldes, Jaza e seus arrabaldes,' },
      { v: 37, en: 'Kedemoth with its suburbs, and Mephaath with its suburbs: four cities.', pt: 'Quedemote e seus arrabaldes, Mefaate e seus arrabaldes; quatro cidades.' },
      { v: 38, en: 'Out of the tribe of Gad, Ramoth in Gilead with its suburbs, the city of refuge for the man slayer, and Mahanaim with its suburbs,', pt: 'E da tribo de Gade, Ramote, cidade de refúgio do homicida, em Gileade, e seus arrabaldes, Maanaim e seus arrabaldes,' },
      { v: 39, en: 'Heshbon with its suburbs, Jazer with its suburbs: four cities in all.', pt: 'Hesbom e seus arrabaldes, Jazer e seus arrabaldes; ao todo, quatro cidades.' },
      { v: 40, en: 'All these were the cities of the children of Merari according to their families, even the rest of the families of the Levites. Their lot was twelve cities.', pt: 'Todas essas cidades couberam por sorte aos filhos de Merári, segundo as suas famílias, o restante das familias dos levitas; foram, ao todo, doze cidades.' },
      { v: 41, en: 'All the cities of the Levites among the possessions of the children of Israel were forty-eight cities with their suburbs.', pt: 'Todas as cidades dos levitas, no meio da herança dos filhos de Israel, foram quarenta e oito cidades e seus arrabaldes.' },
      { v: 42, en: 'Each of these cities included their suburbs around them. It was this way with all these cities.', pt: 'Cada uma dessas cidades tinha os seus arrabaldes em redor; assim foi com todas elas.' },
      { v: 43, en: 'So Yahweh gave to Israel all the land which he swore to give to their fathers. They possessed it, and lived in it.', pt: 'Desta maneira deu o Senhor a Israel toda a terra que, com juramento, prometera dar a seus pais; e eles a possuíram e habitaram nela.' },
      { v: 44, en: 'Yahweh gave them rest all around, according to all that he swore to their fathers. Not a man of all their enemies stood before them. Yahweh delivered all their enemies into their hand.', pt: 'E o Senhor lhes deu repouso de todos os lados, conforme tudo quanto jurara a seus pais; nenhum de todos os seus inimigos pôde ficar de pé diante deles, mas a todos o Senhor lhes entregou nas mãos.' },
      { v: 45, en: 'Nothing failed of any good thing which Yahweh had spoken to the house of Israel. All came to pass.', pt: 'Palavra alguma falhou de todas as boas coisas que o Senhor prometera à casa de Israel; tudo se cumpriu.' },
    ],
    22: [
      { v: 1, en: 'Then Joshua called the Reubenites, the Gadites, and the half-tribe of Manasseh,', pt: 'Então Josué chamou os rubenitas, os gaditas e a meia tribo de Manassés,' },
      { v: 2, en: 'and said to them, “You have kept all that Moses the servant of Yahweh commanded you, and have listened to my voice in all that I commanded you.', pt: 'e disse-lhes: Tudo quanto Moisés, servo do Senhor, vos ordenou, tendes observado, bem como tendes obedecido à minha voz em tudo quanto vos ordenei.' },
      { v: 3, en: 'You have not left your brothers these many days to this day, but have performed the duty of the commandment of Yahweh your God.', pt: 'A vossos irmãos nunca desamparastes, até o dia de hoje, mas tendes observado cuidadosamente o mandamento do Senhor vosso Deus.' },
      { v: 4, en: 'Now Yahweh your God has given rest to your brothers, as he spoke to them. Therefore now return and go to your tents, to the land of your possession, which Moses the servant of Yahweh gave you beyond the Jordan.', pt: 'Agora o Senhor vosso Deus deu descanso a vossos irmãos, como lhes prometera; voltai, pois, agora, e ide para as vossas tendas, para a terra da vossa possessão, que Moisés, servo do Senhor, vos deu além do Jordão.' },
      { v: 5, en: 'Only take diligent heed to do the commandment and the law which Moses the servant of Yahweh commanded you, to love Yahweh your God, to walk in all his ways, to keep his commandments, to hold fast to him, and to serve him with all your heart and with all your soul.”', pt: 'Tão-somente tende cuidado de guardar com diligência o mandamento e a lei que Moisés, servo do Senhor, vos ordenou: que ameis ao Senhor vosso Deus, andeis em todos os seus caminhos, guardeis os seus mandamentos, e vos apegueis a ele e o sirvais com todo o vosso coração e com toda a vossa alma.' },
      { v: 6, en: 'So Joshua blessed them, and sent them away; and they went to their tents.', pt: 'Assim Josué os abençoou, e os despediu; e eles foram para as suas tendas.' },
      { v: 7, en: 'Now to the one half-tribe of Manasseh Moses had given inheritance in Bashan; but to the other half gave Joshua among their brothers beyond the Jordan westward. Moreover when Joshua sent them away to their tents, he blessed them,', pt: 'Ora, Moisés dera herança em Basã à meia tribo de Manassés, porém à outra metade Josué deu herança entre seus irmãos, a oeste do Jordão. E quando Josué os enviou para as suas tendas os abençoou' },
      { v: 8, en: 'and spoke to them, saying, “Return with much wealth to your tents, with very much livestock, with silver, with gold, with brass, with iron, and with very much clothing. Divide the plunder of your enemies with your brothers.”', pt: 'e lhes disse: Voltai para as vossas tendas com grandes riquezas: com muitíssimo gado, com prata e ouro, com cobre e ferro, e com muitíssimos vestidos; e reparti com vossos irmãos o despojo dos vossos inimigos.' },
      { v: 9, en: 'The children of Reuben and the children of Gad and the half-tribe of Manasseh returned, and departed from the children of Israel out of Shiloh, which is in the land of Canaan, to go to the land of Gilead, to the land of their possession, which they owned, according to the commandment of Yahweh by Moses.', pt: 'Assim voltaram os filhos de Rúben os filhos de Gade e a meia tribo de Manassés, separando-se dos filhos de Israel em Siló, que está na terra de Canaã, para irem à terra de Gileade, à terra da sua possessão, de que foram feitos possuidores, segundo a ordem do Senhor por intermédio de Moisés.' },
      { v: 10, en: 'When they came to the region about the Jordan, that is in the land of Canaan, the children of Reuben and the children of Gad and the half-tribe of Manasseh built there an altar by the Jordan, a great altar to look at.', pt: 'Tendo chegado à região junto ao Jordão, ainda na terra de Canaã, os filhos de Rúben os filhos de Gade e a meia tribo de Manassés edificaram ali, à beira do Jordão, um altar de grandes proporções.' },
      { v: 11, en: 'The children of Israel heard this, “Behold, the children of Reuben and the children of Gad and the half-tribe of Manasseh have built an altar in the border of the land of Canaan, in the region around the Jordan, on the side that belongs to the children of Israel.”', pt: 'E os filhos de Israel ouviram dizer: Eis que os filhos de Rúben os filhos de Gade e a meia tribo de Manassés edificaram um altar na fronteira da terra de Canaã, na região junto ao Jordão, da banda que pertence aos filhos de Israel.' },
      { v: 12, en: 'When the children of Israel heard of it, the whole congregation of the children of Israel gathered themselves together at Shiloh, to go up against them to war.', pt: 'Quando os filhos de Israel ouviram isto, congregaram-se todos em Siló, para subirem a guerrear contra eles.' },
      { v: 13, en: 'The children of Israel sent to the children of Reuben, and to the children of Gad, and to the half-tribe of Manasseh, into the land of Gilead, Phinehas the son of Eleazar the priest.', pt: 'Então os filhos de Israel enviaram aos filhos de Rúben aos filhos de Gade e à meia tribo de Manassés, à terra de Gileade, Finéias, filho de Eleazar, o sacerdote,' },
      { v: 14, en: 'With him were ten princes, one prince of a fathers’ house for each of the tribes of Israel; and they were each head of their fathers’ houses among the thousands of Israel.', pt: 'e com ele dez príncipes, um príncipe de cada casa paterna de todas as tribos de Israel; e eles eram os cabeças das suas casas paternas entre os milhares de Israel.' },
      { v: 15, en: 'They came to the children of Reuben, and to the children of Gad, and to the half-tribe of Manasseh, to the land of Gilead, and they spoke with them, saying,', pt: 'Foram, pois, ter com os filhos de Rúben e os filhos de Gade e a meia tribo de Manassés, à terra de Gileade, e lhes disseram:' },
      { v: 16, en: '“Thus says the whole congregation of Yahweh, ‘What trespass is this that you have committed against the God of Israel, to turn away today from following Yahweh, in that you have built yourselves an altar, to rebel today against Yahweh?', pt: 'Assim diz toda a congregação do Senhor: Que transgressão é esta que cometestes contra o Deus de Israel, deixando hoje de seguir ao Senhor, edificando-vos um altar para vos rebelardes hoje contra o Senhor?' },
      { v: 17, en: 'Is the iniquity of Peor too little for us, from which we have not cleansed ourselves to this day, although there came a plague on the congregation of Yahweh,', pt: 'Acaso nos é pouca a iniqüidade de Peor, de que ainda até o dia de hoje não nos temos purificado, apesar de ter vindo uma praga sobre a congregaçao do Senhor,' },
      { v: 18, en: 'that you must turn away today from following Yahweh? It will be, since you rebel today against Yahweh, that tomorrow he will be angry with the whole congregation of Israel.', pt: 'para que hoje queirais abandonar ao Senhor? Será que, rebelando-vos hoje contra o Senhor, amanhã ele se irará contra toda a congregação de Israel.' },
      { v: 19, en: 'However, if the land of your possession is unclean, then pass over to the land of the possession of Yahweh, in which Yahweh’s tabernacle dwells, and take possession among us; but don’t rebel against Yahweh, nor rebel against us, in building an altar other than Yahweh our God’s altar.', pt: 'Se é, porém, que a terra da vossa possessão é imunda, passai para a terra da possessão do Senhor, onde habita o tabernáculo do Senhor, e tomai possessão entre nós; mas não vos rebeleis contra o Senhor, nem tampouco vos rebeleis contra nós, edificando-vos um altar afora o altar do Senhor nosso Deus.' },
      { v: 20, en: 'Didn’t Achan the son of Zerah commit a trespass in the devoted thing, and wrath fell on all the congregation of Israel? That man didn’t perish alone in his iniquity.’”', pt: 'Não cometeu Acã, filho de Zerá, transgressão no tocante ao anátema? e não veio ira sobre toda a congregação de Israel? de modo que não pereceu ele só na sua iniqüidade.' },
      { v: 21, en: 'Then the children of Reuben and the children of Gad and the half-tribe of Manasseh answered, and spoke to the heads of the thousands of Israel,', pt: 'Então responderam os filhos de Rúben os filhos de Gade e a meia tribo de Manassés, e disseram aos cabeças dos milhares de Israel:' },
      { v: 22, en: '“The Mighty One, God, Yahweh, the Mighty One, God, Yahweh, he knows; and Israel shall know: if it was in rebellion, or if in trespass against Yahweh (don’t save us today),', pt: 'O Poderoso, Deus, o Senhor, o Poderoso, Deus, o Senhor, ele o sabe, e Israel mesmo o saberá! Se foi em rebeldia, ou por transgressão contra o Senhor não nos salves hoje;' },
      { v: 23, en: 'that we have built us an altar to turn away from following Yahweh; or if to offer burnt offering or meal offering, or if to offer sacrifices of peace offerings, let Yahweh himself require it.', pt: 'se nós edificamos um altar, para nos tornar de após o Senhor, ou para sobre ele oferecer holocausto e oferta de cereais, ou sobre ele oferecer sacrifícios de ofertas pacíficas, o Senhor mesmo de nós o requeira;' },
      { v: 24, en: '“If we have not out of concern done this, and for a reason, saying, ‘In time to come your children might speak to our children, saying, “What have you to do with Yahweh, the God of Israel?', pt: 'e se antes o não fizemos com receio e de propósito, dizendo: Amanhã vossos filhos poderiam dizer a nossos filhos: Que tendes vós com o Senhor Deus de Israel?' },
      { v: 25, en: 'For Yahweh has made the Jordan a border between us and you, you children of Reuben and children of Gad. You have no portion in Yahweh.”’ So your children might make our children cease from fearing Yahweh.', pt: 'Pois o Senhor pôs o Jordão por termo entre nós e vós, ó filhos de Rúben e ó filhos de Gade; não tendes parte no Senhor. Assim bem poderiam vossos filhos fazer com que os nossos filhos deixassem de temer ao Senhor.' },
      { v: 26, en: '“Therefore we said, ‘Let’s now prepare to build ourselves an altar, not for burnt offering, nor for sacrifice;', pt: 'Pelo que dissemos: Edifiquemos agora um altar, não para holocausto, nem para sacrifício,' },
      { v: 27, en: 'but it will be a witness between us and you, and between our generations after us, that we may perform the service of Yahweh before him with our burnt offerings, with our sacrifices, and with our peace offerings;’ that your children may not tell our children in time to come, ‘You have no portion in Yahweh.’', pt: 'mas para que, entre nós e vós, e entre as nossas gerações depois de nós, nos sirva de testemunho para podermos fazer o serviço do Senhor diante dele com os nossos holocaustos, com os nossos sacrifícios e com as nossas ofertas pacíficas; para que vossos filhos não digam amanhã a nossos filhos: Não tendes parte no Senhor.' },
      { v: 28, en: '“Therefore we said, ‘It shall be, when they tell us or our generations this in time to come, that we shall say, “Behold the pattern of Yahweh’s altar, which our fathers made, not for burnt offering, nor for sacrifice; but it is a witness between us and you.”’', pt: 'Pelo que dissemos: Quando amanhã disserem assim a nós ou às nossas gerações, então diremos: Vede o modelo do altar do Senhor que os nossos pais fizeram, não para holocausto nem para sacrifício, porém para ser testemunho entre nós e vós,' },
      { v: 29, en: '“Far be it from us that we should rebel against Yahweh, and turn away today from following Yahweh, to build an altar for burnt offering, for meal offering, or for sacrifice, besides Yahweh our God’s altar that is before his tabernacle!”', pt: 'Longe esteja de nós que nos rebelemos contra o Senhor, ou que hoje o abandonemos, edificando altar para holocausto, oferta de cereais ou sacrifício, afora o altar do Senhor nosso Deus, que está perante o seu tabernáculo.' },
      { v: 30, en: 'When Phinehas the priest, and the princes of the congregation, even the heads of the thousands of Israel that were with him, heard the words that the children of Reuben and the children of Gad and the children of Manasseh spoke, it pleased them well.', pt: 'Quando, pois, Finéias, o sacerdote, e os príncipes da congregação, os cabeças dos milhares de Israel que estavam com ele, ouviram as palavras que lhes disseram os filhos de Rúben os filhos de Gade e os filhos de Manassés, ficaram satisfeitos.' },
      { v: 31, en: 'Phinehas the son of Eleazar the priest said to the children of Reuben, to the children of Gad, and to the children of Manasseh, “Today we know that Yahweh is among us, because you have not committed this trespass against Yahweh. Now you have delivered the children of Israel out of Yahweh’s hand.”', pt: 'Então disse Finéias, filho de Eleazar, o sacerdote, aos filhos de Rúben aos filhos de Gade e aos filhos de Manassés: Hoje sabemos que o Senhor está no meio de nós, porquanto não cometestes tal transgressão contra o Senhor; agora livrastes os filhos de Israel da mão do Senhor.' },
      { v: 32, en: 'Phinehas the son of Eleazar the priest, and the princes, returned from the children of Reuben, and from the children of Gad, out of the land of Gilead, to the land of Canaan, to the children of Israel, and brought them word again.', pt: 'E Finéias, filho de Eleazar, o sacerdote, e os príncipes, deixando os filhos de Rúben e os filhos de Gade, voltaram da terra de Gileade para a terra de Canaã, aos filhos de Israel, e trouxeram-lhes a resposta.' },
      { v: 33, en: 'The thing pleased the children of Israel; and the children of Israel blessed God, and spoke no more of going up against them to war, to destroy the land in which the children of Reuben and the children of Gad lived.', pt: 'E com isso os filhos de Israel ficaram satisfeitos; e louvaram a Deus, e não falaram mais de subir a guerrear contra eles, para destruírem a terra em que habitavam os filhos de Rúben e os filhos de Gade.' },
      { v: 34, en: 'The children of Reuben and the children of Gad named the altar “A Witness Between Us that Yahweh is God.”', pt: 'E os filhos de Rúben e os filhos de Gade chamaram ao altar Testemunha; pois, disseram eles, é testemunho entre nós que o Senhor é Deus.' },
    ],
    23: [
      { v: 1, en: 'After many days, when Yahweh had given rest to Israel from their enemies all around, and Joshua was old and well advanced in years,', pt: 'Passados muitos dias, tendo o Senhor dado repouso a Israel de todos os seus inimigos em redor, e sendo Josué já velho, de idade muito avançada,' },
      { v: 2, en: 'Joshua called for all Israel, for their elders and for their heads, and for their judges and for their officers, and said to them, “I am old and well advanced in years.', pt: 'chamou Josué a todo o Israel, aos seus anciãos, aos seus cabeças, aos seus juízes e aos seus oficiais, e disse-lhes: Eu já sou velho, de idade muito avançada;' },
      { v: 3, en: 'You have seen all that Yahweh your God has done to all these nations because of you; for it is Yahweh your God who has fought for you.', pt: 'e vós tendes visto tudo quanto o Senhor vosso Deus fez a todas estas nações por causa e vós, porque é o Senhor vosso Deus que tem pelejado por vós.' },
      { v: 4, en: 'Behold, I have allotted to you these nations that remain, to be an inheritance for your tribes, from the Jordan, with all the nations that I have cut off, even to the great sea toward the going down of the sun.', pt: 'Vede que vos reparti por sorte estas nações que restam, para serem herança das vossas tribos, juntamente com todas as naçoes que tenho destruído, desde o Jordão até o grande mar para o pôr do sol.' },
      { v: 5, en: 'Yahweh your God will thrust them out from before you, and drive them from out of your sight. You shall possess their land, as Yahweh your God spoke to you.', pt: 'E o Senhor vosso Deus as impelirá, e as expulsará de diante de vós; e vós possuireis a sua terra, como vos disse o Senhor vosso Deus.' },
      { v: 6, en: '“Therefore be very courageous to keep and to do all that is written in the book of the law of Moses, that you not turn away from it to the right hand or to the left;', pt: 'Esforçai-vos, pois, para guardar e cumprir tudo quanto está escrito no livro da lei de Moisés, para que dela não vos desvieis nem para a direita nem para a esquerda;' },
      { v: 7, en: 'that you not come among these nations, these that remain among you; neither make mention of the name of their gods, nor cause to swear by them, neither serve them, nor bow down yourselves to them;', pt: 'para que não vos mistureis com estas nações que ainda restam entre vós; e dos nomes de seus deuses não façais menção, nem por eles façais jurar, nem os sirvais, nem a eles vos inclineis.' },
      { v: 8, en: 'but hold fast to Yahweh your God, as you have done to this day.', pt: 'Mas ao Senhor vosso Deus vos apegareis, como fizeste até o dia de hoje;' },
      { v: 9, en: '“For Yahweh has driven great and strong nations out from before you. But as for you, no man has stood before you to this day.', pt: 'pois o Senhor expulsou de diante de vós grandes e fortes nações, e, até o dia de hoje, ninguém vos tem podido resistir.' },
      { v: 10, en: 'One man of you shall chase a thousand; for it is Yahweh your God who fights for you, as he spoke to you.', pt: 'um só homem dentre vós persegue a mil, pois o Senhor vosso Deus é quem peleja por vós, como já vos disse.' },
      { v: 11, en: 'Take good heed therefore to yourselves, that you love Yahweh your God.', pt: 'Portanto, cuidai diligentemente de amar ao Senhor vosso Deus.' },
      { v: 12, en: '“But if you do at all go back, and hold fast to the remnant of these nations, even these who remain among you, and make marriages with them, and go in to them, and they to you;', pt: 'Porque se de algum modo vos desviardes, e vos apegardes ao resto destas nações que ainda ficam entre vós, e com elas contrairdes matrimônio, e entrardes a elas, e elas a vós,' },
      { v: 13, en: 'know for a certainty that Yahweh your God will no longer drive these nations from out of your sight; but they shall be a snare and a trap to you, a scourge in your sides, and thorns in your eyes, until you perish from off this good land which Yahweh your God has given you.', pt: 'sabei com certeza que o Senhor vosso Deus não continuará a expulsar estas nações de diante de vós; porém elas vos serão por laço e rede, e açoite às vossas ilhargas, e espinhos aos vossos olhos, até que pereçais desta boa terra que o Senhor vosso Deus vos deu.' },
      { v: 14, en: '“Behold, today I am going the way of all the earth. You know in all your hearts and in all your souls that not one thing has failed of all the good things which Yahweh your God spoke concerning you. All have happened to you. Not one thing has failed of it.', pt: 'Eis que vou hoje pelo caminho de toda a terra; e vós sabeis em vossos corações e em vossas almas que não tem falhado uma só palavra de todas as boas coisas que a vosso respeito falou o Senhor vosso Deus; nenhuma delas falhou, mas todas se cumpriram.' },
      { v: 15, en: 'It shall happen that as all the good things have come on you of which Yahweh your God spoke to you, so Yahweh will bring on you all the evil things, until he has destroyed you from off this good land which Yahweh your God has given you,', pt: 'E assim como vos sobrevieram todas estas boas coisas de que o Senhor vosso Deus vos falou, assim trará o Senhor sobre vós todas aquelas más coisas, até vos destruir de sobre esta boa terra que ele vos deu.' },
      { v: 16, en: 'when you disobey the covenant of Yahweh your God, which he commanded you, and go and serve other gods, and bow down yourselves to them. Then Yahweh’s anger will be kindled against you, and you will perish quickly from off the good land which he has given to you.”', pt: 'Quando transgredirdes o pacto do Senhor vosso Deus, que ele vos ordenou, e fordes servir a outros deuses, inclinando-vos a eles, a ira do Senhor se acenderá contra vós, e depressa perecereis de sobre a boa terra que ele vos deu.' },
    ],
    24: [
      { v: 1, en: 'Joshua gathered all the tribes of Israel to Shechem, and called for the elders of Israel, for their heads, for their judges, and for their officers; and they presented themselves before God.', pt: 'Depois Josué reuniu todas as tribos de Israel em Siquém, e chamou os anciãos de Israel, os seus cabeças, os seus juízes e os seus oficiais; e eles se apresentaram diante de Deus.' },
      { v: 2, en: 'Joshua said to all the people, “Yahweh says, the God of Israel, ‘Your fathers lived of old time beyond the River, even Terah, the father of Abraham, and the father of Nahor: and they served other gods.', pt: 'Disse então Josué a todo o povo: Assim diz o Senhor Deus de Israel: Além do Rio habitaram antigamente vossos pais, Tera, pai de Abraão e de Naor; e serviram a outros deuses.' },
      { v: 3, en: 'I took your father Abraham from beyond the River, and led him throughout all the land of Canaan, and multiplied his offspring, and gave him Isaac.', pt: 'Eu, porém, tomei a vosso pai Abraão dalém do Rio, e o conduzi por toda a terra de Canaã; também multipliquei a sua descendência, e dei-lhe Isaque.' },
      { v: 4, en: 'I gave to Isaac Jacob and Esau: and I gave to Esau Mount Seir, to possess it. Jacob and his children went down into Egypt.', pt: 'A Isaque; dei Jacó e Esaú; a Esaú dei em possessão o monte Seir; mas Jacó e seus filhos desceram para o Egito.' },
      { v: 5, en: '“‘I sent Moses and Aaron, and I plagued Egypt, according to that which I did among them: and afterward I brought you out.', pt: 'Então enviei Moisés e Arão, e feri o Egito com aquilo que fiz no meio dele; e depois vos tirei de lá.' },
      { v: 6, en: 'I brought your fathers out of Egypt: and you came to the sea. The Egyptians pursued your fathers with chariots and with horsemen to the Red Sea.', pt: 'Depois que tirei a vossos pais do Egito viestes ao mar; e os egípcios perseguiram a vossos pais, com carros e com cavaleiros, até o Mar Vermelho.' },
      { v: 7, en: 'When they cried out to Yahweh, he put darkness between you and the Egyptians, and brought the sea on them, and covered them; and your eyes saw what I did in Egypt. You lived in the wilderness many days.', pt: 'Quando clamaram ao Senhor, ele pôs uma escuridão entre vós e os egípcios, e trouxe o mar sobre eles e os cobriu; e os vossos olhos viram o que eu fiz no Egito. Depois habitastes no deserto muitos dias.' },
      { v: 8, en: '“‘I brought you into the land of the Amorites, that lived beyond the Jordan. They fought with you, and I gave them into your hand. You possessed their land, and I destroyed them from before you.', pt: 'Então eu vos trouxe à terra dos amorreus, que habitavam além do Jordão, os quais pelejaram contra vós; porém os entreguei na vossa mão, e possuístes a sua terra; assim os destruí de diante de vós.' },
      { v: 9, en: 'Then Balak the son of Zippor, king of Moab, arose and fought against Israel. He sent and called Balaam the son of Beor to curse you,', pt: 'Levantou-se também Balaque, filho de Zipor, rei dos moabitas, e pelejou contra Israel; e mandou chamar a Balaão, filho de Beor, para que vos amaldiçoasse;' },
      { v: 10, en: 'but I would not listen to Balaam; therefore he blessed you still. So I delivered you out of his hand.', pt: 'porém eu não quis ouvir a Balaão; pelo que ele vos abençoou; e eu vos livrei da sua mao.' },
      { v: 11, en: '“‘You went over the Jordan, and came to Jericho. The men of Jericho fought against you, the Amorite, the Perizzite, the Canaanite, the Hittite, the Girgashite, the Hivite, and the Jebusite; and I delivered them into your hand.', pt: 'E quando vós, passando o Jordão, viestes a Jericó, pelejaram contra vós os homens de Jericó, e os amorreus, os perizeus, os cananeus, os heteus, os girgaseus, os heveus e os jebuseus; porém os entreguei na vossa mao.' },
      { v: 12, en: 'I sent the hornet before you, which drove them out from before you, even the two kings of the Amorites; not with your sword, nor with your bow.', pt: 'Pois enviei vespões adiante de vós, que os expulsaram de diante de vós, como aos dois reis dos amorreus, não com a vossa espada, nem com o vosso arco.' },
      { v: 13, en: 'I gave you a land whereon you had not labored, and cities which you didn’t build, and you live in them. You eat of vineyards and olive groves which you didn’t plant.’', pt: 'E eu vos dei uma terra em que não trabalhastes, e cidades que não edificastes, e habitais nelas; e comeis de vinhas e de olivais que não plantastes.' },
      { v: 14, en: '“Now therefore fear Yahweh, and serve him in sincerity and in truth. Put away the gods which your fathers served beyond the River, in Egypt; and serve Yahweh.', pt: 'Agora, pois, temei ao Senhor, e servi-o com sinceridade e com verdade; deitai fora os deuses a que serviram vossos pais dalém do Rio, e no Egito, e servi ao Senhor.' },
      { v: 15, en: 'If it seems evil to you to serve Yahweh, choose today whom you will serve; whether the gods which your fathers served that were beyond the River, or the gods of the Amorites, in whose land you dwell; but as for me and my house, we will serve Yahweh.”', pt: 'Mas, se vos parece mal o servirdes ao Senhor, escolhei hoje a quem haveis de servir; se aos deuses a quem serviram vossos pais, que estavam além do Rio, ou aos deuses dos amorreus, em cuja terra habitais. Porém eu e a minha casa serviremos ao Senhor.' },
      { v: 16, en: 'The people answered, “Far be it from us that we should forsake Yahweh, to serve other gods;', pt: 'Então respondeu o povo, e disse: Longe esteja de nós o abandonarmos ao Senhor para servirmos a outros deuses:' },
      { v: 17, en: 'for it is Yahweh our God who brought us and our fathers up out of the land of Egypt, from the house of bondage, and who did those great signs in our sight, and preserved us in all the way in which we went, and among all the peoples through the middle of whom we passed.', pt: 'porque o Senhor é o nosso Deus; ele é quem nos fez subir, a nós e a nossos pais, da terra do Egito, da casa da servidão, e quem fez estes grandes sinais aos nossos olhos, e nos preservou por todo o caminho em que andamos, e entre todos os povos pelo meio dos quais passamos.' },
      { v: 18, en: 'Yahweh drove out from before us all the peoples, even the Amorites who lived in the land. Therefore we also will serve Yahweh; for he is our God.”', pt: 'E o Senhor expulsou de diante de nós a todos esses povos, mesmo os amorreus, que moravam na terra. Nós também serviremos ao Senhor, porquanto ele é nosso Deus.' },
      { v: 19, en: 'Joshua said to the people, “You can’t serve Yahweh, for he is a holy God. He is a jealous God. He will not forgive your disobedience nor your sins.', pt: 'Então Josué disse ao povo: Não podereis servir ao Senhor, porque é Deus santo, é Deus zeloso, que não perdoará a vossa transgressão nem os vossos pecados.' },
      { v: 20, en: 'If you forsake Yahweh, and serve foreign gods, then he will turn and do you evil, and consume you, after he has done you good.”', pt: 'Se abandonardes ao Senhor e servirdes a deuses estranhos, então ele se tornará, e vos fará o mal, e vos consumirá, depois de vos ter feito o bem.' },
      { v: 21, en: 'The people said to Joshua, “No, but we will serve Yahweh.”', pt: 'Disse então o povo a Josué: Não! antes serviremos ao Senhor.' },
      { v: 22, en: 'Joshua said to the people, “You are witnesses against yourselves that you have chosen Yahweh yourselves, to serve him.” They said, “We are witnesses.”', pt: 'Josué, pois, disse ao povo: Sois testemunhas contra vós mesmos e que escolhestes ao Senhor para o servir. Responderam eles: Somos testemunhas.' },
      { v: 23, en: '“Now therefore put away the foreign gods which are among you, and incline your heart to Yahweh, the God of Israel.”', pt: 'Agora, pois, - disse Josué - deitai fora os deuses estranhos que há no meio de vós, e inclinai o vosso coração ao Senhor Deus de Israel.' },
      { v: 24, en: 'The people said to Joshua, “We will serve Yahweh our God, and we will listen to his voice.”', pt: 'Disse o povo a Josué: Serviremos ao Senhor nosso Deus, e obedeceremos à sua voz.' },
      { v: 25, en: 'So Joshua made a covenant with the people that day, and made for them a statute and an ordinance in Shechem.', pt: 'Assim fez Josué naquele dia um pacto com o povo, e lhe deu leis e ordenanças em Siquem.' },
      { v: 26, en: 'Joshua wrote these words in the book of the law of God; and he took a great stone, and set it up there under the oak that was by the sanctuary of Yahweh.', pt: 'E Josué escreveu estas palavras no livro da lei de Deus; e, tomando uma grande pedra, a pôs ali debaixo do carvalho que estava junto ao santuário do Senhor,' },
      { v: 27, en: 'Joshua said to all the people, “Behold, this stone shall be a witness against us, for it has heard all Yahweh’s words which he spoke to us. It shall be therefore a witness against you, lest you deny your God.”', pt: 'e disse a todo o povo: Eis que esta pedra será por testemunho contra nós, pois ela ouviu todas as palavras que o Senhor nos falou; pelo que será por testemunho contra vós, para que não negueis o vosso Deus.' },
      { v: 28, en: 'So Joshua sent the people away, each to his own inheritance.', pt: 'Então Josué despediu o povo, cada um para a sua herança.' },
      { v: 29, en: 'After these things, Joshua the son of Nun, the servant of Yahweh, died, being one hundred ten years old.', pt: 'Depois destas coisas Josué, filho de Num, servo do Senhor, morreu, tendo cento e dez anos de idade;' },
      { v: 30, en: 'They buried him in the border of his inheritance in Timnathserah, which is in the hill country of Ephraim, on the north of the mountain of Gaash.', pt: 'e o sepultaram no território da sua herança, em Timnate-Sera, que está na região montanhosa de Efraim, para o norte do monte Gaás.' },
      { v: 31, en: 'Israel served Yahweh all the days of Joshua, and all the days of the elders who outlived Joshua, and had known all the work of Yahweh, that he had worked for Israel.', pt: 'Serviu, pois, Israel ao Senhor todos os dias de Josué, e todos os dias dos anciãos que sobreviveram a Josué e que sabiam toda a obra que o Senhor tinha feito a favor de Israel.' },
      { v: 32, en: 'They buried the bones of Joseph, which the children of Israel brought up out of Egypt, in Shechem, in the parcel of ground which Jacob bought from the sons of Hamor the father of Shechem for a hundred pieces of silver. They became the inheritance of the children of Joseph.', pt: 'Os ossos de José, que os filhos de Israel trouxeram do Egito, foram enterrados em Siquém, naquela parte do campo que Jacó comprara aos filhos de Hamor, pai de Siquém, por cem peças de prata, e que se tornara herança dos filhos de José.' },
      { v: 33, en: 'Eleazar the son of Aaron died. They buried him in the hill of Phinehas his son, which was given him in the hill country of Ephraim.', pt: 'Morreu também Eleazar, filho de Arão, e o sepultaram no outeiro de Finéias, seu filho, que lhe fora dado na região montanhosa de Efraim.' },
    ],
  },
};

export default book;
